// --- GIGMA: Giglio icon ---
const GIGLIO_ICON_SRC = new URL('./Giglio 2 transparent.png', import.meta.url).href;

// --- GIGMA: Mobile fullscreen detection for extension dialogs ---
const GIGMA_MOBILE_FULLSCREEN_CLASS = 'gigma-mobile-fullscreen';

const gigmaIsMobileFullscreenActive = () => isMobile();

const gigmaSyncMobileFullscreenClass = () => {
  document.documentElement.classList.toggle(GIGMA_MOBILE_FULLSCREEN_CLASS, gigmaIsMobileFullscreenActive());
};

(function gigmaMobileFullscreenClassOnce(){
  gigmaSyncMobileFullscreenClass();
  window.addEventListener('resize', gigmaSyncMobileFullscreenClass, { passive: true });
  window.addEventListener('orientationchange', gigmaSyncMobileFullscreenClass, { passive: true });
})();


// --- GIGMA: Lorebook usage icons (persona/chat/character) ---
const __gigmaGetWorldUsageFlags = (worldName) => {
  const personaWorld = power_user?.persona_description_lorebook;
  const chatWorld = chat_metadata?.[METADATA_KEY];
  const baseWorld = characters?.[this_chid]?.data?.extensions?.world;
  const isGroupChat = !!selected_group;

  const isActiveWorld = Array.isArray(selected_world_info) && selected_world_info.includes(worldName);
  const isPersonaWorld = !!worldName && !!personaWorld && personaWorld === worldName;
  const isChatWorld = !!worldName && !!chatWorld && chatWorld === worldName;

  let chatBoundName = '';
  let characterBoundName = '';

  if (isChatWorld) {
    try{
      if (isGroupChat) {
        const ctx = (typeof getContext === 'function') ? (getContext() || {}) : {};
        const gid = (ctx && (ctx.groupId ?? selected_group)) ?? selected_group;
        if (gid != null && Array.isArray(ctx.groups)) {
          const g = ctx.groups.find(x => x && String(x.id) === String(gid));
          if (g && typeof g.name === 'string' && g.name.trim()) chatBoundName = g.name.trim();
        }
        if (!chatBoundName && typeof getCurrentChatDetails === 'function') {
          const cd = getCurrentChatDetails() || {};
          const gg = cd && cd.group;
          if (gg && typeof gg.name === 'string' && gg.name.trim()) chatBoundName = gg.name.trim();
        }
      } else if (this_chid !== null && this_chid !== undefined) {
        const c = characters?.[this_chid];
        chatBoundName = String((c && (c.name || c.data?.name)) || '').trim();
      }
    }catch(_){ }
  }

  let isCharacterWorld = false;
  if (worldName) {
    // In group chats there is no single `this_chid` until a member is opened/peeked.
    // The old logic only checked `this_chid`, so the icon appeared only after opening a member card.
    // Fix: consider the lorebook character-bound if it is bound to ANY current group member.
    if (isGroupChat) {
      const members = (typeof getGroupMembers === 'function') ? (getGroupMembers(selected_group) || []) : [];
      for (const member of members) {
        const chid = (member && Array.isArray(characters)) ? characters.indexOf(member) : -1;
        if (chid < 0) continue;

        const memberBaseWorld = characters?.[chid]?.data?.extensions?.world;
        if (memberBaseWorld && memberBaseWorld === worldName) {
          isCharacterWorld = true;
          characterBoundName = String((characters?.[chid]?.name || characters?.[chid]?.data?.name || member?.name || member?.data?.name || '')).trim();
          break;
        }

        const fn = getCharaFilename(chid);
        const extra = world_info?.charLore?.find((e) => e?.name === fn);
        if (extra?.extraBooks && extra.extraBooks.includes(worldName)) {
          isCharacterWorld = true;
          characterBoundName = String((characters?.[chid]?.name || characters?.[chid]?.data?.name || member?.name || member?.data?.name || '')).trim();
          break;
        }
      }
    } else {
      if (baseWorld && baseWorld === worldName) {
        isCharacterWorld = true;
        const c = characters?.[this_chid];
        characterBoundName = String((c && (c.name || c.data?.name)) || '').trim();
      } else if (this_chid !== null && this_chid !== undefined) {
        const fn = getCharaFilename(this_chid);
        const extra = world_info?.charLore?.find((e) => e?.name === fn);
        isCharacterWorld = !!(extra?.extraBooks && extra.extraBooks.includes(worldName));
        if (isCharacterWorld) {
          const c = characters?.[this_chid];
          characterBoundName = String((c && (c.name || c.data?.name)) || '').trim();
        }
      }
    }
  }

  return { isActiveWorld, isPersonaWorld, isChatWorld, isCharacterWorld, chatBoundName, characterBoundName };
};

const __gigmaMakeUsageIconEl = (faName, extraClass) => {
  const i = document.createElement('i');
  i.className = 'fa-solid ' + faName + ' gigma-active-world-globe ' + extraClass;
  i.setAttribute('aria-hidden', 'true');
  return i;
};

const __gigmaAppendUsageIcons = (parent, flags) => {
  if (!parent || !flags) return;
  if (flags.isActiveWorld) parent.appendChild(__gigmaMakeUsageIconEl('fa-globe', 'gigma-active-world-icon'));
  if (flags.isPersonaWorld) parent.appendChild(__gigmaMakeUsageIconEl('fa-user', 'gigma-persona-world-icon'));
  if (flags.isChatWorld) parent.appendChild(__gigmaMakeUsageIconEl('fa-comment', 'gigma-chat-world-icon'));
  if (flags.isCharacterWorld) parent.appendChild(__gigmaMakeUsageIconEl('fa-users', 'gigma-character-world-icon'));
};

const __gigmaUsageIconsHtml = (flags) => {
  if (!flags) return '';
  let html = '';
  if (flags.isActiveWorld) html += '<i class="fa-solid fa-globe gigma-active-world-globe gigma-active-world-icon" aria-hidden="true"></i>';
  if (flags.isPersonaWorld) html += '<i class="fa-solid fa-user gigma-active-world-globe gigma-persona-world-icon" aria-hidden="true"></i>';
  if (flags.isChatWorld) html += '<i class="fa-solid fa-comment gigma-active-world-globe gigma-chat-world-icon" aria-hidden="true"></i>';
  if (flags.isCharacterWorld) html += '<i class="fa-solid fa-users gigma-active-world-globe gigma-character-world-icon" aria-hidden="true"></i>';
  return html;
};

// --- GIGMA: Row label renderer (number + lorebook usage icons) ---
const __gigmaRenderRowLabel = (labelEl, idx, worldName) => {
  if (!labelEl) return;
  const flags = __gigmaGetWorldUsageFlags(worldName);
  const hasAnyIcon = !!(flags && (flags.isActiveWorld || flags.isPersonaWorld || flags.isChatWorld || flags.isCharacterWorld));
  labelEl.classList.add('gigma-active-world-inline');
  labelEl.textContent = '';
  const main = document.createElement('div');
  main.className = 'gigma-row-label-main';
  labelEl.appendChild(main);

  const title = document.createElement('span');
  title.className = 'gigma-row-title';
  main.appendChild(title);

  const nSpan = document.createElement('span');
  nSpan.className = 'gigma-row-num';
  nSpan.textContent = String(idx) + '.';
  title.appendChild(nSpan);
  __gigmaAppendUsageIcons(title, flags);
  const nameSpan = document.createElement('span');
  nameSpan.className = 'gigma-row-name';
  nameSpan.style.marginLeft = hasAnyIcon ? '0' : '0.25em';
  const nameText = (typeof gigmaInsertSoftHyphens === 'function') ? gigmaInsertSoftHyphens(worldName) : worldName;
  nameSpan.textContent = nameText;
  title.appendChild(nameSpan);
  try{
    if (flags && (flags.isChatWorld || flags.isCharacterWorld)) {
      const isChat = !!flags.isChatWorld;
      let boundName = String((isChat ? flags.chatBoundName : flags.characterBoundName) || '').trim();
      if (!boundName) boundName = isChat ? 'Chat' : 'Character';
      labelEl.classList.add('gigma-bound-tag-host');
      const tag = document.createElement('span');
      tag.className = 'gigma-bound-origin-tag';
      const ic = __gigmaMakeUsageIconEl(isChat ? 'fa-comment' : 'fa-users', isChat ? 'gigma-chat-world-icon' : 'gigma-character-world-icon');
      ic.classList.add('gigma-bound-origin-icon');
      tag.appendChild(ic);
      tag.appendChild(document.createTextNode(boundName.slice(0, 15)));
      main.insertBefore(tag, title);
    }
  }catch(_){ }
  try{ gigmaMaybeAttachModalLorebookStats(labelEl, worldName); }catch(_){ }
};

const __gigmaUpdateUnchainedRowLabelPadding = (labelEl) => {
  try{
    if (!labelEl || !labelEl.style) return;
    labelEl.style.paddingRight = '';
  }catch(_){ }
};

const __gigmaRenderUnchainedRowLabel = (labelEl, worldName, childPresetShort, includeLinkSlashIcon, includeGhostSpan) => {
  if (!labelEl) return;
  const flags = __gigmaGetWorldUsageFlags(worldName);
  const hasAnyIcon = !!(flags && (flags.isActiveWorld || flags.isPersonaWorld || flags.isChatWorld || flags.isCharacterWorld));

  labelEl.classList.add('gigma-active-world-inline');
  try{ labelEl.classList.remove('gigma-bound-tag-host'); }catch(_){}
  try{ labelEl.style.paddingRight = ''; }catch(_){}

  labelEl.textContent = '';

  const main = document.createElement('div');
  main.className = 'gigma-row-label-main';
  labelEl.appendChild(main);

  const title = document.createElement('span');
  title.className = 'gigma-row-title';
  main.appendChild(title);

  if (includeLinkSlashIcon) {
    const icon = document.createElement('i');
    icon.className = 'fa-solid fa-link-slash gigma-retro-lock-icon gigma-parent-unchained-icon';
    title.appendChild(icon);
  }

  __gigmaAppendUsageIcons(title, flags);

  if (includeLinkSlashIcon || hasAnyIcon) {
    title.appendChild(document.createTextNode(' '));
  }

  const nameSpan = document.createElement('span');
  nameSpan.className = 'gigma-row-name gigma-parent-unchained-name';
  const nameText = (typeof gigmaInsertSoftHyphens === 'function') ? gigmaInsertSoftHyphens(worldName) : worldName;
  nameSpan.textContent = nameText;
  title.appendChild(nameSpan);

  const tag = document.createElement('span');
  tag.className = 'gigma-parent-unchained-origin-tag';
  tag.textContent = String(childPresetShort || '').trim().slice(0, 15);
  main.appendChild(tag);

  if (includeGhostSpan) {
    const ghost = document.createElement('span');
    ghost.className = 'gigma-parent-unchained-ghost-text';
    ghost.textContent = '';
    main.appendChild(ghost);
  }

  try{
    if (flags && (flags.isChatWorld || flags.isCharacterWorld)) {
      const isChat = !!flags.isChatWorld;
      let boundName = String((isChat ? flags.chatBoundName : flags.characterBoundName) || '').trim();
      if (!boundName) boundName = isChat ? 'Chat' : 'Character';
      labelEl.classList.add('gigma-bound-tag-host');
      const tag = document.createElement('span');
      tag.className = 'gigma-bound-origin-tag';
      const ic = __gigmaMakeUsageIconEl(isChat ? 'fa-comment' : 'fa-users', isChat ? 'gigma-chat-world-icon' : 'gigma-character-world-icon');
      ic.classList.add('gigma-bound-origin-icon');
      tag.appendChild(ic);
      tag.appendChild(document.createTextNode(boundName.slice(0, 15)));
      main.insertBefore(tag, title);
    }
  }catch(_){ }
  try{ __gigmaUpdateUnchainedRowLabelPadding(labelEl); }catch(_){ }
  try{ requestAnimationFrame(() => __gigmaUpdateUnchainedRowLabelPadding(labelEl)); }catch(_){ }
  try{ gigmaMaybeAttachModalLorebookStats(labelEl, worldName); }catch(_){ }
};


