// --- GIGMA: Never let the extension dialog itself receive focus (prevents the window from being "selected") ---
(function gigmaNeverFocusDialogOnce(){
  try{
    if (window.__gigmaNeverFocusDialog) return;
    window.__gigmaNeverFocusDialog = true;
    document.addEventListener('focusin', (ev)=>{
      try{
        const t = ev && ev.target;
        if (!t || t.tagName !== 'DIALOG') return;
        const dlg = t;
        const cls = dlg.classList;
        if (!cls) return;
        if (!(cls.contains('gigma-wide') || cls.contains('gigma-narrow') || cls.contains('popup'))) return;
        if (document.activeElement === dlg && typeof dlg.blur === 'function') dlg.blur();
      }catch(_){ }
    }, true);
  }catch(_){ }
})();

// Auto-wire when popup nodes appear
(function(){
  if (window.__gigmaWidthObs) return;
  try{
    const obs = new MutationObserver((muts)=>{
      for (const m of muts){
        for (const n of m.addedNodes){
          try{
            if (!(n && n.nodeType===1)) continue;
            if (!(n.matches?.('dialog.popup, .swal2-popup, .st-popup') || (n.classList && (''+n.className).includes('popup')))) continue;
            try{
              if (typeof window.gigmaPreapplyDialogLayoutBootstrap === 'function') {
                window.gigmaPreapplyDialogLayoutBootstrap(n);
              }
            }catch(_){}
            try{
              if (typeof window.gigmaSkinPreviewAndFolderButtons === 'function') {
                window.gigmaSkinPreviewAndFolderButtons(n);
              }
            }catch(_){}
            if (typeof window.gigmaWireWidthButtons === 'function' && (n.querySelector?.('.gigmaWidthBtn') || document.querySelector('.gigmaWidthBtn'))){
              window.gigmaWireWidthButtons();
            }
          }catch(_){}
        }
      }
    });
    obs.observe(document.documentElement, {subtree:true, childList:true});
    window.__gigmaWidthObs = obs;
  }catch(_){}
})();
// GIGMA POPUP WIDTH TOGGLE (button INSIDE popup)
(function(){
  const KEY='gigma_modal_wide_pref_v2';
  function getPref(){
  try {
    const v = localStorage.getItem(KEY);
    // Default to wide view on first use (no stored preference yet).
    if (v === null) return true;
    return gigmaReadBinaryToggleString(v, true);
  } catch(e){
    // If localStorage is unavailable, prefer wide view as a safe default.
    return true;
  }
}
  function setPref(v){ try { localStorage.setItem(KEY, String(gigmaWriteBinaryToggle(v))); } catch(e){} }
  function getMobileAutoWide(){
    return gigmaIsMobileFullscreenActive() ? window.matchMedia('(orientation: landscape)').matches : null;
  }
  function getEffectiveWide(wide){
    const mobileWide = getMobileAutoWide();
    return mobileWide === null ? !!wide : mobileWide;
  }
  function findDialogFrom(el){
    let n = el;
    while(n){
      if (n.tagName && n.tagName.toLowerCase()==='dialog') return n;
      n = n.parentElement;
    }
    // fallback: SillyTavern uses <dialog class="popup">
    return document.querySelector('dialog.popup') || null;
  }

  function gigmaPreapplyDialogLayoutBootstrap(dlg){
    try{
      if (!dlg || !dlg.classList) return;
      const isGigmaDialog = !!(
        dlg.querySelector?.('#gigma-modal-root, #gigma-global-settings, .gigmaWidthBtn') ||
        dlg.classList.contains('gigma-wide') ||
        dlg.classList.contains('gigma-narrow')
      );
      if (!isGigmaDialog) return;
      const mobileFullscreen = gigmaIsMobileFullscreenActive();
      const wide = getEffectiveWide(getPref());
      const NARROW_PX = '44.6875rem';
      const WIDE_WIDTH = 'min(137.5rem, 94.5vw)';
      const MOBILE_WIDTH = '100dvw';
      const MOBILE_HEIGHT = '100dvh';
      if (wide){
        dlg.classList.add('gigma-wide');
        dlg.classList.remove('gigma-narrow');
      }else{
        dlg.classList.add('gigma-narrow');
        dlg.classList.remove('gigma-wide');
      }
      dlg.style.maxWidth = mobileFullscreen ? MOBILE_WIDTH : (wide ? WIDE_WIDTH : NARROW_PX);
      dlg.style.width = mobileFullscreen ? MOBILE_WIDTH : (wide ? WIDE_WIDTH : NARROW_PX);
      dlg.style.height = mobileFullscreen ? MOBILE_HEIGHT : '';
      dlg.style.maxHeight = mobileFullscreen ? MOBILE_HEIGHT : '';
      try{
        if (typeof window.gigmaSkinPreviewAndFolderButtons === 'function') window.gigmaSkinPreviewAndFolderButtons(dlg);
      }catch(_){}
    }catch(_){}
  }
  window.gigmaPreapplyDialogLayoutBootstrap = gigmaPreapplyDialogLayoutBootstrap;

  // In wide mode, the right-hand pane can overlap the header area and intercept clicks.
  // Move the existing narrow-mode close button (#gigma-global-cancel) into a dedicated
  // top-right host inside the dialog so it remains clickable, then restore it in narrow mode.
  
  // Keep the header Accept (✓) and Cancel (X) buttons in the exact same spots in both
  // narrow and wide layouts. We anchor their positions to the dialog's horizontal center
  // using the narrow layout geometry so scrollbars/panes cannot shift them.
  function gigmaSyncFixedHeaderButtons(dlg){
    try{
      if (!dlg || !dlg.querySelector) return;
      const bar = dlg.querySelector('#gigma-global-settings');
      if (!bar) return;

      const acceptBtn = bar.querySelector('#gigma-global-accept') || dlg.querySelector('#gigma-global-accept');
      const cancelBtn = bar.querySelector('#gigma-global-cancel') || dlg.querySelector('#gigma-global-cancel');
      if (!acceptBtn || !cancelBtn) return;

      // Legacy absolute overlay positioning can drift under zoom/font changes; remove it.
      try{
        const layer = dlg.querySelector('#gigma-fixed-header-layer');
        if (layer && layer.parentNode) layer.parentNode.removeChild(layer);
      }catch(_){}

      // Slot wrappers for Accept / Cancel keep their vertical alignment identical to the other header groups.
      let acceptSlot = bar.querySelector('#gigma-global-accept-slot');
      if (!acceptSlot){
        acceptSlot = document.createElement('div');
        acceptSlot.id = 'gigma-global-accept-slot';
        bar.insertBefore(acceptSlot, bar.firstChild);
      }
      let cancelSlot = bar.querySelector('#gigma-global-cancel-slot');
      if (!cancelSlot){
        cancelSlot = document.createElement('div');
        cancelSlot.id = 'gigma-global-cancel-slot';
        bar.appendChild(cancelSlot);
      }
      try{ if (acceptBtn.parentNode !== acceptSlot) acceptSlot.appendChild(acceptBtn); }catch(_){}
      try{ if (cancelBtn.parentNode !== cancelSlot) cancelSlot.appendChild(cancelBtn); }catch(_){}

      // Ensure the 5-slot header structure exists:
      // [Accept] [Width] [Scroll controls (center)] [Bug+Help] [Cancel]
      let widthSlot = bar.querySelector('#gigma-global-width-slot');
      if (!widthSlot){
        widthSlot = document.createElement('div');
        widthSlot.id = 'gigma-global-width-slot';
        bar.insertBefore(widthSlot, acceptSlot.nextSibling);
      }

      let bugHelp = bar.querySelector('#gigma-global-bughelp');
      if (!bugHelp){
        bugHelp = document.createElement('div');
        bugHelp.id = 'gigma-global-bughelp';
        bar.insertBefore(bugHelp, cancelSlot);
      }

      const center = bar.querySelector('.gigma-global-center');

      // Normalize direct-child ordering to match the grid columns.
      try{ if (acceptSlot.parentNode !== bar) bar.insertBefore(acceptSlot, bar.firstChild); }catch(_){}
      try{ if (widthSlot.parentNode !== bar) bar.insertBefore(widthSlot, acceptSlot.nextSibling); }catch(_){}
      try{
        if (center && center.parentNode !== bar) bar.insertBefore(center, bugHelp);
      }catch(_){}
      try{ if (bugHelp.parentNode !== bar) bar.insertBefore(bugHelp, cancelSlot); }catch(_){}
      try{ if (cancelSlot.parentNode !== bar) bar.appendChild(cancelSlot); }catch(_){} 

      // Move the Wide/Narrow toggle into its slot (and keep View Lock grouped next to it).
      try{
        const widthBtn = dlg.querySelector('.gigmaWidthBtn');
        if (widthBtn && widthBtn.parentNode !== widthSlot) widthSlot.appendChild(widthBtn);
        gigmaLockWidthToggleButton(widthBtn);

        let viewLockBtn = dlg.querySelector('#gigma-view-lock-global');
        if (!viewLockBtn){
          viewLockBtn = document.createElement('button');
          viewLockBtn.id = 'gigma-view-lock-global';
          viewLockBtn.type = 'button';
          viewLockBtn.className = 'menu_button gigma-global-icon gigma-view-lock-btn';
          viewLockBtn.setAttribute('aria-label','View lock');
          viewLockBtn.setAttribute('title','View lock');
          viewLockBtn.setAttribute('aria-pressed','false');
          const icon = document.createElement('i');
          icon.className = 'fa-solid fa-lock-open';
          icon.setAttribute('aria-hidden','true');
          viewLockBtn.appendChild(icon);
        }
        if (viewLockBtn.parentNode !== widthSlot) widthSlot.appendChild(viewLockBtn);

        try{
          const locked = (typeof window.gigmaGetViewLockPref === 'function') ? !!window.gigmaGetViewLockPref() : false;
          if (typeof window.gigmaUpdateViewLockButton === 'function') window.gigmaUpdateViewLockButton(viewLockBtn, locked);
          if (typeof window.gigmaApplyViewLockToDialog === 'function') window.gigmaApplyViewLockToDialog(dlg, locked);
        }catch(_){}
      }catch(_){}

      // Move Bug + Help next to each other, between Scroll and Cancel.
      try{
        const bugBtn = dlg.querySelector('#gigma-global-bug');
        const helpBtn = dlg.querySelector('#gigma-global-help');
        if (bugBtn && bugBtn.parentNode !== bugHelp) bugHelp.appendChild(bugBtn);
        if (helpBtn && helpBtn.parentNode !== bugHelp) bugHelp.appendChild(helpBtn);
      }catch(_){}

      // Re-run on any size/layout changes (covers zoom + font-size changes reliably).
      try{
        if (!dlg.__gigmaHeaderObserver && typeof ResizeObserver === 'function'){
          dlg.__gigmaHeaderObserver = new ResizeObserver(()=>{
            try{ requestAnimationFrame(()=>gigmaSyncFixedHeaderButtons(dlg)); }catch(_){}
          });
          dlg.__gigmaHeaderObserver.observe(bar);
        }
      }catch(_){}
    }catch(_){}
  }

  // Keep fixed button positions correct on viewport resize.
  (function(){
    try{
      if (window.__gigmaFixedHeaderBtnsResize) return;
      window.__gigmaFixedHeaderBtnsResize = true;
      window.addEventListener('resize', ()=>{
        try{
          const dlgs = document.querySelectorAll('dialog.gigma-wide, dialog.gigma-narrow');
          for (const d of dlgs){
            try{ gigmaSyncFixedHeaderButtons(d); }catch(_){}
          }
        }catch(_){}
      }, { passive: true });
    }catch(_){}
  })();

    function applyWidthToDialog(dlg, wide){
    if (!dlg) return;

    // Pixel-perfect wide/narrow scroll anchoring using the same anchor logic
    // as the Order/Budget view toggle: first visible row/folder header + its
    // within-row scroll percentage (works for nested folders too).
    let leftAnchor = null;
    try{
      if (typeof gigmaCaptureLeftPaneScrollAnchor === 'function') leftAnchor = gigmaCaptureLeftPaneScrollAnchor();
    }catch(_){}

    try{
      // Width constants and viewport cap for the dialog
      const NARROW_PX = '44.6875rem';
      // Wide mode: keep roughly 10% margins on each side while respecting
      // the previous 137.5rem cap.
      const WIDE_WIDTH = 'min(137.5rem, 94.5vw)';
      const MOBILE_WIDTH = '100dvw';
      const MOBILE_HEIGHT = '100dvh';
      const mobileFullscreen = gigmaIsMobileFullscreenActive();
      wide = getEffectiveWide(wide);
      // State classes
      try{
        if (dlg && dlg.classList){
          if (wide){
            dlg.classList.add('gigma-wide');
            dlg.classList.remove('gigma-narrow');
          }else{
            dlg.classList.add('gigma-narrow');
            dlg.classList.remove('gigma-wide');
          }
        }
      }catch(_){}
      // Apply widths
      dlg.style.maxWidth = mobileFullscreen ? MOBILE_WIDTH : (wide ? WIDE_WIDTH : NARROW_PX);
      dlg.style.width = mobileFullscreen ? MOBILE_WIDTH : (wide ? WIDE_WIDTH : NARROW_PX);
      dlg.style.height = mobileFullscreen ? MOBILE_HEIGHT : '';
      dlg.style.maxHeight = mobileFullscreen ? MOBILE_HEIGHT : '';
      try{ gigmaSyncFixedHeaderButtons(dlg); }catch(_){ }
      // GIGMA FIX (Nov 2025):
      // When switching layouts we need two behaviors:
      //   1) Wide -> Narrow: make sure the focused folder's list is moved back
      //      under its header in the left column so it can be expanded.
      //   2) Narrow -> Wide: restore the previously focused folder so the user
      //      doesn't lose focus just by toggling the view.
      try{
        if (typeof window.gigmaSetRightPaneFolder === 'function'){
          const currentId = (typeof window.gigmaRightPaneActiveFolderId === 'string'
            ? window.gigmaRightPaneActiveFolderId
            : 'none');
          if (!wide){
            // Going to narrow view.
            if (currentId && currentId !== 'none'){
              // Remember which folder was focused, then defocus it so its list
              // is rendered back in the left column.
              window.__gigmaLastFocusedFolderBeforeNarrow = currentId;
              try{ window.__gigmaInWidthToggle = true; }catch(_){}
              try{ window.gigmaSetRightPaneFolder('none'); }catch(_){}
              try{ window.__gigmaInWidthToggle = false; }catch(_){}
            }
          }else{
            // Going to wide view.
            const remembered = window.__gigmaLastFocusedFolderBeforeNarrow;
            // Only restore if nothing else has claimed focus in the meantime.
            if (remembered && remembered !== 'none' &&
                (!currentId || currentId === 'none')){
              try{
                window.gigmaSetRightPaneFolder(remembered);
              }catch(_){}
            }
          }
        }
      }catch(_){}

      // Restore scroll anchor AFTER layout changes.
      try{
        if (typeof gigmaRestoreLeftPaneScrollAnchor === 'function') gigmaRestoreLeftPaneScrollAnchor(leftAnchor);
      }catch(_){}

      // Recompute lorebook header stats columns after view width changes (narrow <-> wide).
      try{ requestAnimationFrame(() => gigmaUpdateModalLorebookStatsColumnCountsAllRows()); }catch(_){ }
    }catch(e){}
}
  function gigmaWidthToggleIconSvg(wide){
    const leftClass = wide ? 'fa-arrow-left' : 'fa-arrow-right';
    const rightClass = wide ? 'fa-arrow-right' : 'fa-arrow-left';
    const modeClass = wide ? ' gigma-width-btn-pair-wide' : ' gigma-width-btn-pair-narrow';
    return '<span class="gigma-width-btn-pair' + modeClass + '" aria-hidden="true"><i class="fa-solid ' + leftClass + '"></i><i class="fa-solid ' + rightClass + '"></i></span>';
  }

  function gigmaApplyWidthToggleButtonSize(btn){
    try{
      if (!btn) return;
      const widthExpr = 'calc(var(--gigma-hdr-btn, 2em) * 2)';
      btn.style.width = widthExpr;
      btn.style.minWidth = widthExpr;
      btn.style.maxWidth = widthExpr;
      btn.style.paddingLeft = '0';
      btn.style.paddingRight = '0';
    }catch(_){}
  }

  function gigmaLockWidthToggleButton(btn){
    try{
      if (!btn) return;
      gigmaApplyWidthToggleButtonSize(btn);
    }catch(_){}
  }

  function setBtnLabel(btn, wide){
      try{
        if (!btn) return;
        const label = wide ? 'Wide' : 'Narrow';
        const title = wide ? 'Current layout: wide' : 'Current layout: narrow';
        btn.classList.add('gigma-width-iconized');
        const labelSpan = document.createElement('span');
        labelSpan.className = 'gigma-width-btn-label';
        labelSpan.textContent = label;
        const glyph = document.createElement('span');
        glyph.className = 'gigma-width-btn-glyph';
        glyph.innerHTML = gigmaWidthToggleIconSvg(!!wide);
        btn.replaceChildren(labelSpan, glyph);
        btn.setAttribute('aria-label', title);
        btn.setAttribute('title', title);
        gigmaApplyWidthToggleButtonSize(btn);
      }catch(_){
        btn.textContent = wide ? 'Wide' : 'Narrow';
      }
  }
  // Wire any uninitialized buttons inside the current DOM (called right after new Popup(...))
  window.gigmaWireWidthButtons = function(){
    const buttons = document.querySelectorAll('.gigmaWidthBtn');
    const pref = getPref();
    const effectivePref = getEffectiveWide(pref);
    for (const btn of buttons){
      if (btn.dataset.gigmaWired === '1') continue;
      btn.dataset.gigmaWired = '1';
      const dlg = findDialogFrom(btn);
      setBtnLabel(btn, effectivePref);
      applyWidthToDialog(dlg, pref);
      btn.addEventListener('click', (ev)=>{
        ev.preventDefault();
        ev.stopPropagation();
        const d = findDialogFrom(btn);
        const mobileWide = getMobileAutoWide();
        if (mobileWide !== null){
          setBtnLabel(btn, mobileWide);
          applyWidthToDialog(d, mobileWide);
          return;
        }
        const next = !getPref();
        setPref(next);
        setBtnLabel(btn, next);
        applyWidthToDialog(d, next);
      }, { passive: true });
    }
  };
  function syncMobileAutoWidthMode(){
    try{
      const mobileWide = getMobileAutoWide();
      if (mobileWide === null) return;
      const dlgs = document.querySelectorAll('dialog.gigma-wide, dialog.gigma-narrow, dialog.popup');
      for (const dlg of dlgs){
        if (!dlg.querySelector?.('#gigma-modal-root, #gigma-global-settings, .gigmaWidthBtn')) continue;
        applyWidthToDialog(dlg, mobileWide);
        const btn = dlg.querySelector('.gigmaWidthBtn');
        if (btn) setBtnLabel(btn, mobileWide);
      }
    }catch(_){ }
  }
  if (!window.__gigmaMobileAutoWidthListener){
    window.__gigmaMobileAutoWidthListener = true;
    window.addEventListener('resize', syncMobileAutoWidthMode, { passive: true });
    window.addEventListener('orientationchange', syncMobileAutoWidthMode, { passive: true });
  }

  // public getter for Popup option usage
  window.getModalWide = window.getModalWide || getPref;
  // Styles: toolbar row + button
  if (!document.getElementById('gigma-width-toolbar-style')){
    const st = document.createElement('style');
    st.id = 'gigma-width-toolbar-style';
    st.textContent = `
      .gigma-modal-toolbar{
        margin-top:0.375em;
        display:flex;
        align-items:center;
        justify-content:center; /* keep buttons grouped together */
        gap:0.25em;                /* minimal horizontal gap between buttons */
        padding-bottom:0.25em;
        margin-bottom:0.125em;
        border-bottom:none;
        position:relative;
      }
      .gigma-modal-toolbar .gigma-toolbar-title{
        font-weight:600;
        font-size:1.125em;
        opacity:.85;
      }
      .gigma-modal-toolbar .gigmaWidthBtn{
        white-space:nowrap;
        display:inline-block;
        margin:0;               /* remove auto margins that pushed it away from the preset toggle */
      }
      .gigmaWidthBtn{
        box-sizing:border-box;
      }
      .gigmaWidthBtn.gigma-width-iconized,
      #gigma-global-settings .gigmaWidthBtn{
        width:calc(var(--gigma-hdr-btn, 2em) * 2) !important;
        min-width:calc(var(--gigma-hdr-btn, 2em) * 2) !important;
        max-width:calc(var(--gigma-hdr-btn, 2em) * 2) !important;
        padding-left:0 !important;
        padding-right:0 !important;
      }
      .gigmaWidthBtn.gigma-width-iconized{
        position:relative;
        display:inline-flex !important;
        align-items:center !important;
        justify-content:center !important;
        box-sizing:border-box;
        overflow:hidden;
      }
      .gigmaWidthBtn .gigma-width-btn-label{
        visibility:hidden;
        white-space:nowrap;
        line-height:inherit;
        display:block;
      }
      .gigmaWidthBtn .gigma-width-btn-glyph{
        position:absolute;
        inset:0;
        display:inline-flex;
        align-items:center;
        justify-content:center;
      }
      .gigmaWidthBtn .gigma-width-btn-pair{
        display:inline-flex;
        align-items:center;
        justify-content:center;
        gap:0.36em;
        line-height:1;
        position:relative;
      }
      .gigmaWidthBtn .gigma-width-btn-pair::before,
      .gigmaWidthBtn .gigma-width-btn-pair::after{
        content:'';
        position:absolute;
        top:50%;
        transform:translateY(-50%);
        height:1em;
        border-left:0.16em solid currentColor;
        opacity:0.92;
      }
      .gigmaWidthBtn .gigma-width-btn-pair-wide::before{
        left:-0.22em;
      }
      .gigmaWidthBtn .gigma-width-btn-pair-wide::after{
        right:-0.22em;
      }
      .gigmaWidthBtn .gigma-width-btn-pair-narrow::before{
        left:50%;
        transform:translate(-50%, -50%);
      }
      .gigmaWidthBtn .gigma-width-btn-pair-narrow::after{
        display:none;
      }
      .gigmaWidthBtn .gigma-width-btn-pair i{
        font-size:0.82em;
        line-height:1;
        width:1em;
        flex:0 0 1em;
        text-align:center;
        display:inline-flex;
        align-items:center;
        justify-content:center;
      }
      .gigma-modal-toolbar + .world_entry_form_control h3{
        margin-top:0;
      }
`;
    document.head.appendChild(st);
  }
})();
