// Debugging flag and helper
const DEBUG_GIGMA = false;
function gigmaDebug(...args) {
    if (DEBUG_GIGMA && typeof console !== 'undefined') {
        console.info('[GIGMA][DEBUG]', ...args);
    }
}

function gigmaGetBudgetDebugEntryName(entry) {
    try {
        const comment = String(entry?.comment ?? '').trim();
        if (comment) return comment;
        const name = String(entry?.name ?? entry?.displayName ?? '').trim();
        if (name) return name;
        const keys = Array.isArray(entry?.key) ? entry.key.map(x => String(x ?? '').trim()).filter(Boolean) : [];
        if (keys.length) return keys.join(', ');
        const lines = String(entry?.content ?? '').split(/\r?\n/).map(x => x.trim()).filter(Boolean);
        if (lines.length) return lines[0];
        return '';
    } catch (_e) {
        return '';
    }
}

function gigmaBuildBudgetDebugEntrySnapshot(entry) {
    return {
        world: String(entry?.world || ''),
        uid: String(entry?.uid ?? ''),
        name: gigmaGetBudgetDebugEntryName(entry),
        order: gigmaGetEntryOrderNumber(entry),
        comment: entry?.comment ?? null,
    };
}

function gigmaBuildBudgetDebugEntryKey(entry) {
    return `${String(entry?.world || '')}:${String(entry?.uid ?? '')}`;
}

function gigmaGetUniqueBudgetDebugEntries(entries) {
    try {
        if (!Array.isArray(entries) || !entries.length) return [];
        const out = [];
        const seen = new Set();
        for (const entry of entries) {
            if (!entry || typeof entry !== 'object') continue;
            const key = gigmaBuildBudgetDebugEntryKey(entry);
            if (!key || seen.has(key)) continue;
            seen.add(key);
            out.push(entry);
        }
        return out;
    } catch (_e) {
        return Array.isArray(entries) ? entries.filter(entry => !!entry && typeof entry === 'object') : [];
    }
}

function gigmaLogBudgetDebugEntries(stage, entries, extra = null) {
    try {
        if (!gigmaGetBudgetDebugLogsPref() || typeof console === 'undefined') return;
        const uniqueEntries = gigmaGetUniqueBudgetDebugEntries(entries);
        const list = uniqueEntries.map(gigmaBuildBudgetDebugEntrySnapshot);
        console.groupCollapsed(`[GIGMA][DEBUG] ${stage} (${list.length})`);
        if (extra && typeof extra === 'object') {
            console.log('[GIGMA][DEBUG] summary:', extra);
        }
        console.table(list);
        console.log('[GIGMA][DEBUG] entries:', list);
        console.groupEnd();
    } catch (_e) { }
}
// Utility functions

// Simple debounce (leading=false, trailing=true)
function debounce(fn, wait = 50) {
    let t = null, lastArgs = null;
    return function debounced(...args) {
        lastArgs = args;
        if (t) clearTimeout(t);
        t = setTimeout(() => {
            t = null;
            fn.apply(this, lastArgs);
        }, wait);
    };
}

// Fire-and-forget background scheduler
function scheduleBackground(fn) {
    const run = () => {
        try {
            const ret = fn();
            if (ret && typeof ret.then === 'function') {
                ret.catch(e => console.warn('[GIGMA] scheduleBackground task error:', e));
            }
        } catch (e) {
            console.warn('[GIGMA] scheduleBackground task sync error:', e);
        }
    };
    try {
        if (typeof requestIdleCallback === 'function') {
            return requestIdleCallback(run, { timeout: 120 });
        }
    } catch {}
    return setTimeout(run, 0);
}


const GIGMA_MOBILE_LARGE_LOREBOOK_THRESHOLD = 250;

function gigmaIsMobileLargeLorebookPerfMode() {
    try {
        return !!gigmaIsMobileFullscreenActive() && Array.isArray(world_names) && world_names.length >= GIGMA_MOBILE_LARGE_LOREBOOK_THRESHOLD;
    } catch (_e) {
        return false;
    }
}

// Cross-event token count cache
const TOKEN_COUNT_CACHE = new Map();
function gigmaHash32(str) {
    let h = 2166136261;
    const s = String(str || '');
    for (let i = 0; i < s.length; i++) {
        h ^= s.charCodeAt(i);
        h = Math.imul(h, 16777619);
    }
    return (h >>> 0);
}
function getEntryTokenCountCached(entry, leadingNewline = false, contentHash = null) {
    try {
        if (!gigmaGetCountLeadingNewlinePref()) leadingNewline = false;
        const uid = entry?.uid ?? '';
        const content = typeof entry?.content === 'string' ? entry.content : '';
        const nl = leadingNewline ? 1 : 0;
        const h = (typeof contentHash === 'number' && Number.isFinite(contentHash)) ? (contentHash >>> 0) : gigmaHash32(content || '');
        const key = `${uid}:${nl}:${h}`;
        if (TOKEN_COUNT_CACHE.has(key)) return TOKEN_COUNT_CACHE.get(key);
        const tokenizerId = (() => {
            try {
                const info = (typeof getFriendlyTokenizerName === 'function') ? getFriendlyTokenizerName() : null;
                const tid = Number(info && info.tokenizerId);
                if (Number.isFinite(tid) && tid !== tokenizers.BEST_MATCH && tid !== tokenizers.NONE) return tid;
            } catch (_) {}
            return tokenizers.OPENAI;
        })();
        const text = leadingNewline ? `\n${content || ''}` : (content || '');
        const ids = (typeof getTextTokens === 'function') ? getTextTokens(tokenizerId, text) : [];
        const tokens = (ids && typeof ids.length === 'number') ? ids.length : 0;
        TOKEN_COUNT_CACHE.set(key, tokens);
        return tokens;
    } catch {
        return 0;
    }
}



function gigmaGetCurrentTokenizerId() {
    try {
        const info = (typeof getFriendlyTokenizerName === 'function') ? getFriendlyTokenizerName() : null;
        const tid = Number(info && info.tokenizerId);
        if (Number.isFinite(tid)) return tid;
    } catch (_e) {}
    return NaN;
}

async function gigmaRebuildAllIndexedLorebookStatsForTokenizerChange() {
    if (window.__gigmaTokenizerRebuildPromise) return window.__gigmaTokenizerRebuildPromise;
    const run = (async () => {
        try {
            if (typeof TOKEN_COUNT_CACHE !== 'undefined' && TOKEN_COUNT_CACHE && typeof TOKEN_COUNT_CACHE.clear === 'function') TOKEN_COUNT_CACHE.clear();
        } catch (_eClear) {}

        try {
            const store = gigmaGetLorebookStatsIndexStore();
            const booksById = store && store.booksById && typeof store.booksById === 'object' ? store.booksById : {};
            const worlds = [];
            for (const b of Object.values(booksById)) {
                const w = b && typeof b === 'object' ? String(b.worldName || '') : '';
                if (w) worlds.push(w);
            }
            for (const w of worlds) {
                try { await gigmaEnsureLorebookStatsIndexForWorld(w, { forceRebuild: true }); } catch (_eBook) {}
                await new Promise(r => setTimeout(r, 0));
            }
        } catch (_e) {}
    })();
    try { window.__gigmaTokenizerRebuildPromise = run; } catch (_eSet) {}
    run.finally(() => { try { window.__gigmaTokenizerRebuildPromise = null; } catch (_eClr) {} });
    return run;
}

function gigmaCheckTokenizerChangedNow() {
    try {
        const tid = gigmaGetCurrentTokenizerId();
        if (!Number.isFinite(tid)) return;
        const last = Number(window.__gigmaLastTokenizerId);
        if (Number.isFinite(last) && last === tid) return;
        window.__gigmaLastTokenizerId = tid;
        gigmaRebuildAllIndexedLorebookStatsForTokenizerChange().catch((_e) => {});
    } catch (_e) {}
}

function gigmaInstallTokenizerChangeHooksOnce() {
    try {
        if (window.__gigmaTokenizerChangeHooksInstalled) return;
        window.__gigmaTokenizerChangeHooksInstalled = true;
        try {
            const tid = gigmaGetCurrentTokenizerId();
            if (Number.isFinite(tid)) window.__gigmaLastTokenizerId = tid;
        } catch (_eInit) {}

        document.addEventListener('change', (ev) => {
            try {
                const t = ev && ev.target;
                if (!(t instanceof HTMLElement)) return;
                const k = String(t.id || t.getAttribute?.('name') || '');
                if (!k) return;
                gigmaCheckTokenizerChangedNow();
            } catch (_e2) {}
        }, true);
    } catch (_e) {}
}
