const GIGMA_LOREBOOK_STATS_ICON_HTML = `<span class="gigma-global-wi-stats-iconwrap" aria-hidden="true"><i class="fa-solid fa-chart-simple gigma-global-wi-stats-icon" aria-hidden="true"></i><span class="gigma-global-wi-stats-globe" aria-hidden="true"><i class="fa-solid fa-file-lines" aria-hidden="true"></i></span></span>`;


function gigmaIsModalLorebookStatsRawSectionEnabled() {
    return !!EXTENSION_STATE.modalLorebookStatsSectionRaw;
}

function gigmaIsModalLorebookStatsActivatedSectionEnabled() {
    return !!EXTENSION_STATE.modalLorebookStatsSectionActivated;
}

function gigmaIsModalLorebookStatsIncludedSectionEnabled() {
    return !!EXTENSION_STATE.modalLorebookStatsSectionIncluded;
}

function gigmaCreateModalLorebookStatsSnapshotPair() {
    return {
        activatedByWorld: new Map(),
        includedByWorld: new Map(),
        activatedEntryUidsByWorld: new Map(),
        includedEntryUidsByWorld: new Map(),
        updatedAt: Date.now(),
    };
}

function gigmaBuildModalLorebookStatsByWorldFromEntries(entriesIterable) {
    const byWorld = new Map();
    try {
        if (!entriesIterable || typeof entriesIterable[Symbol.iterator] !== 'function') return byWorld;
        const seenByWorld = new Map();
        for (const entry of entriesIterable) {
            if (!entry || typeof entry !== 'object') continue;
            const worldName = String(entry.world || '').trim();
            if (!worldName) continue;

            const uid = String(entry.uid ?? '');
            const content = (typeof entry.content === 'string') ? entry.content : '';
            const enabledNonEmpty = entry.disable !== true && !!content;
            const leadingNewline = (seenByWorld.get(worldName) === true) && enabledNonEmpty && uid;

            const rec = gigmaBuildLorebookEntryStatsIndexRecord(entry, leadingNewline);
            if (!rec) continue;

            let stats = byWorld.get(worldName);
            if (!stats) {
                stats = gigmaCreateEmptyLorebookStatsObject();
                byWorld.set(worldName, stats);
            }

            for (const k of (Array.isArray(rec.cats) ? rec.cats : [])) {
                const bucket = stats[k] || (stats[k] = { entries: 0, tokens: 0 });
                bucket.entries = (Number(bucket.entries) || 0) + 1;
                bucket.tokens = (Number(bucket.tokens) || 0) + (Number(rec.tokens) || 0);
            }

            if (enabledNonEmpty && uid) seenByWorld.set(worldName, true);
        }
    } catch (_e) { }
    return byWorld;
}

function gigmaBuildModalLorebookEntryUidSetByWorldFromEntries(entriesIterable) {
    const byWorld = new Map();
    try {
        if (!entriesIterable || typeof entriesIterable[Symbol.iterator] !== 'function') return byWorld;
        for (const entry of entriesIterable) {
            if (!entry || typeof entry !== 'object') continue;
            const worldName = String(entry.world || '').trim();
            const uidRaw = entry.uid;
            if (!worldName || uidRaw == null) continue;
            const uid = String(uidRaw);
            let set = byWorld.get(worldName);
            if (!set) {
                set = new Set();
                byWorld.set(worldName, set);
            }
            set.add(uid);
        }
    } catch (_e) { }
    return byWorld;
}

function gigmaSetLastModalLorebookStatsSnapshotPair(activatedEntriesIterable, includedEntriesIterable) {
    try {
        const pair = gigmaCreateModalLorebookStatsSnapshotPair();
        pair.activatedByWorld = gigmaBuildModalLorebookStatsByWorldFromEntries(activatedEntriesIterable);
        pair.includedByWorld = gigmaBuildModalLorebookStatsByWorldFromEntries(includedEntriesIterable);
        pair.activatedEntryUidsByWorld = gigmaBuildModalLorebookEntryUidSetByWorldFromEntries(activatedEntriesIterable);
        pair.includedEntryUidsByWorld = gigmaBuildModalLorebookEntryUidSetByWorldFromEntries(includedEntriesIterable);
        pair.updatedAt = Date.now();

        EXTENSION_STATE.modalLorebookStatsLastWiSnapshotPair = pair;
        try { gigmaRecomputeLastBudgetDropSummary(); } catch (_eRecompute) { }
        return true;
    } catch (_e) {
        return false;
    }
}

function gigmaGetLastModalLorebookStatsSnapshotByWorld(sectionKey, worldName) {
    try {
        const pair = EXTENSION_STATE.modalLorebookStatsLastWiSnapshotPair;
        if (!pair || typeof pair !== 'object') return null;
        const world = String(worldName || '').trim();
        if (!world) return gigmaCreateEmptyLorebookStatsObject();
        const map = (sectionKey === 'included') ? pair.includedByWorld : pair.activatedByWorld;
        if (!(map && typeof map.get === 'function')) return null;
        return map.get(world) || gigmaCreateEmptyLorebookStatsObject();
    } catch (_e) {
        return null;
    }
}

function gigmaGetLastModalLorebookEntryUidSetByWorld(sectionKey, worldName) {
    try {
        const pair = EXTENSION_STATE.modalLorebookStatsLastWiSnapshotPair;
        if (!pair || typeof pair !== 'object') return new Set();
        const world = String(worldName || '').trim();
        if (!world) return new Set();
        const map = (sectionKey === 'included') ? pair.includedEntryUidsByWorld : pair.activatedEntryUidsByWorld;
        if (!(map && typeof map.get === 'function')) return new Set();
        const set = map.get(world);
        return (set && typeof set.has === 'function') ? set : new Set();
    } catch (_e) {
        return new Set();
    }
}


// === GIGMA: Persistent lorebook token/category index (ID-keyed) ===
const GIGMA_LOREBOOK_STATS_INDEX_VERSION = 3;

function gigmaCreateEmptyLorebookStatsObject() {
    const out = {};
    for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
        out[c.key] = { entries: 0, tokens: 0 };
    }
    return out;
}

function gigmaGetLorebookStatsIndexStore() {
    try {
        if (!gigmaExtensionSettings || typeof gigmaExtensionSettings !== 'object') return { version: GIGMA_LOREBOOK_STATS_INDEX_VERSION, booksById: {} };
        let store = gigmaExtensionSettings.lorebookStatsIndex;
        if (!store || typeof store !== 'object') {
            store = { version: GIGMA_LOREBOOK_STATS_INDEX_VERSION, booksById: {} };
            gigmaExtensionSettings.lorebookStatsIndex = store;
            return store;
        }
        if (!store.booksById || typeof store.booksById !== 'object') store.booksById = {};
        if (store.version !== GIGMA_LOREBOOK_STATS_INDEX_VERSION) {
            store.version = GIGMA_LOREBOOK_STATS_INDEX_VERSION;
            store.booksById = {};
        }
        return store;
    } catch (_e) {
        return { version: GIGMA_LOREBOOK_STATS_INDEX_VERSION, booksById: {} };
    }
}

function gigmaPersigigmarebookStatsIndexStore() {
    try {
        if (gigmaIsMobileLargeLorebookPerfMode()) {
            if (typeof saveSettingsDebounced === 'function') saveSettingsDebounced();
            return;
        }
        const store = gigmaGetLorebookStatsIndexStore();
        const booksById = (store && store.booksById && typeof store.booksById === 'object') ? store.booksById : null;
        if (booksById) {
            for (const book of Object.values(booksById)) {
                if (!book || typeof book !== 'object' || Array.isArray(book)) continue;
                const rawEntriesByUid = (book.entriesByUid && typeof book.entriesByUid === 'object' && !Array.isArray(book.entriesByUid)) ? book.entriesByUid : null;
                if (rawEntriesByUid) {
                    const nextEntriesByUid = {};
                    for (const [entryUid, rawRecord] of Object.entries(rawEntriesByUid)) {
                        if (!rawRecord || typeof rawRecord !== 'object' || Array.isArray(rawRecord)) continue;
                        const nextRecord = {};
                        const tokens = Number(rawRecord.tokens) || 0;
                        const cats = Array.isArray(rawRecord.cats) ? rawRecord.cats.filter((v) => typeof v === 'string' && v) : [];
                        const sig = (typeof rawRecord.sig === 'string') ? rawRecord.sig : '';
                        nextRecord.tokens = tokens;
                        nextRecord.cats = cats;
                        if (sig) nextRecord.sig = sig;
                        nextEntriesByUid[String(entryUid)] = nextRecord;
                    }
                    book.entriesByUid = nextEntriesByUid;
                }
                const rawStats = book.stats;
                if (!rawStats || typeof rawStats !== 'object' || Array.isArray(rawStats)) continue;
                const nextStats = {};
                for (const [statsKey, rawBucket] of Object.entries(rawStats)) {
                    if (!rawBucket || typeof rawBucket !== 'object' || Array.isArray(rawBucket)) continue;
                    const nextBucket = {};
                    const entries = Number(rawBucket.entries) || 0;
                    const tokens = Number(rawBucket.tokens) || 0;
                    if (entries !== 0) nextBucket.entries = entries;
                    if (tokens !== 0) nextBucket.tokens = tokens;
                    if (Object.keys(nextBucket).length) nextStats[statsKey] = nextBucket;
                }
                book.stats = nextStats;
            }
        }
        if (typeof saveSettingsDebounced === 'function') saveSettingsDebounced();
    } catch (_e) {}
}

function gigmaNormalizeLorebookEntryPosition(entry) {
    try {
        const posRaw = (entry && entry.extensions && entry.extensions.position != null) ? entry.extensions.position : (entry ? entry.position : undefined);
        let pos = posRaw;
        if (typeof pos === 'string') {
            if (pos === 'before_char') pos = 0;
            else if (pos === 'after_char') pos = 1;
            else if (pos === 'ANTop') pos = 2;
            else if (pos === 'ANBottom') pos = 3;
            else if (pos === 'atDepth') pos = 4;
            else if (pos === 'EMTop') pos = 5;
            else if (pos === 'EMBottom') pos = 6;
            else if (pos === 'outlet') pos = 7;
            else pos = Number(pos);
        }
        return Number.isFinite(Number(pos)) ? Number(pos) : -1;
    } catch (_e) {
        return -1;
    }
}

function gigmaNormalizeLorebookEntryRole(entry) {
    try {
        const roleRaw = (entry && entry.extensions && entry.extensions.role != null) ? entry.extensions.role : (entry ? entry.role : undefined);
        return (typeof roleRaw === 'number') ? roleRaw : Number(roleRaw);
    } catch (_e) {
        return NaN;
    }
}

function gigmaComputeLorebookLeadingNewlineInfo(entriesObj, overrideUid = '', overrideEntry = null) {
    try {
        if (!entriesObj || typeof entriesObj !== 'object') return { count: 0, minUid: '' };
        const ovUid = String(overrideUid || '');
        let count = 0;
        let minOrder = Infinity;
        let minUid = '';
        const values = Object.values(entriesObj);
        for (const raw of values) {
            if (!raw || typeof raw !== 'object') continue;
            const uid = String(raw.uid ?? '');
            const e = (ovUid && uid === ovUid && overrideEntry && typeof overrideEntry === 'object') ? overrideEntry : raw;
            if (e.disable === true) continue;
            const content = (typeof e.content === 'string') ? e.content : '';
            if (!content) continue;
            count += 1;
            const ordRaw = Number(e.order ?? e.insertion_order ?? 0);
            const ord = Number.isFinite(ordRaw) ? ordRaw : 0;
            if (ord < minOrder || (ord === minOrder && uid && (minUid === '' || uid < minUid))) {
                minOrder = ord;
                minUid = uid;
            }
        }
        return { count, minUid };
    } catch {
        return { count: 0, minUid: '' };
    }
}


function gigmaBuildLorebookEntryStatsIndexRecord(entry, leadingNewline = false, contentHash = null) {
    if (!entry || typeof entry !== 'object') return null;

    const uid = String(entry.uid ?? '');
    if (!uid) return null;

    const content = (typeof entry.content === 'string') ? entry.content : '';
    const entryObj = (entry.content === content) ? entry : { ...entry, uid, content };
    const h = (typeof contentHash === 'number' && Number.isFinite(contentHash)) ? (contentHash >>> 0) : gigmaHash32(content || '');
    const tokens = Number(getEntryTokenCountCached(entryObj, leadingNewline, h)) || 0;

    const disabled = entry.disable === true;
    const pos = disabled ? -1 : gigmaNormalizeLorebookEntryPosition(entry);
    const roleVal = (!disabled && pos === 4) ? gigmaNormalizeLorebookEntryRole(entry) : 0;
    const sig = `${disabled ? 1 : 0}|${entry.constant === true ? 1 : 0}|${entry.vectorized === true ? 1 : 0}|${pos}|${roleVal}|${leadingNewline ? 1 : 0}|${h}`;

    const cats = ['total'];
    if (disabled) {
        cats.push('disabled');
        return { tokens, cats, sig };
    }

    cats.push('enabled');

    if (entry.constant === true) cats.push('constant');
    else if (entry.vectorized === true) cats.push('vectorized');
    else cats.push('normal');

    if (pos === 0) cats.push('charUp');
    else if (pos === 1) cats.push('charDown');
    else if (pos === 5) cats.push('emUp');
    else if (pos === 6) cats.push('emDown');
    else if (pos === 2) cats.push('anUp');
    else if (pos === 3) cats.push('anDown');
    else if (pos === 7) cats.push('outlet');
    else if (pos === 4) {
        if (extension_prompt_roles && roleVal === extension_prompt_roles.USER) cats.push('depthUser');
        else if (extension_prompt_roles && roleVal === extension_prompt_roles.ASSISTANT) cats.push('depthAssistant');
        else cats.push('depthSystem');
    }

    return { tokens, cats, sig };
}


function gigmaApplyLorebookEntryStatsIndexRecordToBook(book, record, sign) {
    if (!book || !record || !Array.isArray(record.cats)) return;
    if (!book.stats || typeof book.stats !== 'object') book.stats = gigmaCreateEmptyLorebookStatsObject();
    if (!book.dominance || typeof book.dominance !== 'object') {
        book.dominance = { enabled: 'enabled', mode: 'normal', pos: 'charUp' };
    }

    const domEnabled = book.dominance.enabled === 'disabled' ? 'disabled' : 'enabled';
    const domMode = (book.dominance.mode === 'constant' || book.dominance.mode === 'vectorized') ? book.dominance.mode : 'normal';
    const domPos = (typeof book.dominance.pos === 'string' && book.dominance.pos) ? book.dominance.pos : 'charUp';

    const entryDelta = sign > 0 ? 1 : -1;
    const tokenDelta = (sign > 0 ? 1 : -1) * (Number(record.tokens) || 0);

    for (const k of record.cats) {
        if (k !== 'total') {
            if (k === domEnabled) continue;
            if (k === domMode) continue;
            if (k === domPos) continue;
        }
        const bucket = book.stats[k] || (book.stats[k] = { entries: 0, tokens: 0 });
        bucket.entries = Math.max(0, (Number(bucket.entries) || 0) + entryDelta);
        bucket.tokens = Math.max(0, (Number(bucket.tokens) || 0) + tokenDelta);
    }
}

const GIGMA_LOREBOOK_STATS_MODE_KEYS = ['constant', 'normal', 'vectorized'];
const GIGMA_LOREBOOK_STATS_POS_KEYS = ['charUp', 'charDown', 'emUp', 'emDown', 'anUp', 'anDown', 'depthSystem', 'depthUser', 'depthAssistant', 'outlet'];

function gigmaEnsureLorebookStatsIndexBookDominance(book) {
    if (!book || typeof book !== 'object') return { enabled: 'enabled', mode: 'normal', pos: 'charUp' };
    if (!book.dominance || typeof book.dominance !== 'object') book.dominance = { enabled: 'enabled', mode: 'normal', pos: 'charUp' };
    const d = book.dominance;
    d.enabled = (d.enabled === 'disabled') ? 'disabled' : 'enabled';
    d.mode = (d.mode === 'constant' || d.mode === 'vectorized') ? d.mode : 'normal';
    d.pos = (typeof d.pos === 'string' && d.pos) ? d.pos : 'charUp';
    return d;
}

function gigmaComputeLorebookStatsIndexFullStats(book) {
    try {
        if (!book || typeof book !== 'object') return null;
        if (!book.stats || typeof book.stats !== 'object') return null;
        const d = gigmaEnsureLorebookStatsIndexBookDominance(book);
        const base = book.stats;

        const out = gigmaCreateEmptyLorebookStatsObject();
        for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
            const k = c.key;
            const b = base[k];
            if (b && typeof b === 'object') {
                out[k].entries = Number(b.entries) || 0;
                out[k].tokens = Number(b.tokens) || 0;
            }
        }

        const totalE = Number(out.total.entries) || 0;
        const totalT = Number(out.total.tokens) || 0;

        if (d.enabled === 'enabled') {
            const disE = Number(out.disabled.entries) || 0;
            const disT = Number(out.disabled.tokens) || 0;
            out.enabled.entries = totalE - disE;
            out.enabled.tokens = totalT - disT;
        } else {
            const enE = Number(out.enabled.entries) || 0;
            const enT = Number(out.enabled.tokens) || 0;
            out.disabled.entries = totalE - enE;
            out.disabled.tokens = totalT - enT;
        }

        const enabledE = Number(out.enabled.entries) || 0;
        const enabledT = Number(out.enabled.tokens) || 0;

        if (d.mode === 'normal') {
            const cE = Number(out.constant.entries) || 0;
            const vE = Number(out.vectorized.entries) || 0;
            const cT = Number(out.constant.tokens) || 0;
            const vT = Number(out.vectorized.tokens) || 0;
            out.normal.entries = enabledE - cE - vE;
            out.normal.tokens = enabledT - cT - vT;
        } else if (d.mode === 'constant') {
            const nE = Number(out.normal.entries) || 0;
            const vE = Number(out.vectorized.entries) || 0;
            const nT = Number(out.normal.tokens) || 0;
            const vT = Number(out.vectorized.tokens) || 0;
            out.constant.entries = enabledE - nE - vE;
            out.constant.tokens = enabledT - nT - vT;
        } else {
            const cE = Number(out.constant.entries) || 0;
            const nE = Number(out.normal.entries) || 0;
            const cT = Number(out.constant.tokens) || 0;
            const nT = Number(out.normal.tokens) || 0;
            out.vectorized.entries = enabledE - cE - nE;
            out.vectorized.tokens = enabledT - cT - nT;
        }

        let sumPosE = 0;
        let sumPosT = 0;
        for (const k of GIGMA_LOREBOOK_STATS_POS_KEYS) {
            if (k === d.pos) continue;
            sumPosE += Number(out[k]?.entries) || 0;
            sumPosT += Number(out[k]?.tokens) || 0;
        }
        out[d.pos].entries = enabledE - sumPosE;
        out[d.pos].tokens = enabledT - sumPosT;

        return out;
    } catch (_e) {
        return null;
    }
}

function gigmaPrepareLorebookStatsIndexBookForDelta(book) {
    try {
        if (!book || typeof book !== 'object') return;
        if (!book.stats || typeof book.stats !== 'object') book.stats = gigmaCreateEmptyLorebookStatsObject();
        const d = gigmaEnsureLorebookStatsIndexBookDominance(book);
        const zeroBucket = (key) => {
            const bucket = book.stats[key] || (book.stats[key] = { entries: 0, tokens: 0 });
            bucket.entries = 0;
            bucket.tokens = 0;
        };
        zeroBucket(d.enabled);
        zeroBucket(d.mode);
        zeroBucket(d.pos);
    } catch (_e) {}
}

function gigmaFinalizeLorebookStatsIndexBookStats(book) {
    try {
        if (!book || typeof book !== 'object') return null;
        const full = gigmaComputeLorebookStatsIndexFullStats(book);
        if (!full || typeof full !== 'object') return null;
        book.stats = full;
        return full;
    } catch (_e) {
        return null;
    }
}

function gigmaUpdateLorebookStatsIndexBookDominance(book) {
    try {
        if (!book || typeof book !== 'object') return;
        if (!book.stats || typeof book.stats !== 'object') book.stats = gigmaCreateEmptyLorebookStatsObject();
        const stats = book.stats;
        const d = gigmaEnsureLorebookStatsIndexBookDominance(book);

        const pickMax = (keys, currentKey) => {
            let best = keys.includes(currentKey) ? currentKey : keys[0];
            let bestV = Number(stats[best]?.tokens) || 0;
            for (const k of keys) {
                const v = Number(stats[k]?.tokens) || 0;
                if (v > bestV) {
                    best = k;
                    bestV = v;
                }
            }
            return best;
        };

        d.enabled = pickMax(['enabled', 'disabled'], d.enabled);
        d.mode = pickMax(GIGMA_LOREBOOK_STATS_MODE_KEYS, d.mode);
        d.pos = pickMax(GIGMA_LOREBOOK_STATS_POS_KEYS, d.pos);
    } catch (_e) {}
}


function gigmaCreateLorebookStatsIndexBook(lorebookId, worldName) {
    return {
        id: String(lorebookId || ''),
        worldName: String(worldName || ''),
        updatedAt: Date.now(),
        entriesByUid: {},
        stats: gigmaCreateEmptyLorebookStatsObject(),
        dominance: { enabled: 'enabled', mode: 'normal', pos: 'charUp' },
    };
}


function gigmaRebuildLorebookStatsIndexBook(lorebookId, worldName, entriesObj) {
    const book = gigmaCreateLorebookStatsIndexBook(lorebookId, worldName);
    const values = (entriesObj && typeof entriesObj === 'object') ? Object.values(entriesObj) : [];
    const nlInfo = gigmaComputeLorebookLeadingNewlineInfo(entriesObj);
    book.enabledNonEmptyCount = nlInfo.count;
    book.minEnabledUid = nlInfo.minUid;

    for (const raw of values) {
        if (!raw || typeof raw !== 'object') continue;
        const uid = String(raw.uid ?? '');
        const content = (typeof raw.content === 'string') ? raw.content : '';
        const enabledNonEmpty = raw.disable !== true && !!content;
        const leadingNewline = (nlInfo.count > 1) && enabledNonEmpty && uid && (uid !== nlInfo.minUid);
        const rec = gigmaBuildLorebookEntryStatsIndexRecord(raw, leadingNewline);
        if (!rec) continue;
        book.entriesByUid[uid] = rec;
        gigmaApplyLorebookEntryStatsIndexRecordToBook(book, rec, +1);
    }
    gigmaFinalizeLorebookStatsIndexBookStats(book);
    gigmaUpdateLorebookStatsIndexBookDominance(book);
    book.updatedAt = Date.now();
    return book;
}


