function gigmaInstallLorebookStatsIndexLifecycleHooksOnce() {
    try {
        if (window.__gigmaLorebookStatsIndexLifecycleHooksInstalled) return;
        if (!eventSource || !event_types) return;
        window.__gigmaLorebookStatsIndexLifecycleHooksInstalled = true;

        const onWorldInfoUpdated = (name, data) => {
            try {
                if (!name) return;
                const w = String(name || '');
                if (!w) return;
                try {
                    if (!window.__gigmaLorebookStatsDirtyByWorld || typeof window.__gigmaLorebookStatsDirtyByWorld !== 'object') window.__gigmaLorebookStatsDirtyByWorld = {};
                    delete window.__gigmaLorebookStatsDirtyByWorld[w];
                } catch (_e2) {}

                gigmaEnsureLorebookStatsIndexForWorld(w, { worldData: data }).catch((_e3) => {});
            } catch (_e) {}
        };

        if (event_types.WORLDINFO_UPDATED) {
            eventSource.on(event_types.WORLDINFO_UPDATED, onWorldInfoUpdated);
            if (Array.isArray(eventListeners)) eventListeners.push({ source: eventSource, event: event_types.WORLDINFO_UPDATED, handler: onWorldInfoUpdated });
        }

    } catch (e) {
        console.warn('[GIGMA] Failed to install lorebook stats index lifecycle hooks:', e);
    }
}

function gigmaInstallWorldInfoLorebookStatsIndexHooksOnce() {
    try {
        if (window.__gigmaWorldInfoLorebookStatsIndexHooksInstalled) return;
        window.__gigmaWorldInfoLorebookStatsIndexHooksInstalled = true;

        const fireEntryUpdate = (entryEl, contentOverride, deferred) => {
            try {
                const uid = String(entryEl?.getAttribute?.('uid') || '');
                const worldName = (typeof getCurrentLorebookName === 'function') ? getCurrentLorebookName() : null;
                if (!uid || !worldName) return;
                const opts = (contentOverride !== undefined) ? { contentOverride } : {};
                try {
                    if (!window.__gigmaLorebookStatsDirtyByWorld || typeof window.__gigmaLorebookStatsDirtyByWorld !== 'object') window.__gigmaLorebookStatsDirtyByWorld = {};
                    if (!window.__gigmaLorebookStatsDirtyByWorld[worldName]) window.__gigmaLorebookStatsDirtyByWorld[worldName] = new Set();
                    window.__gigmaLorebookStatsDirtyByWorld[worldName].add(uid);
                } catch (_eMarkDirty) {}
                if (deferred) {
                    setTimeout(() => {
                        gigmaUpdateLorebookStatsIndexEntry(worldName, uid, opts).catch((_e) => {});
                    }, 0);
                } else {
                    gigmaUpdateLorebookStatsIndexEntry(worldName, uid, opts).catch((_e) => {});
                }
            } catch (_e) {}
        };

        const handler = (ev) => {
            try {
                const target = ev?.target;
                if (!(target instanceof HTMLElement)) return;
                if (!target.closest || !target.closest('#world_popup_entries_list')) return;
                const entryEl = target.closest('.world_entry[uid]');
                if (!entryEl) return;

                if (ev.type === 'click') {
                    if (target.closest && target.closest('div[name="entryKillSwitch"]')) {
                        fireEntryUpdate(entryEl, undefined, true);
                    }
                    return;
                }

                if (target instanceof HTMLTextAreaElement && target.name === 'content') {
                    const uid = String(entryEl.getAttribute('uid') || '');
                    const worldName = (typeof getCurrentLorebookName === 'function') ? getCurrentLorebookName() : null;
                    if (!uid || !worldName) return;
                    if (!window.__gigmaLorebookEntryInputTimers) window.__gigmaLorebookEntryInputTimers = {};
                    const timers = window.__gigmaLorebookEntryInputTimers;
                    const key = `${worldName}:${uid}`;
                    if (timers[key]) clearTimeout(timers[key]);
                    const content = target.value;
                    const delay = gigmaIsMobileLargeLorebookPerfMode() ? 900 : 70;
                    timers[key] = setTimeout(() => {
                        delete timers[key];
                        gigmaUpdateLorebookStatsIndexEntry(worldName, uid, { contentOverride: content }).catch((_e) => {});
                    }, delay);
                    return;
                }

                if (ev.type === 'change') {
                    fireEntryUpdate(entryEl, undefined, true);
                    return;
                }

                if (target instanceof HTMLInputElement || target instanceof HTMLSelectElement) {
                    fireEntryUpdate(entryEl, undefined, true);
                }
            } catch (_e) {}
        };

        document.addEventListener('input', handler, true);
        document.addEventListener('change', handler, true);
        document.addEventListener('click', handler);
    } catch (e) {
        console.warn('[GIGMA] Failed to install WI stats index DOM hooks:', e);
    }
}
