const GIGMA_MODAL_LOREBOOK_STATS_CACHE = new Map();

const GIGMA_MODAL_LOREBOOK_STATS_LS_PREFIX = 'gigma_modal_lorebook_stats';

function gigmaPurgeStaleModalLorebookStatsFromLocalStorage() {
    try {
        const prefix = `${GIGMA_MODAL_LOREBOOK_STATS_LS_PREFIX}:`;
        for (let i = localStorage.length - 1; i >= 0; i--) {
            const k = localStorage.key(i);
            if (k && k.startsWith(prefix)) localStorage.removeItem(k);
        }
    } catch (_e) {}
}

