        const mode = gigmaNormalizeBudgetHeaderMode(data[0] || 'default');
        const rawValue = (mode === 'default' || mode === 'off') ? 0 : gigmaParseBudgetValueForMode(mode, data[1] == null ? 0 : data[1]);
        const value = Number.isFinite(rawValue) ? rawValue : 0;
