// === GIGMA: Global WI statistics (config + rendering) =========================

function gigmaGetEmPx(el){
    try{ return parseFloat(getComputedStyle(el).fontSize) || 16; }catch(_e){ return 16; }
}

function gigmaResetWorldInfoFloatingDropdownPlacement(panelEl){
    try{
        if (!panelEl) return;
        panelEl.style.position = '';
        panelEl.style.left = '';
        panelEl.style.right = '';
        panelEl.style.top = '';
        panelEl.style.bottom = '';
        panelEl.style.maxHeight = '';
        panelEl.style.overflowY = '';
        panelEl.style.overflowX = '';
        panelEl.style.zIndex = '';
    }catch(_e){}
}

function gigmaApplyWorldInfoFloatingDropdownPlacement(panelEl, anchorEl){
    try{
        if (!panelEl || !anchorEl) return;

        const rect = anchorEl.getBoundingClientRect ? anchorEl.getBoundingClientRect() : null;
        if (!rect) return;

        const em = gigmaGetEmPx(anchorEl);
        const gapPx = em * 0.25;
        const safetyPx = em * 0.6;
        const viewportW = Math.max(document.documentElement?.clientWidth || 0, window?.innerWidth || 0);
        const viewportH = Math.max(document.documentElement?.clientHeight || 0, window?.innerHeight || 0);

        let preferredSide = '';
        try{ preferredSide = String(panelEl.dataset.gigmaPreferredHSide || ''); }catch(_ePref){}
        if (preferredSide !== 'left' && preferredSide !== 'right') {
            try{
                const cs = getComputedStyle(panelEl);
                const left = String(cs && cs.left != null ? cs.left : '').trim();
                const right = String(cs && cs.right != null ? cs.right : '').trim();
                preferredSide = (left && left !== 'auto' && (!right || right === 'auto')) ? 'left' : 'right';
            }catch(_eSide){
                preferredSide = 'right';
            }
            try{ panelEl.dataset.gigmaPreferredHSide = preferredSide; }catch(_ePrefSet){}
        }

        panelEl.style.position = 'fixed';
        panelEl.style.bottom = 'auto';
        panelEl.style.zIndex = '10002';
        panelEl.style.overflowY = 'auto';
        panelEl.style.overflowX = 'hidden';

        const top = Math.max(safetyPx, rect.bottom + gapPx);
        panelEl.style.top = Math.round(top) + 'px';

        const panelWidth = Math.max(
            panelEl.getBoundingClientRect ? (panelEl.getBoundingClientRect().width || 0) : 0,
            panelEl.scrollWidth || 0,
            parseFloat(getComputedStyle(panelEl).minWidth) || 0
        );

        let left = (preferredSide === 'left') ? rect.left : (rect.right - panelWidth);
        const minLeft = safetyPx;
        const maxLeft = Math.max(minLeft, viewportW - panelWidth - safetyPx);
        left = Math.min(Math.max(left, minLeft), maxLeft);

        panelEl.style.left = Math.round(left) + 'px';
        panelEl.style.right = 'auto';

        let maxH = viewportH - top - safetyPx;
        if (!Number.isFinite(maxH)) maxH = 0;
        panelEl.style.maxHeight = Math.floor(Math.max(0, maxH)) + 'px';
    }catch(_e){}
}

function gigmaUpdateWorldInfoStatsFloatingDropdowns(){
    try{
        const globalPanel = document.getElementById(SELECTORS.WORLD_INFO_GLOBAL_WI_STATS_PANEL);
        const globalBtn = document.getElementById(SELECTORS.WORLD_INFO_GLOBAL_WI_STATS_BUTTON);
        if (globalPanel) {
            if (EXTENSION_STATE.globalWiStatsWiPanelOpen && globalBtn) gigmaApplyWorldInfoFloatingDropdownPlacement(globalPanel, globalBtn);
            else gigmaResetWorldInfoFloatingDropdownPlacement(globalPanel);
        }

        const lorePanel = document.getElementById(SELECTORS.WORLD_INFO_LOREBOOK_STATS_PANEL);
        const loreBtn = document.getElementById(SELECTORS.WORLD_INFO_LOREBOOK_STATS_BUTTON);
        if (lorePanel) {
            if (EXTENSION_STATE.worldInfoLorebookStatsPanelOpen && loreBtn) gigmaApplyWorldInfoFloatingDropdownPlacement(lorePanel, loreBtn);
            else gigmaResetWorldInfoFloatingDropdownPlacement(lorePanel);
        }
    }catch(_e){}
}

function gigmaApplyDropdownHorizontalFallback(panelEl, anchorEl, clipEl){
    try{
        if (!panelEl || !anchorEl) return;

        let preferredSide = '';
        try{ preferredSide = String(panelEl.dataset.gigmaPreferredHSide || ''); }catch(_ePref){}
        if (preferredSide !== 'left' && preferredSide !== 'right') {
            try{
                const cs = getComputedStyle(panelEl);
                const left = String(cs && cs.left != null ? cs.left : '').trim();
                const right = String(cs && cs.right != null ? cs.right : '').trim();
                preferredSide = (left && left !== 'auto' && (!right || right === 'auto')) ? 'left' : 'right';
            }catch(_eSide){
                preferredSide = 'right';
            }
            try{ panelEl.dataset.gigmaPreferredHSide = preferredSide; }catch(_ePrefSet){}
        }

        const hostEl = panelEl.parentElement || anchorEl;
        const hostRect = (hostEl && hostEl.getBoundingClientRect) ? hostEl.getBoundingClientRect() : null;
        const clipRect = (clipEl && clipEl.getBoundingClientRect)
            ? clipEl.getBoundingClientRect()
            : { left: 0, right: (window && window.innerWidth) ? window.innerWidth : 0 };

        const panelWidth = Math.max(
            panelEl.getBoundingClientRect ? (panelEl.getBoundingClientRect().width || 0) : 0,
            panelEl.scrollWidth || 0,
            parseFloat(getComputedStyle(panelEl).minWidth) || 0
        );

        let openSide = preferredSide;
        if (hostRect && panelWidth > 0) {
            const preferredSpace = (preferredSide === 'left')
                ? (clipRect.right - hostRect.left)
                : (hostRect.right - clipRect.left);
            const fallbackSpace = (preferredSide === 'left')
                ? (hostRect.right - clipRect.left)
                : (clipRect.right - hostRect.left);
            if (panelWidth > preferredSpace && fallbackSpace > preferredSpace) {
                openSide = (preferredSide === 'left') ? 'right' : 'left';
            }
        }

        if (openSide === 'left') {
            panelEl.style.right = 'auto';
            panelEl.style.left = '0';
        } else {
            panelEl.style.left = 'auto';
            panelEl.style.right = '0';
        }
        try{ panelEl.dataset.gigmaOpenHSide = openSide; }catch(_eOpenSide){}
    }catch(_e){}
}

// Placement helper for the Global WI stats dropdown.
// - modal: open UP if there is at least 60em space above the button; otherwise open DOWN.
// - preview: always open UP.
function gigmaApplyGlobalWiStatsDropdownPlacement(panelEl, btnEl, place){
    try{
        if (!panelEl || !btnEl) return;
        if (place === 'wi') {
            gigmaApplyWorldInfoFloatingDropdownPlacement(panelEl, btnEl);
            return;
        }

        const rect = btnEl.getBoundingClientRect ? btnEl.getBoundingClientRect() : null;
        if (!rect) return;

        const wantBottomOnly = (place === 'preview');
        const em = gigmaGetEmPx(btnEl);

        // modal: open UP only if there is at least 30em space above; otherwise open DOWN.
        // preview: always open DOWN.
        let openUp = false;
        if (!wantBottomOnly){
            openUp = !!(rect.top >= (em * 30));
        }

        try{ panelEl.dataset.gigmaOpenDir = openUp ? 'up' : 'down'; }catch(_e2){}

        // Apply direction
        if (openUp){
            panelEl.style.top = 'auto';
            panelEl.style.bottom = 'calc(100% + 0.25em)';
        } else {
            panelEl.style.bottom = 'auto';
            panelEl.style.top = 'calc(100% + 0.25em)';
        }

        // Find the nearest clipping ancestor (overflow != visible) so the dropdown never gets cut off.
        let clipEl = null;

        // World Info UI: prefer the World Info popup as the clip boundary so the dropdown never gets sliced off
        // by the popup's bottom edge (it should shrink and become scrollable instead).
        if (place === 'wi') {
            try{ clipEl = document.getElementById('world_popup') || document.querySelector('#world_popup') || null; }catch(_eWiClip){}
        }

        if (!clipEl){
            try{
                let n = panelEl;
                while(n && n !== document.body && n !== document.documentElement){
                    n = n.parentElement;
                    if (!n) break;
                    const cs = getComputedStyle(n);
                    const ovy = cs ? cs.overflowY : '';
                    const ovx = cs ? cs.overflowX : '';
                    if ((ovy && ovy !== 'visible') || (ovx && ovx !== 'visible')){
                        clipEl = n;
                        break;
                    }
                }
            }catch(_eClip){}
        }

        if (!clipEl){
            try{ clipEl = btnEl.closest ? btnEl.closest('dialog') : null; }catch(_eDlg){}
        }
        if (!clipEl) clipEl = document.documentElement;
        gigmaApplyDropdownHorizontalFallback(panelEl, btnEl, clipEl);

        const clipRect = clipEl.getBoundingClientRect ? clipEl.getBoundingClientRect() : { top: 0, bottom: (window && window.innerHeight) ? window.innerHeight : 0 };

        // World Info UI: choose open direction based on the available space inside the popup
        // (so we don't end up visually cutting the dropdown off at the window edge).
        if (place === 'wi') {
            try{
                const abovePx = rect.top - clipRect.top;
                const belowPx = clipRect.bottom - rect.bottom;
                openUp = (belowPx < abovePx);

                try{ panelEl.dataset.gigmaOpenDir = openUp ? 'up' : 'down'; }catch(_e2){}

                if (openUp){
                    panelEl.style.top = 'auto';
                    panelEl.style.bottom = 'calc(100% + 0.25em)';
                } else {
                    panelEl.style.bottom = 'auto';
                    panelEl.style.top = 'calc(100% + 0.25em)';
                }
            }catch(_eWiDir){}
        }

        // Compute max-height so the panel fits within the clip area (and scrolls when needed).
        const gapPx = em * 0.25;         // font-relative visual gap
        const safetyPx = em * 0.6;       // font-relative breathing room from the edge
        const spaceAbove = rect.top - clipRect.top;
        let clipBottom = clipRect.bottom;
        if (place === 'preview') {
            try{
                const root = (btnEl && btnEl.closest) ? btnEl.closest('#gigma-layout-preset-tree-preview-root') : null;
                const chips = root ? root.querySelector('#gigma-global-wi-stats-display-preview') : null;
                if (chips && chips.getBoundingClientRect) {
                    const cr = chips.getBoundingClientRect();
                    if (cr && Number.isFinite(cr.top) && cr.height > 0) clipBottom = Math.min(clipBottom, cr.top);
                }
            }catch(_eChips){}
        }
        const spaceBelow = clipBottom - rect.bottom;

        let maxH = openUp ? (spaceAbove - gapPx - safetyPx) : (spaceBelow - gapPx - safetyPx);
        if (!Number.isFinite(maxH)) maxH = 0;
        maxH = Math.max(0, maxH);

        panelEl.style.maxHeight = Math.floor(maxH) + 'px';
        panelEl.style.overflowY = 'auto';
        panelEl.style.overflowX = 'hidden';
    }catch(_e){}
}

function gigmaNormalizeGlobalWiStatsOptionList(list){
    const enabled = new Set();
    for (const k of (Array.isArray(list) ? list : [])) {
        const kk = String(k || '').trim();
        if (!kk || !GIGMA_GLOBAL_WI_STATS_ALL_KEY_SET.has(kk)) continue;
        enabled.add(kk);
    }
    // Keep the same ordering users are used to: Cats first, then the extra count options.
    const out = [];
    for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
        if (enabled.has(c.key)) out.push(c.key);
    }
    for (const o of GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS) {
        if (enabled.has(o.key)) out.push(o.key);
    }
    for (const o of GIGMA_GLOBAL_WI_STATS_EXTRA_OPTIONS) {
        if (enabled.has(o.key)) out.push(o.key);
    }
    return out;
}

function gigmaSetGlobalWiStatsOptionList(place, list){
    try{
        const out = gigmaNormalizeGlobalWiStatsOptionList(list);
        if (place === 'preview') {
            EXTENSION_STATE.globalWiStatsPreviewOptionsList = out;
            EXTENSION_STATE.globalWiStatsPreviewOptionsSet = new Set(out);
            EXTENSION_STATE.globalWiStatsPreviewOptionsCsv = out.join(',');
        } else if (place === 'wi') {
            EXTENSION_STATE.globalWiStatsWiOptionsList = out;
            EXTENSION_STATE.globalWiStatsWiOptionsSet = new Set(out);
            EXTENSION_STATE.globalWiStatsWiOptionsCsv = out.join(',');
        } else {
            EXTENSION_STATE.globalWiStatsModalOptionsList = out;
            EXTENSION_STATE.globalWiStatsModalOptionsSet = new Set(out);
            EXTENSION_STATE.globalWiStatsModalOptionsCsv = out.join(',');
        }
    }catch(_e){}
}

function gigmaEnsureGlobalWiStatsContextDefaults(place){
    try{
        const isPreview = (place === 'preview');
        const isWi = (place === 'wi');
        const initKey = isPreview
            ? 'globalWiStatsPreviewContextOptionsInitialized'
            : (isWi ? 'globalWiStatsWiContextOptionsInitialized' : 'globalWiStatsModalContextOptionsInitialized');
        const fullKey = isPreview
            ? 'globalWiStatsPreviewFullContextOptionInitialized'
            : (isWi ? 'globalWiStatsWiFullContextOptionInitialized' : 'globalWiStatsModalFullContextOptionInitialized');

        const cached = isPreview
            ? EXTENSION_STATE.globalWiStatsPreviewOptionsList
            : (isWi ? EXTENSION_STATE.globalWiStatsWiOptionsList : EXTENSION_STATE.globalWiStatsModalOptionsList);
        const csv = isPreview
            ? (EXTENSION_STATE.globalWiStatsPreviewOptionsCsv || '')
            : (isWi ? (EXTENSION_STATE.globalWiStatsWiOptionsCsv || '') : (EXTENSION_STATE.globalWiStatsModalOptionsCsv || ''));

        let changed = false;
        const raw = Array.isArray(cached) ? cached.slice() : gigmaParseCsvToList(csv, GIGMA_GLOBAL_WI_STATS_DEFAULT_CSV);
        let filtered = raw.filter(k => GIGMA_GLOBAL_WI_STATS_ALL_KEY_SET.has(k));

        if (!EXTENSION_STATE[initKey]) {
            const hasContext = filtered.some(k => GIGMA_GLOBAL_WI_STATS_CONTEXT_KEY_SET.has(String(k || '').trim()));
            if (!hasContext) {
                filtered = filtered.concat(GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS.map(o => o.key));
                changed = true;
            } else if (!Array.isArray(cached)) {
                changed = true;
            }
            EXTENSION_STATE[initKey] = true;
        }

        if (!EXTENSION_STATE[fullKey]) {
            if (!filtered.includes('fullContext')) {
                filtered = filtered.concat(['fullContext']);
                changed = true;
            }
            EXTENSION_STATE[fullKey] = true;
        }

        if (changed) {
            gigmaSetGlobalWiStatsOptionList(place, filtered);
        }
        gigmaPersistGlobalWiStatsSettings(place);
    }catch(_e){}
}


function gigmaGetGlobalWiStatsOptionList(place){
    try{
        gigmaEnsureGlobalWiStatsContextDefaults(place);
        const isPreview = (place === 'preview');
        const isWi = (place === 'wi');
        const cached = isPreview
            ? EXTENSION_STATE.globalWiStatsPreviewOptionsList
            : (isWi ? EXTENSION_STATE.globalWiStatsWiOptionsList : EXTENSION_STATE.globalWiStatsModalOptionsList);
        if (Array.isArray(cached)) return cached;

        const csv = isPreview
            ? (EXTENSION_STATE.globalWiStatsPreviewOptionsCsv || '')
            : (isWi ? (EXTENSION_STATE.globalWiStatsWiOptionsCsv || '') : (EXTENSION_STATE.globalWiStatsModalOptionsCsv || ''));
        const raw = gigmaParseCsvToList(csv, GIGMA_GLOBAL_WI_STATS_DEFAULT_CSV);
        const filtered = raw.filter(k => GIGMA_GLOBAL_WI_STATS_ALL_KEY_SET.has(k));
        gigmaSetGlobalWiStatsOptionList(place, filtered);

        return isPreview
            ? (EXTENSION_STATE.globalWiStatsPreviewOptionsList || [])
            : (isWi ? (EXTENSION_STATE.globalWiStatsWiOptionsList || []) : (EXTENSION_STATE.globalWiStatsModalOptionsList || []));
    }catch(_e){
        const raw = gigmaParseCsvToList('', GIGMA_GLOBAL_WI_STATS_DEFAULT_CSV);
        gigmaSetGlobalWiStatsOptionList(place, raw);
        return (place === 'preview')
            ? (EXTENSION_STATE.globalWiStatsPreviewOptionsList || [])
            : ((place === 'wi') ? (EXTENSION_STATE.globalWiStatsWiOptionsList || []) : (EXTENSION_STATE.globalWiStatsModalOptionsList || []));
    }
}


function gigmaGetGlobalWiStatsOptionSet(place){
    try{
        const isPreview = (place === 'preview');
        const isWi = (place === 'wi');
        const cached = isPreview
            ? EXTENSION_STATE.globalWiStatsPreviewOptionsSet
            : (isWi ? EXTENSION_STATE.globalWiStatsWiOptionsSet : EXTENSION_STATE.globalWiStatsModalOptionsSet);
        if (cached instanceof Set) return cached;

        const set = new Set(gigmaGetGlobalWiStatsOptionList(place));
        if (isPreview) EXTENSION_STATE.globalWiStatsPreviewOptionsSet = set;
        else if (isWi) EXTENSION_STATE.globalWiStatsWiOptionsSet = set;
        else EXTENSION_STATE.globalWiStatsModalOptionsSet = set;
        return set;
    }catch(_e){
        return new Set();
    }
}


function gigmaPersistGlobalWiStatsSettings(place){
    try{
        if (!gigmaExtensionSettings || typeof gigmaExtensionSettings !== 'object') return;
        if (place === 'preview') {
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewEnabled', EXTENSION_STATE.globalWiStatsPreviewEnabled, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewShowEntries', EXTENSION_STATE.globalWiStatsPreviewShowEntries, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewShowTokens', EXTENSION_STATE.globalWiStatsPreviewShowTokens, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewSectionBudgetContext', EXTENSION_STATE.globalWiStatsPreviewSectionBudgetContext, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewSectionBooks', EXTENSION_STATE.globalWiStatsPreviewSectionBooks, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewSectionRaw', EXTENSION_STATE.globalWiStatsPreviewSectionRaw, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewSectionActivated', EXTENSION_STATE.globalWiStatsPreviewSectionActivated, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewSectionIncluded', EXTENSION_STATE.globalWiStatsPreviewSectionIncluded, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewRemoveIrrelevantCategories', EXTENSION_STATE.globalWiStatsPreviewRemoveIrrelevantCategories, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewRemoveZeroTokenCategories', EXTENSION_STATE.globalWiStatsPreviewRemoveZeroTokenCategories, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewCollapsed', EXTENSION_STATE.globalWiStatsPreviewCollapsed, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewShowCollapseButton', EXTENSION_STATE.globalWiStatsPreviewShowCollapseButton, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewContextOptionsInitialized', EXTENSION_STATE.globalWiStatsPreviewContextOptionsInitialized, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsPreviewFullContextOptionInitialized', EXTENSION_STATE.globalWiStatsPreviewFullContextOptionInitialized, 0);
            const csv = String(EXTENSION_STATE.globalWiStatsPreviewOptionsCsv || '');
            if (csv) gigmaExtensionSettings.globalWiStatsPreviewOptionsCsv = csv;
            else delete gigmaExtensionSettings.globalWiStatsPreviewOptionsCsv;
        } else if (place === 'wi') {
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiEnabled', EXTENSION_STATE.globalWiStatsWiEnabled, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiShowEntries', EXTENSION_STATE.globalWiStatsWiShowEntries, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiShowTokens', EXTENSION_STATE.globalWiStatsWiShowTokens, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiSectionBudgetContext', EXTENSION_STATE.globalWiStatsWiSectionBudgetContext, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiSectionBooks', EXTENSION_STATE.globalWiStatsWiSectionBooks, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiSectionRaw', EXTENSION_STATE.globalWiStatsWiSectionRaw, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiSectionActivated', EXTENSION_STATE.globalWiStatsWiSectionActivated, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiSectionIncluded', EXTENSION_STATE.globalWiStatsWiSectionIncluded, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiRemoveIrrelevantCategories', EXTENSION_STATE.globalWiStatsWiRemoveIrrelevantCategories, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiRemoveZeroTokenCategories', EXTENSION_STATE.globalWiStatsWiRemoveZeroTokenCategories, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiCollapsed', EXTENSION_STATE.globalWiStatsWiCollapsed, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiShowCollapseButton', EXTENSION_STATE.globalWiStatsWiShowCollapseButton, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiContextOptionsInitialized', EXTENSION_STATE.globalWiStatsWiContextOptionsInitialized, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsWiFullContextOptionInitialized', EXTENSION_STATE.globalWiStatsWiFullContextOptionInitialized, 0);
            const csv = String(EXTENSION_STATE.globalWiStatsWiOptionsCsv || '');
            if (csv) gigmaExtensionSettings.globalWiStatsWiOptionsCsv = csv;
            else delete gigmaExtensionSettings.globalWiStatsWiOptionsCsv;
        } else {
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalEnabled', EXTENSION_STATE.globalWiStatsModalEnabled, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalShowEntries', EXTENSION_STATE.globalWiStatsModalShowEntries, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalShowTokens', EXTENSION_STATE.globalWiStatsModalShowTokens, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalSectionBudgetContext', EXTENSION_STATE.globalWiStatsModalSectionBudgetContext, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalSectionBooks', EXTENSION_STATE.globalWiStatsModalSectionBooks, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalSectionRaw', EXTENSION_STATE.globalWiStatsModalSectionRaw, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalSectionActivated', EXTENSION_STATE.globalWiStatsModalSectionActivated, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalSectionIncluded', EXTENSION_STATE.globalWiStatsModalSectionIncluded, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalRemoveIrrelevantCategories', EXTENSION_STATE.globalWiStatsModalRemoveIrrelevantCategories, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalRemoveZeroTokenCategories', EXTENSION_STATE.globalWiStatsModalRemoveZeroTokenCategories, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalCollapsed', EXTENSION_STATE.globalWiStatsModalCollapsed, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalShowCollapseButton', EXTENSION_STATE.globalWiStatsModalShowCollapseButton, 1);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalContextOptionsInitialized', EXTENSION_STATE.globalWiStatsModalContextOptionsInitialized, 0);
            gigmaPersistBinaryExtensionSetting('globalWiStatsModalFullContextOptionInitialized', EXTENSION_STATE.globalWiStatsModalFullContextOptionInitialized, 0);
            const csv = String(EXTENSION_STATE.globalWiStatsModalOptionsCsv || '');
            if (csv) gigmaExtensionSettings.globalWiStatsModalOptionsCsv = csv;
            else delete gigmaExtensionSettings.globalWiStatsModalOptionsCsv;
        }
        if (typeof saveSettingsDebounced === 'function') saveSettingsDebounced();
    }catch(_e){}
}


function gigmaGetGlobalWiStatsDisplayCollapsed(place){
    try{
        if (place === 'preview') return !!EXTENSION_STATE.globalWiStatsPreviewCollapsed;
        if (place === 'wi') return !!EXTENSION_STATE.globalWiStatsWiCollapsed;
        return !!EXTENSION_STATE.globalWiStatsModalCollapsed;
    }catch(_e){
        return false;
    }
}

function gigmaSetGlobalWiStatsDisplayCollapsed(place, collapsed){
    try{
        const next = !!collapsed;
        if (place === 'preview') EXTENSION_STATE.globalWiStatsPreviewCollapsed = next;
        else if (place === 'wi') EXTENSION_STATE.globalWiStatsWiCollapsed = next;
        else EXTENSION_STATE.globalWiStatsModalCollapsed = next;
        gigmaPersistGlobalWiStatsSettings(place);
    }catch(_e){}
}

function gigmaIsWorldInfoStatsSectionCollapsed(sectionKey){
    try{
        return sectionKey === 'global'
            ? !!EXTENSION_STATE.globalWiStatsWiCollapsed
            : !!EXTENSION_STATE.worldInfoLorebookStatsCollapsed;
    }catch(_e){
        return false;
    }
}

function gigmaSetWorldInfoStatsSectionCollapsed(sectionKey, collapsed){
    try{
        const next = !!collapsed;
        if (sectionKey === 'global') {
            EXTENSION_STATE.globalWiStatsWiCollapsed = next;
            gigmaPersistGlobalWiStatsSettings('wi');
        } else {
            EXTENSION_STATE.worldInfoLorebookStatsCollapsed = next;
            gigmaPersistBinaryExtensionSetting('worldInfoLorebookStatsCollapsed', EXTENSION_STATE.worldInfoLorebookStatsCollapsed, 0);
            if (typeof saveSettingsDebounced === 'function') saveSettingsDebounced();
        }
    }catch(_e){}
}

function gigmaGetLorebookStatsDisplayCollapsed(place){
    try{
        if (place === 'preview') {
            const state = gigmaGetLayoutPresetTreePreviewLorebookStatsState();
            return !!(state && state.collapsed);
        }
        return !!EXTENSION_STATE.modalLorebookStatsCollapsed;
    }catch(_e){
        return false;
    }
}

function gigmaSetLorebookStatsDisplayCollapsed(place, collapsed){
    try{
        const next = !!collapsed;
        if (place === 'preview') {
            const state = gigmaGetLayoutPresetTreePreviewLorebookStatsState();
            if (state && typeof state === 'object') state.collapsed = next;
            gigmaPersistLayoutPresetTreePreviewLorebookStatsState();
        } else {
            EXTENSION_STATE.modalLorebookStatsCollapsed = next;
            gigmaPersistModalLorebookStatsSettings();
        }
    }catch(_e){}
}

function gigmaGetStatsCollapseButtonVisible(place, kind){
    try{
        if (kind === 'global') {
            if (place === 'preview') return !!EXTENSION_STATE.globalWiStatsPreviewShowCollapseButton;
            if (place === 'wi') return !!EXTENSION_STATE.globalWiStatsWiShowCollapseButton;
            return !!EXTENSION_STATE.globalWiStatsModalShowCollapseButton;
        }
        if (place === 'preview') {
            const state = gigmaGetLayoutPresetTreePreviewLorebookStatsState();
            return !!(state && state.showCollapseButton !== false);
        }
        if (place === 'wi') return !!EXTENSION_STATE.worldInfoLorebookStatsShowCollapseButton;
        return !!EXTENSION_STATE.modalLorebookStatsShowCollapseButton;
    }catch(_e){
        return true;
    }
}

function gigmaSetStatsCollapseButtonVisible(place, kind, visible){
    try{
        const next = !!visible;
        if (kind === 'global') {
            if (place === 'preview') EXTENSION_STATE.globalWiStatsPreviewShowCollapseButton = next;
            else if (place === 'wi') EXTENSION_STATE.globalWiStatsWiShowCollapseButton = next;
            else EXTENSION_STATE.globalWiStatsModalShowCollapseButton = next;
            gigmaPersistGlobalWiStatsSettings(place);
            return;
        }
        if (place === 'preview') {
            const state = gigmaGetLayoutPresetTreePreviewLorebookStatsState();
            if (state && typeof state === 'object') state.showCollapseButton = next;
            gigmaPersistLayoutPresetTreePreviewLorebookStatsState();
            return;
        }
        if (place === 'wi') {
            EXTENSION_STATE.worldInfoLorebookStatsShowCollapseButton = next;
            gigmaPersistBinaryExtensionSetting('worldInfoLorebookStatsShowCollapseButton', EXTENSION_STATE.worldInfoLorebookStatsShowCollapseButton, 1);
            if (typeof saveSettingsDebounced === 'function') saveSettingsDebounced();
            return;
        }
        EXTENSION_STATE.modalLorebookStatsShowCollapseButton = next;
        gigmaPersistModalLorebookStatsSettings();
    }catch(_e){}
}

function gigmaApplyStatsPrimaryButtonUi(btn, enabled){
    try{
        if (!btn) return;
        btn.setAttribute('data-gigma-stats-enabled', enabled ? 'true' : 'false');
    }catch(_e){}
}

function gigmaSyncStatsButtonPairUi(btn, collapseBtn, enabled, expanded, label, showCollapseButton){
    try{
        const safeEnabled = !!enabled;
        const safeShowCollapseButton = !!showCollapseButton;
        gigmaApplyStatsPrimaryButtonUi(btn, safeEnabled);
        gigmaUpdateStatsCollapseButtonUi(collapseBtn, expanded, label, { visible: safeEnabled && safeShowCollapseButton });
    }catch(_e){}
}

function gigmaUpdateStatsCollapseButtonUi(btn, expanded, label, options){
    try{
        if (!btn) return;
        const safeVisible = !(options && options.visible === false);
        btn.hidden = !safeVisible;
        btn.classList.toggle('gigma-hidden', !safeVisible);
        if (safeVisible) btn.style.removeProperty('display');
        else btn.style.setProperty('display', 'none', 'important');
        btn.setAttribute('aria-hidden', safeVisible ? 'false' : 'true');
        if (!safeVisible) return;
        const safeExpanded = !!expanded;
        const safeLabel = String(label || 'Stats').replace(/:\s*$/, '');
        const stateLabel = safeLabel + ': ' + (safeExpanded ? 'Expanded' : 'Collapsed');
        btn.type = 'button';
        btn.className = 'menu_button gigma-icon-btn gigma-stats-collapse-btn';
        btn.title = stateLabel;
        btn.setAttribute('aria-label', stateLabel);
        btn.setAttribute('aria-expanded', safeExpanded ? 'true' : 'false');
        btn.setAttribute('data-gigma-state', safeExpanded ? 'expanded' : 'collapsed');
        btn.replaceChildren();
        const icon = document.createElement('i');
        icon.className = 'fa-solid ' + (safeExpanded ? 'fa-chevron-down' : 'fa-chevron-up');
        icon.setAttribute('aria-hidden', 'true');
        btn.appendChild(icon);
    }catch(_e){}
}

function gigmaCreateStatsCollapseButton(expanded, label){
    const btn = document.createElement('button');
    gigmaUpdateStatsCollapseButtonUi(btn, expanded, label);
    return btn;
}

function gigmaCreateStatsPanelSwitchRow(labelText, inputAttrName, inputAttrValue, titleText, ariaLabel){
    const row = document.createElement('div');
    row.className = 'gigma-gwi-panel-switchline';
    const label = document.createElement('div');
    label.className = 'gigma-gwi-panel-switchline-label';
    label.textContent = String(labelText || '');
    const switchLabel = document.createElement('label');
    switchLabel.className = 'gigma-gwi-pretty-switch';
    if (titleText) switchLabel.title = String(titleText);
    const sw = document.createElement('input');
    sw.type = 'checkbox';
    if (inputAttrName) sw.setAttribute(String(inputAttrName), String(inputAttrValue || '1'));
    if (ariaLabel) sw.setAttribute('aria-label', String(ariaLabel));
    const track = document.createElement('span');
    track.className = 'gigma-gwi-pretty-switch-track';
    const thumb = document.createElement('span');
    thumb.className = 'gigma-gwi-pretty-switch-thumb';
    track.appendChild(thumb);
    switchLabel.appendChild(sw);
    switchLabel.appendChild(track);
    row.appendChild(label);
    row.appendChild(switchLabel);
    return { row, input: sw };
}

function gigmaCreatePrettySwitch(initialChecked, titleText, ariaLabel, changeHandler){
    const switchLabel = document.createElement('label');
    switchLabel.className = 'gigma-gwi-pretty-switch';
    if (titleText) switchLabel.title = String(titleText);
    const sw = document.createElement('input');
    sw.type = 'checkbox';
    sw.checked = !!initialChecked;
    if (ariaLabel) sw.setAttribute('aria-label', String(ariaLabel));
    const track = document.createElement('span');
    track.className = 'gigma-gwi-pretty-switch-track';
    const thumb = document.createElement('span');
    thumb.className = 'gigma-gwi-pretty-switch-thumb';
    track.appendChild(thumb);
    switchLabel.appendChild(sw);
    switchLabel.appendChild(track);
    if (typeof changeHandler === 'function') {
        sw.addEventListener('change', changeHandler);
    }
    return { switchLabel, input: sw };
}

function gigmaSetPrettySwitchDisabled(input, disabled){
    try{
        if (!input) return;
        const off = !!disabled;
        input.disabled = off;
        input.setAttribute('aria-disabled', off ? 'true' : 'false');
        const switchLabel = input.closest ? input.closest('.gigma-gwi-pretty-switch') : null;
        if (switchLabel && switchLabel.classList) {
            switchLabel.classList.toggle('gigma-disabled-switch', off);
        }
    }catch(_){ }
}

function gigmaSyncNativeWiMobileFullscreenStatsLayer(){
    const active = document.documentElement.classList.contains(GIGMA_MOBILE_FULLSCREEN_CLASS)
        && !!(EXTENSION_STATE.globalWiStatsWiPanelOpen || EXTENSION_STATE.worldInfoLorebookStatsPanelOpen);
    document.body.classList.toggle('gigma-native-wi-mobile-fullscreen-stats-open', active);
}

function gigmaCloseMobileFullscreenDropdown(panelEl){
    try{
        if (!panelEl) return;
        const id = String(panelEl.id || '');
        if (id === 'gigma-modal-settings-popup') {
            panelEl.style.display = 'none';
            return;
        }
        if (id === SELECTORS.WORLD_INFO_GLOBAL_WI_STATS_PANEL) {
            EXTENSION_STATE.globalWiStatsWiPanelOpen = false;
            gigmaUpdateGlobalWiStatsControlsUi('wi');
            return;
        }
        if (id === SELECTORS.WORLD_INFO_LOREBOOK_STATS_PANEL) {
            EXTENSION_STATE.worldInfoLorebookStatsPanelOpen = false;
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            return;
        }
        if (id === 'gigma-layout-preset-tree-global-wi-stats-panel') {
            EXTENSION_STATE.globalWiStatsPreviewPanelOpen = false;
            gigmaUpdateGlobalWiStatsControlsUi('preview');
            return;
        }
        if (id === 'gigma-layout-preset-tree-stats-panel') {
            const root = panelEl.closest ? panelEl.closest('#gigma-layout-preset-tree-preview-root') : null;
            const state = gigmaGetLayoutPresetTreePreviewLorebookStatsState();
            state.panelOpen = false;
            gigmaUpdateLayoutPresetTreePreviewLorebookStatsControlsUi(root);
            return;
        }
        if (id.indexOf('gigma-modal-global-wi-stats-panel') === 0) {
            EXTENSION_STATE.globalWiStatsModalPanelOpen = false;
            EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen = '';
            gigmaUpdateGlobalWiStatsControlsUi('modal');
            return;
        }
        if (id.indexOf('gigma-modal-stats-panel') === 0) {
            const suffix = id.endsWith('-right') ? '-right' : '';
            panelEl.classList.add('gigma-hidden');
            panelEl.setAttribute('aria-hidden', 'true');
            const btn = document.getElementById('gigma-modal-stats-cats' + suffix);
            if (btn) btn.setAttribute('aria-expanded', 'false');
        }
    }catch(_){ }
}

function gigmaEnsureMobileFullscreenDropdownShell(panelEl, closeLabel){
    try{
        if (!panelEl) return;
        panelEl.classList.add('gigma-mobile-fullscreen-panel');
        if (panelEl.querySelector(':scope > .gigma-mobile-fullscreen-close')) return;
        const closeBtn = document.createElement('button');
        closeBtn.type = 'button';
        closeBtn.className = 'menu_button gigma-global-cancel gigma-global-icon gigma-mobile-fullscreen-close';
        closeBtn.setAttribute('aria-label', closeLabel || 'Close popup');
        closeBtn.title = closeLabel || 'Close popup';
        closeBtn.innerHTML = '<svg viewBox="0 0 24 24" aria-hidden="true" focusable="false" class="gigma-global-icon-svg"><path d="M6 6L18 18M18 6L6 18" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" fill="none"/></svg>';
        closeBtn.addEventListener('click', (ev) => {
            try{ ev.preventDefault(); ev.stopPropagation(); }catch(_e){ }
            gigmaCloseMobileFullscreenDropdown(panelEl);
        });
        panelEl.insertBefore(closeBtn, panelEl.firstChild);
    }catch(_){ }
}

function gigmaBuildGlobalWiStatsPanel(panel, place){
    try{
        if (!panel) return;
        if (panel.getAttribute('data-gigma-built') === '1') return;
        panel.setAttribute('data-gigma-built', '1');
        panel.classList.add('gigma-global-wi-stats-panel');
        gigmaEnsureMobileFullscreenDropdownShell(panel, 'Close Global WI statistics');

        const headRow = document.createElement('div');
        headRow.className = 'gigma-gwi-panel-headrow';

        const title = document.createElement('div');
        title.className = 'gigma-global-wi-stats-panel-title';
        title.textContent = 'Global WI statistics';

        const switchLabel = document.createElement('label');
        switchLabel.className = 'gigma-gwi-pretty-switch';
        switchLabel.title = 'Toggle Global WI statistics display';

        const sw = document.createElement('input');
        sw.type = 'checkbox';
        sw.setAttribute('data-gigma-gwi-switch', '1');
        sw.setAttribute('aria-label', 'Toggle Global WI statistics display');

        const track = document.createElement('span');
        track.className = 'gigma-gwi-pretty-switch-track';
        const thumb = document.createElement('span');
        thumb.className = 'gigma-gwi-pretty-switch-thumb';
        track.appendChild(thumb);

        switchLabel.appendChild(sw);
        switchLabel.appendChild(track);

        headRow.appendChild(title);
        headRow.appendChild(switchLabel);
        panel.appendChild(headRow);

        const collapseSwitchRow = gigmaCreateStatsPanelSwitchRow('Show Expand/Collapse button', 'data-gigma-gwi-collapse-switch', '1', 'Show Expand/Collapse button', 'Show Expand/Collapse button');
        panel.appendChild(collapseSwitchRow.row);

        const removeIrrelevantSwitchRow = gigmaCreateStatsPanelSwitchRow('Remove irrelevant categories', 'data-gigma-gwi-remove-irrelevant-switch', '1', 'Remove irrelevant categories', 'Remove irrelevant categories');
        panel.appendChild(removeIrrelevantSwitchRow.row);

        const removeZeroTokensSwitchRow = gigmaCreateStatsPanelSwitchRow('Remove 0 tokens categories', 'data-gigma-gwi-remove-zero-tokens-switch', '1', 'Remove 0 tokens categories', 'Remove 0 tokens categories');
        panel.appendChild(removeZeroTokensSwitchRow.row);

        const countRow = document.createElement('div');
        countRow.className = 'gigma-modal-stats-panel-actions gigma-gwi-count-row';
        countRow.appendChild((() => { const b = document.createElement('button'); b.type = 'button'; b.className = 'menu_button'; b.textContent = 'Entries'; b.title = 'Toggle entry counts'; b.setAttribute('data-gigma-gwi-count', 'entries'); return b; })());
        countRow.appendChild((() => { const b = document.createElement('button'); b.type = 'button'; b.className = 'menu_button'; b.textContent = 'Tokens'; b.title = 'Toggle token counts'; b.setAttribute('data-gigma-gwi-count', 'tokens'); return b; })());
        panel.appendChild(countRow);

        // Budget & Context / Lorebooks & Folders section toggles
        const lfRow = document.createElement('div');
        lfRow.className = 'gigma-modal-stats-panel-actions gigma-gwi-books-row';
        lfRow.appendChild((() => {
            const b = document.createElement('button');
            b.type = 'button';
            b.className = 'menu_button';
            b.textContent = 'Budget & Context';
            b.title = 'Toggle Budget & Context section';
            b.setAttribute('data-gigma-gwi-section', 'context');
            return b;
        })());
        lfRow.appendChild((() => {
            const b = document.createElement('button');
            b.type = 'button';
            b.className = 'menu_button';
            b.textContent = 'Lorebooks & Folders';
            b.title = 'Toggle Lorebooks & Folders section';
            b.setAttribute('data-gigma-gwi-section', 'books');
            return b;
        })());
        panel.appendChild(lfRow);

        // Section toggles (Raw/Activated/Included)
        const sectionToggles = document.createElement('div');
        sectionToggles.className = 'gigma-modal-stats-panel-actions';
        sectionToggles.appendChild((() => { const b = document.createElement('button'); b.type='button'; b.className='menu_button'; b.textContent='Raw'; b.title='Toggle Raw section'; b.setAttribute('data-gigma-gwi-section','raw'); return b; })());
        sectionToggles.appendChild((() => { const b = document.createElement('button'); b.type='button'; b.className='menu_button'; b.textContent='Activated'; b.title='Toggle Activated section'; b.setAttribute('data-gigma-gwi-section','activated'); return b; })());
        sectionToggles.appendChild((() => { const b = document.createElement('button'); b.type='button'; b.className='menu_button'; b.textContent='Included'; b.title='Toggle Included section'; b.setAttribute('data-gigma-gwi-section','included'); return b; })());
        panel.appendChild(sectionToggles);

        // All/None
        const actions = document.createElement('div');
        actions.className = 'gigma-modal-stats-panel-actions';
        const btnAll = document.createElement('button');
        btnAll.type = 'button';
        btnAll.className = 'menu_button';
        btnAll.textContent = 'All';
        btnAll.title = 'Show all statistics';
        btnAll.setAttribute('data-gigma-gwi-action', 'all');
        const btnNone = document.createElement('button');
        btnNone.type = 'button';
        btnNone.className = 'menu_button';
        btnNone.textContent = 'None';
        btnNone.title = 'Hide all statistics';
        btnNone.setAttribute('data-gigma-gwi-action', 'none');
        actions.appendChild(btnAll);
        actions.appendChild(btnNone);
        panel.appendChild(actions);

        const list = document.createElement('div');
        list.className = 'gigma-modal-stats-panel-list';

        // Cats options (same as the existing Cats dropdown)
        for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
            const row = document.createElement('label');
            row.className = 'gigma-modal-stats-panel-item';
            const cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.setAttribute('data-gigma-gwi', c.key);
            const txt = document.createElement('span');
            txt.innerHTML = (place === 'wi') ? (GIGMA_NATIVE_WI_FULL_STATS_LABEL_BY_KEY.get(c.key) || c.key) : (c.menuHtml || c.key);
            row.appendChild(cb);
            row.appendChild(txt);
            list.appendChild(row);
        }

        const contextHr = document.createElement('div');
        contextHr.className = 'gigma-global-wi-stats-divider';
        contextHr.textContent = 'Budget & Context';
        list.appendChild(contextHr);

        for (const o of GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS) {
            const row = document.createElement('label');
            row.className = 'gigma-modal-stats-panel-item';
            const cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.setAttribute('data-gigma-gwi', o.key);
            const txt = document.createElement('span');
            txt.innerHTML = (place === 'wi') ? (o.label || o.key) : (o.menuHtml || o.label || o.key);
            row.appendChild(cb);
            row.appendChild(txt);
            list.appendChild(row);
        }

        const hr = document.createElement('div');
        hr.className = 'gigma-global-wi-stats-divider';
        hr.textContent = 'Lorebooks & Folders';
        list.appendChild(hr);

        // Extra count options (icons match the search results list)
        for (const o of GIGMA_GLOBAL_WI_STATS_EXTRA_OPTIONS) {
            const row = document.createElement('label');
            row.className = 'gigma-modal-stats-panel-item';
            const cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.setAttribute('data-gigma-gwi', o.key);
            const txt = document.createElement('span');
            txt.innerHTML = (place === 'wi') ? (GIGMA_NATIVE_WI_FULL_GLOBAL_BOOKS_LABEL_BY_KEY.get(o.key) || o.label || o.key) : (o.menuHtml || o.label || o.key);
            row.appendChild(cb);
            row.appendChild(txt);
            list.appendChild(row);
        }

        panel.appendChild(list);

        // Wire interactions (panel-local; works for modal+preview)
        panel.addEventListener('click', (ev) => {
            try{
                const t = ev && ev.target;
                const btn = (t && t.closest) ? t.closest('button') : null;
                if (!btn) return;

                const count = btn.getAttribute('data-gigma-gwi-count');
                if (count) {
                    ev.preventDefault(); ev.stopPropagation();
                    if (place === 'preview') {
                        const wasE = !!EXTENSION_STATE.globalWiStatsPreviewShowEntries;
                        const wasT = !!EXTENSION_STATE.globalWiStatsPreviewShowTokens;
                        if (count === 'entries') EXTENSION_STATE.globalWiStatsPreviewShowEntries = !wasE;
                        if (count === 'tokens') EXTENSION_STATE.globalWiStatsPreviewShowTokens = !wasT;
                        if (!EXTENSION_STATE.globalWiStatsPreviewShowEntries && !EXTENSION_STATE.globalWiStatsPreviewShowTokens) {
                            if (count === 'entries') EXTENSION_STATE.globalWiStatsPreviewShowTokens = true;
                            else EXTENSION_STATE.globalWiStatsPreviewShowEntries = true;
                        }
                    } else if (place === 'wi') {
                        const wasE = !!EXTENSION_STATE.globalWiStatsWiShowEntries;
                        const wasT = !!EXTENSION_STATE.globalWiStatsWiShowTokens;
                        if (count === 'entries') EXTENSION_STATE.globalWiStatsWiShowEntries = !wasE;
                        if (count === 'tokens') EXTENSION_STATE.globalWiStatsWiShowTokens = !wasT;
                        if (!EXTENSION_STATE.globalWiStatsWiShowEntries && !EXTENSION_STATE.globalWiStatsWiShowTokens) {
                            if (count === 'entries') EXTENSION_STATE.globalWiStatsWiShowTokens = true;
                            else EXTENSION_STATE.globalWiStatsWiShowEntries = true;
                        }
                    } else {
                        const wasE = !!EXTENSION_STATE.globalWiStatsModalShowEntries;
                        const wasT = !!EXTENSION_STATE.globalWiStatsModalShowTokens;
                        if (count === 'entries') EXTENSION_STATE.globalWiStatsModalShowEntries = !wasE;
                        if (count === 'tokens') EXTENSION_STATE.globalWiStatsModalShowTokens = !wasT;
                        if (!EXTENSION_STATE.globalWiStatsModalShowEntries && !EXTENSION_STATE.globalWiStatsModalShowTokens) {
                            if (count === 'entries') EXTENSION_STATE.globalWiStatsModalShowTokens = true;
                            else EXTENSION_STATE.globalWiStatsModalShowEntries = true;
                        }
                    }
                    gigmaPersistGlobalWiStatsSettings(place);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    gigmaQueueGlobalWiStatsUpdate(place);
                    return;
                }

                const section = btn.getAttribute('data-gigma-gwi-section');
                const action = btn.getAttribute('data-gigma-gwi-action');

                if (section) {
                    ev.preventDefault(); ev.stopPropagation();
                    if (place === 'preview') {
                        if (section === 'context') EXTENSION_STATE.globalWiStatsPreviewSectionBudgetContext = !EXTENSION_STATE.globalWiStatsPreviewSectionBudgetContext;
                        if (section === 'books') EXTENSION_STATE.globalWiStatsPreviewSectionBooks = !EXTENSION_STATE.globalWiStatsPreviewSectionBooks;
                        if (section === 'raw') EXTENSION_STATE.globalWiStatsPreviewSectionRaw = !EXTENSION_STATE.globalWiStatsPreviewSectionRaw;
                        if (section === 'activated') EXTENSION_STATE.globalWiStatsPreviewSectionActivated = !EXTENSION_STATE.globalWiStatsPreviewSectionActivated;
                        if (section === 'included') EXTENSION_STATE.globalWiStatsPreviewSectionIncluded = !EXTENSION_STATE.globalWiStatsPreviewSectionIncluded;
                    } else if (place === 'wi') {
                        if (section === 'context') EXTENSION_STATE.globalWiStatsWiSectionBudgetContext = !EXTENSION_STATE.globalWiStatsWiSectionBudgetContext;
                        if (section === 'books') EXTENSION_STATE.globalWiStatsWiSectionBooks = !EXTENSION_STATE.globalWiStatsWiSectionBooks;
                        if (section === 'raw') EXTENSION_STATE.globalWiStatsWiSectionRaw = !EXTENSION_STATE.globalWiStatsWiSectionRaw;
                        if (section === 'activated') EXTENSION_STATE.globalWiStatsWiSectionActivated = !EXTENSION_STATE.globalWiStatsWiSectionActivated;
                        if (section === 'included') EXTENSION_STATE.globalWiStatsWiSectionIncluded = !EXTENSION_STATE.globalWiStatsWiSectionIncluded;
                    } else {
                        if (section === 'context') EXTENSION_STATE.globalWiStatsModalSectionBudgetContext = !EXTENSION_STATE.globalWiStatsModalSectionBudgetContext;
                        if (section === 'books') EXTENSION_STATE.globalWiStatsModalSectionBooks = !EXTENSION_STATE.globalWiStatsModalSectionBooks;
                        if (section === 'raw') EXTENSION_STATE.globalWiStatsModalSectionRaw = !EXTENSION_STATE.globalWiStatsModalSectionRaw;
                        if (section === 'activated') EXTENSION_STATE.globalWiStatsModalSectionActivated = !EXTENSION_STATE.globalWiStatsModalSectionActivated;
                        if (section === 'included') EXTENSION_STATE.globalWiStatsModalSectionIncluded = !EXTENSION_STATE.globalWiStatsModalSectionIncluded;
                    }
                    gigmaPersistGlobalWiStatsSettings(place);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    gigmaQueueGlobalWiStatsUpdate(place);
                    return;
                }

                if (action) {
                    ev.preventDefault(); ev.stopPropagation();
                    if (action === 'all') {
                        gigmaSetGlobalWiStatsOptionList(place, GIGMA_MODAL_STATS_CATEGORIES.map(c => c.key).concat(GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS.map(o => o.key)).concat(GIGMA_GLOBAL_WI_STATS_EXTRA_OPTIONS.map(o => o.key)));
                    } else if (action === 'none') {
                        gigmaSetGlobalWiStatsOptionList(place, []);
                    }
                    gigmaPersistGlobalWiStatsSettings(place);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    gigmaQueueGlobalWiStatsUpdate(place);
                }
            }catch(_e){}
        }, true);

        panel.addEventListener('change', (ev) => {
            try{
                const t = ev && ev.target;
                if (!t || t.tagName !== 'INPUT') return;

                // Switch
                if (t.getAttribute('data-gigma-gwi-switch') === '1') {
                    if (place === 'preview') EXTENSION_STATE.globalWiStatsPreviewEnabled = !!t.checked;
                    else if (place === 'wi') EXTENSION_STATE.globalWiStatsWiEnabled = !!t.checked;
                    else EXTENSION_STATE.globalWiStatsModalEnabled = !!t.checked;
                    gigmaPersistGlobalWiStatsSettings(place);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    gigmaQueueGlobalWiStatsUpdate(place);
                    return;
                }

                if (t.getAttribute('data-gigma-gwi-collapse-switch') === '1') {
                    gigmaSetStatsCollapseButtonVisible(place, 'global', !!t.checked);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    return;
                }

                if (t.getAttribute('data-gigma-gwi-remove-irrelevant-switch') === '1') {
                    if (place === 'preview') EXTENSION_STATE.globalWiStatsPreviewRemoveIrrelevantCategories = !!t.checked;
                    else if (place === 'wi') EXTENSION_STATE.globalWiStatsWiRemoveIrrelevantCategories = !!t.checked;
                    else EXTENSION_STATE.globalWiStatsModalRemoveIrrelevantCategories = !!t.checked;
                    gigmaPersistGlobalWiStatsSettings(place);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    gigmaQueueGlobalWiStatsUpdate(place);
                    return;
                }

                if (t.getAttribute('data-gigma-gwi-remove-zero-tokens-switch') === '1') {
                    if (place === 'preview') EXTENSION_STATE.globalWiStatsPreviewRemoveZeroTokenCategories = !!t.checked;
                    else if (place === 'wi') EXTENSION_STATE.globalWiStatsWiRemoveZeroTokenCategories = !!t.checked;
                    else EXTENSION_STATE.globalWiStatsModalRemoveZeroTokenCategories = !!t.checked;
                    gigmaPersistGlobalWiStatsSettings(place);
                    gigmaUpdateGlobalWiStatsControlsUi(place);
                    gigmaQueueGlobalWiStatsUpdate(place);
                    return;
                }

                const k = t.getAttribute('data-gigma-gwi');
                if (!k) return;
                const cur = gigmaGetGlobalWiStatsOptionList(place).slice();
                const i = cur.indexOf(k);
                if (t.checked) {
                    if (i < 0) cur.push(k);
                } else {
                    if (i >= 0) cur.splice(i, 1);
                }
                gigmaSetGlobalWiStatsOptionList(place, cur);
                gigmaPersistGlobalWiStatsSettings(place);
                gigmaUpdateGlobalWiStatsControlsUi(place);
                gigmaQueueGlobalWiStatsUpdate(place);
            }catch(_e){}
        }, true);
    }catch(_e){}
}

function gigmaUpdateGlobalWiStatsControlsUi(place){
    try{
        if (place === 'preview') {
            const root = gigmaGetLatestLayoutPresetTreePreviewRoot();
            const panels = root ? Array.from(root.querySelectorAll('.gigma-global-wi-stats-panel')) : [];
            const set = gigmaGetGlobalWiStatsOptionSet('preview');

            panels.forEach((panel) => {
                const sw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-switch="1"]');
                if (sw) sw.checked = !!EXTENSION_STATE.globalWiStatsPreviewEnabled;
                const collapseSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-collapse-switch="1"]');
                if (collapseSw) collapseSw.checked = gigmaGetStatsCollapseButtonVisible('preview', 'global');
                const removeIrrelevantSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-remove-irrelevant-switch="1"]');
                if (removeIrrelevantSw) removeIrrelevantSw.checked = !!EXTENSION_STATE.globalWiStatsPreviewRemoveIrrelevantCategories;
                const removeZeroTokensSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-remove-zero-tokens-switch="1"]');
                if (removeZeroTokensSw) removeZeroTokensSw.checked = !!EXTENSION_STATE.globalWiStatsPreviewRemoveZeroTokenCategories;

                panel.querySelectorAll('button[data-gigma-gwi-count]').forEach((b) => {
                    const k = b.getAttribute('data-gigma-gwi-count');
                    const on = (k === 'entries') ? !!EXTENSION_STATE.globalWiStatsPreviewShowEntries
                             : (k === 'tokens') ? !!EXTENSION_STATE.globalWiStatsPreviewShowTokens
                             : false;
                    b.setAttribute('aria-pressed', on ? 'true' : 'false');
                });

                panel.querySelectorAll('button[data-gigma-gwi-section]').forEach((b) => {
                    const k = b.getAttribute('data-gigma-gwi-section');
                    const on = (k === 'context') ? !!EXTENSION_STATE.globalWiStatsPreviewSectionBudgetContext
                             : (k === 'books') ? !!EXTENSION_STATE.globalWiStatsPreviewSectionBooks
                             : (k === 'raw') ? !!EXTENSION_STATE.globalWiStatsPreviewSectionRaw
                             : (k === 'activated') ? !!EXTENSION_STATE.globalWiStatsPreviewSectionActivated
                             : (k === 'included') ? !!EXTENSION_STATE.globalWiStatsPreviewSectionIncluded
                             : false;
                    b.setAttribute('aria-pressed', on ? 'true' : 'false');
                });

                panel.querySelectorAll('input[type="checkbox"][data-gigma-gwi]').forEach((cb) => {
                    const k = cb.getAttribute('data-gigma-gwi');
                    cb.checked = !!(k && set.has(k));
                });
            });

            // Button aria-expanded
            if (root) {
                const btn = root.querySelector('#gigma-layout-preset-tree-global-wi-stats');
                const collapseBtn = root.querySelector('#gigma-layout-preset-tree-global-wi-stats-collapse');
                if (btn) btn.setAttribute('aria-expanded', EXTENSION_STATE.globalWiStatsPreviewPanelOpen ? 'true' : 'false');
                gigmaSyncStatsButtonPairUi(btn, collapseBtn, !!EXTENSION_STATE.globalWiStatsPreviewEnabled, !gigmaGetGlobalWiStatsDisplayCollapsed('preview'), 'Global WI Statistics', gigmaGetStatsCollapseButtonVisible('preview', 'global'));
                const panel = root.querySelector('#gigma-layout-preset-tree-global-wi-stats-panel');
                if (panel) {
                    panel.classList.toggle('gigma-hidden', !EXTENSION_STATE.globalWiStatsPreviewPanelOpen);
                    panel.setAttribute('aria-hidden', EXTENSION_STATE.globalWiStatsPreviewPanelOpen ? 'false' : 'true');
                    if (EXTENSION_STATE.globalWiStatsPreviewPanelOpen && btn) {
                        gigmaApplyGlobalWiStatsDropdownPlacement(panel, btn, 'preview');
                    }
                }
            }
            return;
        }

        if (place === 'wi') {
            const set = gigmaGetGlobalWiStatsOptionSet('wi');
            const panel = document.getElementById(SELECTORS.WORLD_INFO_GLOBAL_WI_STATS_PANEL);
            const btn = document.getElementById(SELECTORS.WORLD_INFO_GLOBAL_WI_STATS_BUTTON);
            const collapseBtn = document.getElementById(SELECTORS.WORLD_INFO_GLOBAL_WI_COLLAPSE_BUTTON);

            if (panel) {
                const sw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-switch="1"]');
                if (sw) sw.checked = !!EXTENSION_STATE.globalWiStatsWiEnabled;
                const collapseSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-collapse-switch="1"]');
                if (collapseSw) collapseSw.checked = gigmaGetStatsCollapseButtonVisible('wi', 'global');
                const removeIrrelevantSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-remove-irrelevant-switch="1"]');
                if (removeIrrelevantSw) removeIrrelevantSw.checked = !!EXTENSION_STATE.globalWiStatsWiRemoveIrrelevantCategories;
                const removeZeroTokensSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-remove-zero-tokens-switch="1"]');
                if (removeZeroTokensSw) removeZeroTokensSw.checked = !!EXTENSION_STATE.globalWiStatsWiRemoveZeroTokenCategories;

                panel.querySelectorAll('button[data-gigma-gwi-count]').forEach((b) => {
                    const k = b.getAttribute('data-gigma-gwi-count');
                    const on = (k === 'entries') ? !!EXTENSION_STATE.globalWiStatsWiShowEntries
                             : (k === 'tokens') ? !!EXTENSION_STATE.globalWiStatsWiShowTokens
                             : false;
                    b.setAttribute('aria-pressed', on ? 'true' : 'false');
                });

                panel.querySelectorAll('button[data-gigma-gwi-section]').forEach((b) => {
                    const k = b.getAttribute('data-gigma-gwi-section');
                    const on = (k === 'context') ? !!EXTENSION_STATE.globalWiStatsWiSectionBudgetContext
                             : (k === 'books') ? !!EXTENSION_STATE.globalWiStatsWiSectionBooks
                             : (k === 'raw') ? !!EXTENSION_STATE.globalWiStatsWiSectionRaw
                             : (k === 'activated') ? !!EXTENSION_STATE.globalWiStatsWiSectionActivated
                             : (k === 'included') ? !!EXTENSION_STATE.globalWiStatsWiSectionIncluded
                             : false;
                    b.setAttribute('aria-pressed', on ? 'true' : 'false');
                });

                panel.querySelectorAll('input[type="checkbox"][data-gigma-gwi]').forEach((cb) => {
                    const k = cb.getAttribute('data-gigma-gwi');
                    cb.checked = !!(k && set.has(k));
                });

                panel.classList.toggle('gigma-hidden', !EXTENSION_STATE.globalWiStatsWiPanelOpen);
                panel.setAttribute('aria-hidden', EXTENSION_STATE.globalWiStatsWiPanelOpen ? 'false' : 'true');

                if (EXTENSION_STATE.globalWiStatsWiPanelOpen && btn) {
                    try{ gigmaApplyWorldInfoFloatingDropdownPlacement(panel, btn); }catch(_ePlaceWi){}
                } else {
                    gigmaResetWorldInfoFloatingDropdownPlacement(panel);
                }
            }

            if (btn) btn.setAttribute('aria-expanded', EXTENSION_STATE.globalWiStatsWiPanelOpen ? 'true' : 'false');
            gigmaSyncStatsButtonPairUi(btn, collapseBtn, !!EXTENSION_STATE.globalWiStatsWiEnabled, !gigmaGetGlobalWiStatsDisplayCollapsed('wi'), 'Global Stats', gigmaGetStatsCollapseButtonVisible('wi', 'global'));
            gigmaSyncNativeWiMobileFullscreenStatsLayer();
            return;
        }

        // modal: two toolbars -> two panels
        const set = gigmaGetGlobalWiStatsOptionSet('modal');
        const panels = [
            document.getElementById('gigma-modal-global-wi-stats-panel'),
            document.getElementById('gigma-modal-global-wi-stats-panel-right')
        ].filter(Boolean);

        for (const panel of panels) {
            const sw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-switch="1"]');
            if (sw) sw.checked = !!EXTENSION_STATE.globalWiStatsModalEnabled;
            const collapseSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-collapse-switch="1"]');
            if (collapseSw) collapseSw.checked = gigmaGetStatsCollapseButtonVisible('modal', 'global');
            const removeIrrelevantSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-remove-irrelevant-switch="1"]');
            if (removeIrrelevantSw) removeIrrelevantSw.checked = !!EXTENSION_STATE.globalWiStatsModalRemoveIrrelevantCategories;
            const removeZeroTokensSw = panel.querySelector('input[type="checkbox"][data-gigma-gwi-remove-zero-tokens-switch="1"]');
            if (removeZeroTokensSw) removeZeroTokensSw.checked = !!EXTENSION_STATE.globalWiStatsModalRemoveZeroTokenCategories;

            panel.querySelectorAll('button[data-gigma-gwi-count]').forEach((b) => {
                const k = b.getAttribute('data-gigma-gwi-count');
                const on = (k === 'entries') ? !!EXTENSION_STATE.globalWiStatsModalShowEntries
                         : (k === 'tokens') ? !!EXTENSION_STATE.globalWiStatsModalShowTokens
                         : false;
                b.setAttribute('aria-pressed', on ? 'true' : 'false');
            });

            panel.querySelectorAll('button[data-gigma-gwi-section]').forEach((b) => {
                const k = b.getAttribute('data-gigma-gwi-section');
                const on = (k === 'context') ? !!EXTENSION_STATE.globalWiStatsModalSectionBudgetContext
                         : (k === 'books') ? !!EXTENSION_STATE.globalWiStatsModalSectionBooks
                         : (k === 'raw') ? !!EXTENSION_STATE.globalWiStatsModalSectionRaw
                         : (k === 'activated') ? !!EXTENSION_STATE.globalWiStatsModalSectionActivated
                         : (k === 'included') ? !!EXTENSION_STATE.globalWiStatsModalSectionIncluded
                         : false;
                b.setAttribute('aria-pressed', on ? 'true' : 'false');
            });

            panel.querySelectorAll('input[type="checkbox"][data-gigma-gwi]').forEach((cb) => {
                const k = cb.getAttribute('data-gigma-gwi');
                cb.checked = !!(k && set.has(k));
            });

            // Show only the panel that matches the open suffix (so the dropdown comes from the clicked button)
            const suffix = panel.id.endsWith('-right') ? '-right' : '';
            const shouldOpen = !!(EXTENSION_STATE.globalWiStatsModalPanelOpen && EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen === suffix);
            panel.classList.toggle('gigma-hidden', !shouldOpen);
            panel.setAttribute('aria-hidden', shouldOpen ? 'false' : 'true');
        }

        const btns = [
            document.getElementById('gigma-modal-global-wi-stats'),
            document.getElementById('gigma-modal-global-wi-stats-right')
        ].filter(Boolean);
        const collapseBtn = document.getElementById('gigma-modal-global-wi-stats-collapse');
        const modalGlobalEnabled = !!EXTENSION_STATE.globalWiStatsModalEnabled;
        const modalGlobalShowCollapseButton = gigmaGetStatsCollapseButtonVisible('modal', 'global');
        for (const btn of btns) {
            const suffix = btn.id.endsWith('-right') ? '-right' : '';
            const open = !!(EXTENSION_STATE.globalWiStatsModalPanelOpen && EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen === suffix);
            gigmaApplyStatsPrimaryButtonUi(btn, modalGlobalEnabled);
            btn.setAttribute('aria-expanded', open ? 'true' : 'false');
        }
        gigmaUpdateStatsCollapseButtonUi(collapseBtn, !gigmaGetGlobalWiStatsDisplayCollapsed('modal'), 'Global WI Statistics', { visible: modalGlobalEnabled && modalGlobalShowCollapseButton });

        try{
            const suf = String(EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen || '');
            const btn = document.getElementById('gigma-modal-global-wi-stats' + suf);
            const panel = document.getElementById('gigma-modal-global-wi-stats-panel' + suf);

            if (EXTENSION_STATE.globalWiStatsModalPanelOpen) {
                if (!btn || !panel) {
                    // Right-pane Global button was removed; close gracefully if stale state remains.
                    EXTENSION_STATE.globalWiStatsModalPanelOpen = false;
                    EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen = '';
                } else {
                    gigmaApplyGlobalWiStatsDropdownPlacement(panel, btn, 'modal');
                }
            }
        }catch(_ePlace){}
    }catch(_e){}
}


function gigmaAccumulateLorebookStatsInto(dest, src){
    try{
        if (!dest || !src) return;
        for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
            const k = c.key;
            const d = dest[k] || (dest[k] = { entries: 0, tokens: 0 });
            const s = src[k];
            if (!s) continue;
            d.entries = (Number(d.entries) || 0) + (Number(s.entries) || 0);
            d.tokens  = (Number(d.tokens)  || 0) + (Number(s.tokens)  || 0);
        }
    }catch(_e){}
}

function gigmaComputeGlobalWiStatsForWorldNames(worldNames, unchainedSet){
    const meta = {
        lorebooks: 0,
        unchained: 0,
        chained: 0,
        folders: 0,
        global: 0,
        character: 0,
        chat: 0,
        persona: 0,
        other: 0,
    };
    const out = {
        meta,
        raw: gigmaCreateEmptyLorebookStatsObject(),
        activated: gigmaCreateEmptyLorebookStatsObject(),
        included: gigmaCreateEmptyLorebookStatsObject(),
        missing: [],
    };

    try{
        const seen = new Set();
        for (const nameRaw of (Array.isArray(worldNames) ? worldNames : [])) {
            const world = String(nameRaw || '').trim();
            if (!world) continue;
            if (seen.has(world)) continue;
            seen.add(world);
            meta.lorebooks += 1;

            const isUnchained = !!(unchainedSet && typeof unchainedSet.has === 'function' && unchainedSet.has(world));
            if (isUnchained) meta.unchained += 1;
            else meta.chained += 1;

            // Usage flags (global / character / chat / persona / other)
            try{
                const flags = (typeof __gigmaGetWorldUsageFlags === 'function') ? __gigmaGetWorldUsageFlags(world) : null;
                const isGlobal = !!flags?.isActiveWorld;
                const isChar   = !!flags?.isCharacterWorld;
                const isChat   = !!flags?.isChatWorld;
                const isPers   = !!flags?.isPersonaWorld;
                if (isGlobal) meta.global += 1;
                if (isChar) meta.character += 1;
                if (isChat) meta.chat += 1;
                if (isPers) meta.persona += 1;
                if (!isGlobal && !isChar && !isChat && !isPers) meta.other += 1;
            }catch(_eFlags){
                meta.other += 1;
            }

            // Raw stats
            const stats = gigmaGetLorebookStatsIndexStatsByWorldName(world);
            if (stats) gigmaAccumulateLorebookStatsInto(out.raw, stats);
            else out.missing.push(world);

            // Activated/Included sections use last-generation snapshot pair (if present)
            try{
                const a = gigmaGetLastModalLorebookStatsSnapshotByWorld('activated', world);
                if (a) gigmaAccumulateLorebookStatsInto(out.activated, a);
            }catch(_eA){}
            try{
                const inc = gigmaGetLastModalLorebookStatsSnapshotByWorld('included', world);
                if (inc) gigmaAccumulateLorebookStatsInto(out.included, inc);
            }catch(_eI){}
        }
    }catch(_e){}

    return out;
}


function gigmaGetCurrentPresetOrderBudgetChainedUnchainedCounts(){
    const out = { order:{chained:0, unchained:0}, budget:{chained:0, unchained:0} };
    try{
        const ids = new Set();
        let total = 0;
        try{
            const idByName = (window && window.gigmaWorldIdByName && typeof window.gigmaWorldIdByName === 'object')
                ? window.gigmaWorldIdByName
                : ((typeof gigmaGetWorldIdMap === 'function') ? gigmaGetWorldIdMap() : null);
            if (Array.isArray(world_names)){
                for (const wn of world_names){
                    const name = String(wn || '').trim();
                    if (!name) continue;
                    const id = (idByName && typeof idByName[name] === 'string' && idByName[name].trim()) ? idByName[name].trim() : name;
                    if (id) ids.add(String(id));
                }
            }
            total = ids.size || (Array.isArray(world_names) ? world_names.length : 0);
        }catch(_eIds){
            total = Array.isArray(world_names) ? world_names.length : 0;
        }

        let active = null;
        try{ if (typeof gigmaGetActivePresetKindAndId === 'function') active = gigmaGetActivePresetKindAndId(); }catch(_eAct){ active = null; }
        const kind = (active && (active.kind === 'parent' || active.kind === 'child')) ? active.kind : 'child';
        const presetId = (active && active.presetId) ? String(active.presetId) : '';
        if (!presetId) {
            out.order.chained = total;
            out.budget.chained = total;
            return out;
        }

        const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore(kind) || {}) : {};
        const preset = (store && typeof store === 'object' && Object.prototype.hasOwnProperty.call(store, presetId)) ? store[presetId] : null;

        if (kind === 'parent'){
            out.order.chained = total;
            out.budget.chained = total;

            const childStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
            const inheritingOrder = new Set();
            const inheritingBudget = new Set();
            try{
                Object.keys(childStore || {}).forEach((cid) => {
                    const cp = childStore[cid];
                    if (!cp || typeof cp !== 'object') return;
                    const ord = (typeof cp.chatInheritOrderFromId === 'string') ? cp.chatInheritOrderFromId.trim() : '';
                    if (ord && ord === presetId) inheritingOrder.add(String(cid));
                    const bud = (typeof cp.budgetInheritFromId === 'string') ? cp.budgetInheritFromId.trim() : '';
                    if (bud && bud === presetId) inheritingBudget.add(String(cid));
                });
            }catch(_eInh){}

            let orderCount = 0;
            try{
                const pairs = new Set();
                const co = (preset && preset.childrenOrder && typeof preset.childrenOrder === 'object') ? preset.childrenOrder : null;
                if (co){
                    Object.keys(co).forEach((k) => {
                        const arr = co[k];
                        if (!Array.isArray(arr)) return;
                        for (const token of arr){
                            if (typeof token !== 'string') continue;
                            if (token.indexOf('urowid:') !== 0) continue;
                            const rest = token.slice(7);
                            const sep = rest.indexOf(':');
                            if (sep <= 0) continue;
                            const encChild = rest.slice(0, sep);
                            const wid = rest.slice(sep + 1);
                            if (!wid) continue;
                            let childId = '';
                            try{ childId = decodeURIComponent(encChild || ''); }catch(_eDec){ childId = encChild || ''; }
                            childId = String(childId || '').trim();
                            if (!childId || !inheritingOrder.has(childId)) continue;
                            pairs.add(childId + '|' + String(wid));
                        }
                    });
                }
                orderCount = pairs.size;
            }catch(_eUrow){ orderCount = 0; }

            let budgetCount = 0;
            try{
                for (const cid of Array.from(inheritingBudget)){
                    const cp = childStore[cid];
                    if (!cp || typeof cp !== 'object') continue;
                    const lockSet = (typeof gigmaGetRetroBudgetLockSetFromPreset === 'function')
                        ? gigmaGetRetroBudgetLockSetFromPreset(cp)
                        : new Set((Array.isArray(cp.retroLocksBudget) ? cp.retroLocksBudget : []).map(v => String(v)).filter(Boolean));
                    budgetCount += (lockSet && typeof lockSet.size === 'number') ? lockSet.size : 0;
                }
            }catch(_eBud){ budgetCount = 0; }

            out.order.unchained = orderCount;
            out.budget.unchained = budgetCount;
            return out;
        }

        if (!preset || typeof preset !== 'object'){
            out.order.chained = total;
            out.budget.chained = total;
            return out;
        }

        let effective = preset;
        try{
            if (typeof gigmaBuildEffectivePresetForTree === 'function'){
                effective = gigmaBuildEffectivePresetForTree('child', presetId, preset) || preset;
            }
        }catch(_eEff){ effective = preset; }

        let orderLocks = null;
        try{
        if (typeof gigmaGetOrderLockSet === 'function') orderLocks = gigmaGetOrderLockSet();
        }catch(_eOrdLive){ orderLocks = null; }
        if (!(orderLocks instanceof Set)){
        orderLocks = new Set();
        try{
        const arr = Array.isArray(effective.retroLocksOrder)
        ? effective.retroLocksOrder
        : (Array.isArray(effective.retroLocks) ? effective.retroLocks : []);
        for (const x of arr){
        const s = String(x || '').trim();
        if (s) orderLocks.add(s);
        }
        }catch(_eOrd){}
        }
        
        let budgetLocks = null;
        try{
        if (typeof gigmaGetBudgetLockSet === 'function') budgetLocks = gigmaGetBudgetLockSet();
        }catch(_eBudLive){ budgetLocks = null; }
        if (!(budgetLocks instanceof Set)){
        try{
        if (typeof gigmaGetRetroBudgetLockSetFromPreset === 'function') budgetLocks = gigmaGetRetroBudgetLockSetFromPreset(preset);
        }catch(_eB){ budgetLocks = null; }
        }
        if (!(budgetLocks instanceof Set)){
        budgetLocks = new Set();
        try{
        const arr = Array.isArray(preset.retroLocksBudget) ? preset.retroLocksBudget : [];
        for (const x of arr){
        const s = String(x || '').trim();
        if (s) budgetLocks.add(s);
        }
        }catch(_eBud2){}
        }

out.order.unchained = orderLocks.size;
        out.budget.unchained = budgetLocks.size;
        out.order.chained = Math.max(0, total - out.order.unchained);
        out.budget.chained = Math.max(0, total - out.budget.unchained);
    }catch(_eAll){}
    return out;
}


function gigmaGetGlobalWiStatsSectionTitle(sectionKey){
    return (sectionKey === 'raw')
        ? 'Raw'
        : ((sectionKey === 'activated')
            ? 'Activated'
            : ((sectionKey === 'included')
                ? 'Included'
                : String(sectionKey || '')));
}

function gigmaCreateStatChip(labelText, valueText, titleText, extraClass, iconClass, labelHtml, labelClass, valueClass){
    const chip = document.createElement('span');
    chip.className = `gigma-row-stat-chip${extraClass ? ` ${extraClass}` : ''}`;
    if (titleText) chip.title = titleText;

    const main = document.createElement('span');
    main.className = 'gigma-row-stat-chip-main';

    if (iconClass) {
        const icon = document.createElement('i');
        icon.className = `fa-solid ${iconClass} gigma-row-stat-chip-icon`;
        icon.setAttribute('aria-hidden', 'true');
        main.appendChild(icon);
    }

    const fit = document.createElement('span');
    fit.className = `gigma-row-stat-chip-fit-target${labelClass ? ` ${labelClass}` : ''}`;

    if (labelHtml != null) {
        const host = document.createElement('span');
        host.innerHTML = String(labelHtml);

        const iconNodes = host.querySelectorAll('i, svg, .gigma-row-stat-chip-text-icon');
        for (const node of iconNodes) {
            const icon = node.cloneNode(true);
            if (icon.classList) {
                icon.classList.remove('gigma-active-world-globe');
                icon.classList.add('gigma-row-stat-chip-icon');
                if (String(icon.tagName || '').toLowerCase() === 'svg') {
                    icon.classList.add('gigma-row-stat-chip-svg-icon');
                    chip.classList.add('gigma-row-stat-chip-has-svg-icon');
                }
            }
            icon.setAttribute('aria-hidden', 'true');
            main.appendChild(icon);
            node.remove();
        }

        fit.innerHTML = host.innerHTML.replace(/^\s+/, '').replace(/\s+$/, '');
    } else {
        fit.textContent = String(labelText || '');
    }

    main.appendChild(fit);
    chip.appendChild(main);

    if (valueText !== '' && valueText != null) {
        const value = document.createElement('span');
        value.className = `gigma-row-stat-chip-value${valueClass ? ` ${valueClass}` : ''}`;
        value.textContent = String(valueText);
        chip.appendChild(value);
    }

    return chip;
}

function gigmaCreateGlobalWiStatsSectionLabelChip(labelText, iconClass){
    return gigmaCreateStatChip(labelText, '', '', 'gigma-row-stat-chip-section-label', iconClass, null, '', '');
}

function gigmaCreateTokenizerStatChip(tokenizerLabel){
    const chip = document.createElement('span');
    chip.className = 'gigma-row-stat-chip gigma-global-wi-stat-chip gigma-global-wi-stat-chip-tokenizer';
    chip.title = `Tokenizer: ${String(tokenizerLabel || 'Unknown')}`;

    const main = document.createElement('span');
    main.className = 'gigma-row-stat-chip-main';

    const icon = document.createElement('span');
    icon.className = 'gigma-row-stat-chip-icon gigma-row-stat-chip-text-icon';
    icon.setAttribute('aria-hidden', 'true');
    icon.textContent = 'T';
    main.appendChild(icon);

    const fit = document.createElement('span');
    fit.className = 'gigma-row-stat-chip-fit-target gigma-global-wi-chip-label gigma-global-wi-tokenizer-chip-label';
    fit.textContent = String(tokenizerLabel || 'Unknown');
    main.appendChild(fit);

    chip.appendChild(main);
    return chip;
}

function gigmaApplyStatChipFitModeIn(root){
    try{
        if (!root || !root.querySelectorAll) return;
        const targets = root.querySelectorAll('.gigma-row-stat-chip-fit-target');
        for (const target of targets) {
            if (!target) continue;
            target.style.fontSize = '';
            const available = Math.floor(target.clientWidth || 0);
            if (!available) continue;
            const needed = Math.ceil(target.scrollWidth || 0);
            if (!needed || needed <= available) continue;
            const scale = Math.max(0.5, Math.min(1, available / needed));
            if (scale < 0.999) target.style.fontSize = `${scale}em`;
        }
    }catch(_e){}
}

function gigmaQueueStatChipFitModeIn(root){
    try{
        if (!root || !root.isConnected) return;
        if (root.__gigmaStatChipFitRaf) cancelAnimationFrame(root.__gigmaStatChipFitRaf);
        gigmaApplyStatChipFitModeIn(root);
        const pending = root.querySelectorAll ? Array.from(root.querySelectorAll('.gigma-row-stat-chip-fit-target')).some((target) => {
            try{
                return !!target && Math.floor(target.clientWidth || 0) <= 0;
            }catch(_eTarget){
                return false;
            }
        }) : false;
        if (!pending) {
            root.__gigmaStatChipFitRaf = 0;
            return;
        }
        root.__gigmaStatChipFitRaf = requestAnimationFrame(() => {
            root.__gigmaStatChipFitRaf = 0;
            if (!root.isConnected) return;
            gigmaApplyStatChipFitModeIn(root);
        });
    }catch(_e){}
}

function gigmaGetGlobalWiStatsBooksSectionItems(computed, extrasSelected, place){
    try{
        const items = [];
        const useNativeWiFullLabels = place === 'wi';
        const labelByKey = useNativeWiFullLabels
            ? GIGMA_NATIVE_WI_FULL_GLOBAL_BOOKS_LABEL_BY_KEY
            : new Map(GIGMA_GLOBAL_WI_STATS_EXTRA_OPTIONS.map(o => [o.key, o.label]));
        const menuByKey = useNativeWiFullLabels
            ? new Map(Array.from(labelByKey.entries()))
            : new Map(GIGMA_GLOBAL_WI_STATS_EXTRA_OPTIONS.map(o => [o.key, o.menuHtml || o.label || o.key]));
        const orderUnchLabel = useNativeWiFullLabels ? 'Order Unchained' : 'Order Unch';
        const budgetUnchLabel = useNativeWiFullLabels ? 'Budget Unchained' : 'Budget Unch';
        const orderChLabel = useNativeWiFullLabels ? 'Order Chained' : 'Order Ch';
        const budgetChLabel = useNativeWiFullLabels ? 'Budget Chained' : 'Budget Ch';
        const getVal = (k) => {
            if (k === 'folders') return computed?.meta?.folders;
            if (k === 'lorebooks') return computed?.meta?.lorebooks;
            if (k === 'unchained') return computed?.meta?.unchained;
            if (k === 'chained') return computed?.meta?.chained;
            if (k === 'global') return computed?.meta?.global;
            if (k === 'character') return computed?.meta?.character;
            if (k === 'chat') return computed?.meta?.chat;
            if (k === 'persona') return computed?.meta?.persona;
            if (k === 'other') return computed?.meta?.other;
            return 0;
        };
        const ob = (typeof gigmaGetCurrentPresetOrderBudgetChainedUnchainedCounts === 'function') ? gigmaGetCurrentPresetOrderBudgetChainedUnchainedCounts() : null;

        for (const k of (Array.isArray(extrasSelected) ? extrasSelected : [])) {
            if (k === 'unchained') {
                items.push({ label: orderUnchLabel, labelHtml: `<i class="fa-solid fa-link-slash"></i> ${orderUnchLabel}`, value: ob ? (Number(ob.order && ob.order.unchained) || 0) : 0 });
                items.push({ label: budgetUnchLabel, labelHtml: `<i class="fa-solid fa-link-slash"></i> ${budgetUnchLabel}`, value: ob ? (Number(ob.budget && ob.budget.unchained) || 0) : 0 });
                continue;
            }
            if (k === 'chained') {
                items.push({ label: orderChLabel, labelHtml: `<i class="fa-solid fa-link"></i> ${orderChLabel}`, value: ob ? (Number(ob.order && ob.order.chained) || 0) : 0 });
                items.push({ label: budgetChLabel, labelHtml: `<i class="fa-solid fa-link"></i> ${budgetChLabel}`, value: ob ? (Number(ob.budget && ob.budget.chained) || 0) : 0 });
                continue;
            }
            items.push({
                label: labelByKey.get(k) || k,
                labelHtml: menuByKey.get(k) || (labelByKey.get(k) || k),
                value: getVal(k),
            });
        }

        return items;
    }catch(_e){
        return [];
    }
}

function gigmaFormatGlobalWiStatsCountTokenValue(entries, tokens, showEntries, showTokens){
    const safeShowEntries = !!(showEntries || !showTokens);
    const safeShowTokens = !!(showTokens || !showEntries);
    if (safeShowEntries && safeShowTokens) return `${Number(entries) || 0}/${Number(tokens) || 0}`;
    if (safeShowEntries) return `${Number(entries) || 0}`;
    if (safeShowTokens) return `${Number(tokens) || 0}`;
    return `${Number(entries) || 0}/${Number(tokens) || 0}`;
}

function gigmaGetGlobalWiStatsBudgetContextItems(worldNames, contextSelected, showEntries, showTokens, place){
    try{
        const selected = new Set(Array.isArray(contextSelected) ? contextSelected : []);
        const items = [];
        const labelByKey = new Map(GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS.map(o => [o.key, o.label]));
        const menuByKey = new Map(GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS.map(o => [o.key, o.menuHtml || o.label || o.key]));
        const removeZeroTokenCategories = gigmaGetGlobalWiStatsRemoveZeroTokenCategories(place);
        const fullContext = Math.max(0, Number((typeof getMaxContextTokens === 'function') ? getMaxContextTokens() : 0) || 0);
        const usableContext = Math.max(0, Number((typeof getMaxContextSize === 'function') ? getMaxContextSize() : 0) || 0);
        const responseTokens = Math.max(0, Number((typeof getMaxResponseTokens === 'function') ? getMaxResponseTokens() : 0) || 0);
        const wiPercent = (typeof world_info_budget === 'number' && world_info_budget > 0) ? world_info_budget : 25;
        const budgetCap = (typeof world_info_budget_cap === 'number' && world_info_budget_cap > 0) ? world_info_budget_cap : 0;
        const globalBudget = Math.max(0, Number(calculateTotalWIBudget()) || 0);

        let tokenizerLabel = 'Unknown';
        try{
            const info = (typeof getFriendlyTokenizerName === 'function') ? getFriendlyTokenizerName() : null;
            const primary = info && typeof info.tokenizerName === 'string' ? info.tokenizerName.trim() : '';
            const fallback = info && typeof info.tokenizerKey === 'string' ? info.tokenizerKey.trim() : '';
            tokenizerLabel = primary || fallback || tokenizerLabel;
        }catch(_eTokenizer){}

        let ignoredEntries = 0;
        let ignoredTokens = 0;
        try{
            const seenWorlds = new Set();
            for (const nameRaw of (Array.isArray(worldNames) ? worldNames : [])) {
                const worldName = String(nameRaw || '').trim();
                if (!worldName || seenWorlds.has(worldName)) continue;
                seenWorlds.add(worldName);

                const data = worldInfoCache?.has?.(worldName) ? worldInfoCache.get(worldName) : null;
                const entries = (data && typeof data === 'object' && data.entries && typeof data.entries === 'object') ? data.entries : null;
                if (!entries) continue;

                const nlInfo = gigmaComputeLorebookLeadingNewlineInfo(entries);
                for (const uid in entries) {
                    const e = entries[uid];
                    if (!e || e.disable === true || e.ignoreBudget !== true) continue;
                    const entryObj = (e && typeof e === 'object' && e.uid != null) ? e : { ...e, uid };
                    const uidStr = String(entryObj.uid ?? uid);
                    const content = (typeof entryObj.content === 'string') ? entryObj.content : '';
                    const enabledNonEmpty = entryObj.disable !== true && !!content;
                    if (!enabledNonEmpty) continue;
                    const leadingNewline = (nlInfo.count > 1) && uidStr && (uidStr !== nlInfo.minUid);
                    ignoredEntries += 1;
                    ignoredTokens += Number(getEntryTokenCountCached(entryObj, leadingNewline)) || 0;
                }
            }
        }catch(_eIgnored){}

        const trimmedSummary = (EXTENSION_STATE && EXTENSION_STATE.lastBudgetDropSummary && typeof EXTENSION_STATE.lastBudgetDropSummary === 'object')
            ? EXTENSION_STATE.lastBudgetDropSummary
            : { entries: 0, tokens: 0 };
        const trimmedEntries = Math.max(0, Number(trimmedSummary.entries) || 0);
        const trimmedTokens = Math.max(0, Number(trimmedSummary.tokens) || 0);

        const pushStatic = (key, value, tokenValue = null) => {
            if (!selected.has(key)) return;
            if (removeZeroTokenCategories && Number(tokenValue) <= 0) return;
            items.push({
                key,
                label: labelByKey.get(key) || key,
                labelHtml: menuByKey.get(key) || (labelByKey.get(key) || key),
                value: value,
            });
        };
        const pushPair = (key, entries, tokens) => {
            if (!selected.has(key)) return;
            if (removeZeroTokenCategories && Number(tokens) <= 0) return;
            items.push({
                key,
                label: labelByKey.get(key) || key,
                labelHtml: menuByKey.get(key) || (labelByKey.get(key) || key),
                value: gigmaFormatGlobalWiStatsCountTokenValue(entries, tokens, showEntries, showTokens),
            });
        };
        const pushMeta = (key, value) => {
            if (!selected.has(key)) return;
            items.push({
                key,
                label: labelByKey.get(key) || key,
                labelHtml: menuByKey.get(key) || (labelByKey.get(key) || key),
                value: value,
            });
        };

        pushStatic('fullContext', fullContext, fullContext);
        pushStatic('usableContext', usableContext, usableContext);
        pushStatic('responseTokens', responseTokens, responseTokens);
        pushStatic('globalBudget', globalBudget, globalBudget);
        pushMeta('contextPercent', `${wiPercent}%`);
        pushStatic('budgetCap', budgetCap > 0 ? budgetCap : 'Off', budgetCap);
        pushMeta('tokenizer', tokenizerLabel);
        pushPair('ignoredBudget', ignoredEntries, ignoredTokens);
        pushPair('trimmedBudget', trimmedEntries, trimmedTokens);

        return items;
    }catch(_e){
        return [];
    }
}

