function gigmaRenderGlobalWiStatsDisplayInto(container, place, rootOverride){
    try{
        if (!container) return;

        const isPreview = (place === 'preview');
        const enabled = isPreview ? !!EXTENSION_STATE.globalWiStatsPreviewEnabled : !!EXTENSION_STATE.globalWiStatsModalEnabled;
        if (!enabled) {
            container.classList.add('gigma-hidden');
            container.replaceChildren();
            return;
        }

        const set = gigmaGetGlobalWiStatsOptionSet(place);
        const catsSelected = GIGMA_MODAL_STATS_CATEGORIES.map(c => c.key).filter(k => set.has(k));
        const contextSelected = GIGMA_GLOBAL_WI_STATS_CONTEXT_OPTIONS.map(o => o.key).filter(k => set.has(k));
        const extrasSelected = GIGMA_GLOBAL_WI_STATS_EXTRA_OPTIONS.map(o => o.key).filter(k => set.has(k));

        const showEntries = isPreview
            ? !!EXTENSION_STATE.globalWiStatsPreviewShowEntries
            : !!EXTENSION_STATE.globalWiStatsModalShowEntries;
        const showTokens = isPreview
            ? !!EXTENSION_STATE.globalWiStatsPreviewShowTokens
            : !!EXTENSION_STATE.globalWiStatsModalShowTokens;
        const safeShowEntries = (showEntries || !showTokens);
        const safeShowTokens = (showTokens || !showEntries);

        const sectionRaw = isPreview ? !!EXTENSION_STATE.globalWiStatsPreviewSectionRaw : !!EXTENSION_STATE.globalWiStatsModalSectionRaw;
        const sectionActivated = isPreview ? !!EXTENSION_STATE.globalWiStatsPreviewSectionActivated : !!EXTENSION_STATE.globalWiStatsModalSectionActivated;
        const sectionIncluded = isPreview ? !!EXTENSION_STATE.globalWiStatsPreviewSectionIncluded : !!EXTENSION_STATE.globalWiStatsModalSectionIncluded;

        const sectionContext = isPreview ? !!EXTENSION_STATE.globalWiStatsPreviewSectionBudgetContext : !!EXTENSION_STATE.globalWiStatsModalSectionBudgetContext;
        const sectionBooks = isPreview ? !!EXTENSION_STATE.globalWiStatsPreviewSectionBooks : !!EXTENSION_STATE.globalWiStatsModalSectionBooks;
        const anyRenderable = ((sectionContext && contextSelected.length) || (sectionBooks && extrasSelected.length) || (catsSelected.length && (sectionRaw || sectionActivated || sectionIncluded)));
        const collapsed = gigmaGetGlobalWiStatsDisplayCollapsed(place);
        container.classList.toggle('gigma-hidden', (!anyRenderable || collapsed));
        if (!anyRenderable || collapsed) {
            container.replaceChildren();
            return;
        }


        const root = rootOverride || (isPreview ? gigmaGetLatestLayoutPresetTreePreviewRoot() : document.getElementById('gigma-ordering-container'));
        let worldNames = [];
        let unchainedSet = new Set();
        let folderCount = 0;

        if (isPreview) {
            if (root && root.querySelectorAll) {
                const rows = Array.from(root.querySelectorAll('.gigma-layout-preset-tree-row[data-world-name]') || []);
                worldNames = rows.map(r => (r.getAttribute('data-world-name') || '').trim()).filter(Boolean);
                const unch = rows.filter(r => r.classList && r.classList.contains('gigma-layout-preset-tree-row-unchained'))
                                 .map(r => (r.getAttribute('data-world-name') || '').trim()).filter(Boolean);
                unchainedSet = new Set(unch);
                folderCount = (root.querySelectorAll('.gigma-layout-preset-tree-folder') || []).length;
            }
        } else {
            const scope = document.getElementById('gigma-ordering-container') || document.getElementById('gigma-modal-root') || document;
            const rows = scope.querySelectorAll ? Array.from(scope.querySelectorAll('.gigma-row[data-world]') || []) : [];
            worldNames = rows.map(r => (r.dataset && r.dataset.world) ? String(r.dataset.world) : '').filter(Boolean);
            try{
                const unch = rows.filter(r => (typeof isRowUnchained === 'function') ? isRowUnchained(r) : false)
                                 .map(r => (r.dataset && r.dataset.world) ? String(r.dataset.world) : '').filter(Boolean);
                unchainedSet = new Set(unch);
            }catch(_e){ unchainedSet = new Set(); }

            try{
                folderCount = Array.isArray(window.gigmaFolders) ? window.gigmaFolders.length : (scope.querySelectorAll('.gigma-folder[data-folder-id]') || []).length;
            }catch(_e){ folderCount = 0; }
        }

        const computed = gigmaComputeGlobalWiStatsForWorldNames(worldNames, unchainedSet);
        computed.meta.folders = folderCount;

        // Build DOM
        const frag = document.createDocumentFragment();

        if (contextSelected.length && sectionContext) {
            const contextSec = document.createElement('div');
            contextSec.className = 'gigma-row-stats-section gigma-global-wi-stats-context';
            const n = gigmaRenderGlobalWiStatsBudgetContextSectionInto(contextSec, worldNames, contextSelected, safeShowEntries, safeShowTokens, place);
            if (n > 0) frag.appendChild(contextSec);
        }

        if (extrasSelected.length && sectionBooks) {
            const metaSec = document.createElement('div');
            metaSec.className = 'gigma-row-stats-section gigma-global-wi-stats-meta';
            const n = gigmaRenderGlobalWiStatsBooksSectionInto(metaSec, computed, extrasSelected);
            if (n > 0) frag.appendChild(metaSec);
        }

        // If no cats selected, skip the WI sections entirely.
        const sections = [];
        if (catsSelected.length) {
            if (sectionRaw) sections.push({ key: 'raw', stats: computed.raw });
            if (sectionActivated) sections.push({ key: 'activated', stats: computed.activated });
            if (sectionIncluded) sections.push({ key: 'included', stats: computed.included });
        }

        for (const s of sections) {
            const sec = document.createElement('div');
            sec.className = 'gigma-row-stats-section';
            sec.setAttribute('data-gigma-stats-section', s.key);
            const n = gigmaRenderGlobalWiStatsSectionInto(sec, s.stats, s.key, safeShowEntries, safeShowTokens, catsSelected, place);
            if (n > 0) frag.appendChild(sec);
        }

        // Incomplete indicator (only when relevant and visible)
        if (computed.missing && computed.missing.length) {
            const note = document.createElement('div');
            note.className = 'gigma-global-wi-stats-note';
            note.textContent = 'Some lorebooks have not been scanned for stats yet (click Gen to refresh).';
            frag.appendChild(note);
            // Opportunistically compute a few missing in the background (lightweight, capped).
            try{
                const cap = Math.min(3, computed.missing.length);
                for (let i = 0; i < cap; i++) {
                    const wn = computed.missing[i];
                    if (wn) scheduleBackground(() => gigmaGetLorebookStats(wn).then(() => gigmaQueueGlobalWiStatsUpdate(place)));
                }
            }catch(_e){}
        }

        if (!frag.childNodes.length) {
            container.classList.add('gigma-hidden');
            container.replaceChildren();
            return;
        }

        const head = document.createElement('div');
        head.className = 'gigma-global-wi-stats-display-head';
        const title = document.createElement('div');
        title.className = 'gigma-global-wi-stats-display-title';
        title.textContent = 'Global WI Statistics';
        head.appendChild(title);

        const body = document.createElement('div');
        body.className = 'gigma-global-wi-stats-display-body';
        body.appendChild(frag);

        container.replaceChildren(head, body);
        try{
            if (place === 'preview' || place === 'modal') gigmaApplyGlobalWiStatsColumnCount(container);
        }catch(_eCols){}
        gigmaQueueStatChipFitModeIn(body);
    }catch(_e){}
}

function gigmaApplyGlobalWiStatsColumnCount(container){
    try{
        if (!container || !container.isConnected) return;
        const sample = container.querySelector ? container.querySelector('.gigma-row-stats-section') : null;
        if (!sample) {
            try { container.style.removeProperty('--gigma-global-wi-stats-cols'); } catch (_e) { }
            return;
        }
        const minColEm = 9.25;
        const gapEm = gigmaGetModalLorebookStatsColumnGapEm(sample);
        const widthEm = gigmaGetModalLorebookStatsLayoutWidthEm(container);
        const n = Math.max(1, Math.floor((widthEm + gapEm) / (minColEm + gapEm)));
        container.style.setProperty('--gigma-global-wi-stats-cols', String(n));
    }catch(_e){}
}

function gigmaQueueGlobalWiStatsUpdate(place){
    try{
        const key = (place === 'preview')
            ? '__gigmaGlobalWiStatsPreviewTimer'
            : ((place === 'wi') ? '__gigmaGlobalWiStatsWiTimer' : '__gigmaGlobalWiStatsModalTimer');
        if (window[key]) clearTimeout(window[key]);
        window[key] = setTimeout(() => {
            try{
                if (place === 'preview') {
                    const root = gigmaGetLatestLayoutPresetTreePreviewRoot();
                    const container = root ? root.querySelector('#gigma-global-wi-stats-display-preview') : null;
                    gigmaRenderGlobalWiStatsDisplayInto(container, 'preview', root || undefined);
                    try{
                        if (root && EXTENSION_STATE.globalWiStatsPreviewPanelOpen) {
                            const btn = root.querySelector('#gigma-layout-preset-tree-global-wi-stats');
                            const panel = root.querySelector('#gigma-layout-preset-tree-global-wi-stats-panel');
                            if (btn && panel) gigmaApplyGlobalWiStatsDropdownPlacement(panel, btn, 'preview');
                        }
                    }catch(_ePlc){}

                } else if (place === 'wi') {
                    // World Info UI reuses the existing token total slot renderer.
                    // Rebuild the "Global" line (if tokens are enabled) without touching the modal/preview chips.
                    try{ gigmaQueueWorldInfoTokenUpdate(); }catch(_eWi){}
                } else {
                    const container = document.getElementById('gigma-global-wi-stats-display-modal');
                    gigmaRenderGlobalWiStatsDisplayInto(container, 'modal');
                }
            }catch(_e2){}
        }, 50);
    }catch(_e){}
}

function gigmaNotifyGlobalWiStatsFolderCountChanged(){
    try{
        if (typeof gigmaQueueGlobalWiStatsUpdate === 'function'){
            gigmaQueueGlobalWiStatsUpdate('modal');
            gigmaQueueGlobalWiStatsUpdate('preview');
            gigmaQueueGlobalWiStatsUpdate('wi');
        }
    }catch(_e){}
}

// === END GIGMA: Global WI statistics =========================================


async function gigmaComputeLorebookStats(entriesObj) {
    const mk = () => ({ entries: 0, tokens: 0 });
    const out = {
        total: mk(),
        enabled: mk(),
        disabled: mk(),
        constant: mk(),
        normal: mk(),
        vectorized: mk(),
        charUp: mk(),
        charDown: mk(),
        emUp: mk(),
        emDown: mk(),
        anUp: mk(),
        anDown: mk(),
        depthSystem: mk(),
        depthUser: mk(),
        depthAssistant: mk(),
        outlet: mk(),
    };

    try {
        const entries = (entriesObj && typeof entriesObj === 'object') ? Object.values(entriesObj) : [];
        const nlInfo = gigmaComputeLorebookLeadingNewlineInfo(entriesObj);
        let i = 0;
        for (const e of entries) {
            if (!e || typeof e !== 'object') continue;
            const uid = String(e.uid ?? '');
            const content = (typeof e.content === 'string') ? e.content : '';
            const enabledNonEmpty = e.disable !== true && !!content;
            const leadingNewline = (nlInfo.count > 1) && enabledNonEmpty && uid && (uid !== nlInfo.minUid);
            const tokens = getEntryTokenCountCached(e, leadingNewline);
            out.total.entries += 1;
            out.total.tokens += tokens;

            const disabled = !!e.disable;
            if (disabled) {
                out.disabled.entries += 1;
                out.disabled.tokens += tokens;
                continue;
            }

            out.enabled.entries += 1;
            out.enabled.tokens += tokens;

            if (e.constant === true) {
                out.constant.entries += 1;
                out.constant.tokens += tokens;
            } else if (e.vectorized === true) {
                out.vectorized.entries += 1;
                out.vectorized.tokens += tokens;
            } else {
                out.normal.entries += 1;
                out.normal.tokens += tokens;
            }

            const pos = Number.isInteger(e.position) ? e.position : -1;
            switch (pos) {
                case 0: out.charUp.entries += 1; out.charUp.tokens += tokens; break;
                case 1: out.charDown.entries += 1; out.charDown.tokens += tokens; break;
                case 5: out.emUp.entries += 1; out.emUp.tokens += tokens; break;
                case 6: out.emDown.entries += 1; out.emDown.tokens += tokens; break;
                case 2: out.anUp.entries += 1; out.anUp.tokens += tokens; break;
                case 3: out.anDown.entries += 1; out.anDown.tokens += tokens; break;
                case 7: out.outlet.entries += 1; out.outlet.tokens += tokens; break;
                case 4: {
                    let role = (typeof e.role !== 'undefined' && e.role !== null) ? e.role : (extension_prompt_roles ? extension_prompt_roles.SYSTEM : 0);
                    if (extension_prompt_roles && role === extension_prompt_roles.USER) {
                        out.depthUser.entries += 1; out.depthUser.tokens += tokens;
                    } else if (extension_prompt_roles && role === extension_prompt_roles.ASSISTANT) {
                        out.depthAssistant.entries += 1; out.depthAssistant.tokens += tokens;
                    } else {
                        out.depthSystem.entries += 1; out.depthSystem.tokens += tokens;
                    }
                    break;
                }
                default:
                    break;
            }

            i += 1;
            if ((i % 25) === 0) {
                await new Promise(r => setTimeout(r, 0));
            }
        }
    } catch (_e) { }

    return out;
}

async function gigmaGetLorebookStats(worldName) {
    const key = String(worldName || '');
    if (!key) {
        return gigmaCreateEmptyLorebookStats();
    }

    const indexed = gigmaGetLorebookStatsIndexStatsByWorldName(key);
    if (indexed) {
        try { GIGMA_MODAL_LOREBOOK_STATS_CACHE.set(key, { stats: indexed }); } catch (_e) {}
        return indexed;
    }

    const cached = GIGMA_MODAL_LOREBOOK_STATS_CACHE.get(key);
    if (cached?.stats) {
        return cached.stats;
    }
    if (cached?.promise) {
        return cached.promise;
    }

    const promise = (async () => {
        try {
            await gigmaEnsureLorebookStatsIndexForWorld(key, { forceRebuild: true });
            const statsFromIndex = gigmaGetLorebookStatsIndexStatsByWorldName(key);
            if (statsFromIndex) {
                GIGMA_MODAL_LOREBOOK_STATS_CACHE.set(key, { stats: statsFromIndex });
                return statsFromIndex;
            }

            const data = worldInfoCache?.has?.(key) ? worldInfoCache.get(key) : await loadWorldInfo(key);
            const entries = data?.entries ? Object.values(data.entries) : [];
            const stats = await gigmaComputeLorebookStats(entries);
            GIGMA_MODAL_LOREBOOK_STATS_CACHE.set(key, { stats });
            return stats;
        } catch (e) {
            console.warn('[GIGMA] Failed to compute lorebook stats for', key, e);
            const empty = gigmaCreateEmptyLorebookStats();
            GIGMA_MODAL_LOREBOOK_STATS_CACHE.set(key, { stats: empty });
            return empty;
        }
    })();

    GIGMA_MODAL_LOREBOOK_STATS_CACHE.set(key, { promise });

    promise.finally(() => {
        const rec = GIGMA_MODAL_LOREBOOK_STATS_CACHE.get(key);
        if (rec?.promise === promise && !rec.stats) {
            GIGMA_MODAL_LOREBOOK_STATS_CACHE.delete(key);
        }
    });

    return promise;
}

function gigmaEnsureModalRowStatsHost(row) {
    try {
        if (!row) return null;
        let grid = row.querySelector && row.querySelector(':scope > .gigma-row-header-grid');

        if (!grid) {
            // Cleanup any legacy in-label stats nodes if present.
            try {
                row.querySelectorAll('.gigma-row-label .gigma-row-stats, .gigma-row-label .gigma-row-stats-inline').forEach(n => n.remove());
            } catch (_e) {}

            grid = document.createElement('div');
            grid.className = 'gigma-row-header-grid';

            const mainline = document.createElement('div');
            mainline.className = 'gigma-row-header-mainline';

            const kids = Array.from(row.childNodes);
            for (const k of kids) mainline.appendChild(k);

            const stats = document.createElement('div');
            stats.className = 'gigma-row-stats';

            grid.appendChild(mainline);
            grid.appendChild(stats);
            row.appendChild(grid);
        }

        try { if (grid.classList) grid.classList.remove('gigma-inline-off'); } catch (_eClass) {}
        try { if (grid.querySelectorAll) grid.querySelectorAll('.gigma-row-stats-inline').forEach(n => { try{ n.remove(); }catch(_){ } }); } catch (_eRm) {}

        // Keep budget controls inside the header mainline and before the label in source order
        // so the lorebook name can wrap around them on the first line (left or right float).
        try {
            const mainline = grid.querySelector ? grid.querySelector('.gigma-row-header-mainline') : null;
            const budgetControls = row.querySelector ? row.querySelector('.gigma-budget-header-controls') : null;
            const label = mainline && mainline.querySelector ? mainline.querySelector('.gigma-row-label') : null;
            const side = (gigmaExtensionSettings && gigmaExtensionSettings.budgetHeaderSide === 'left') ? 'left' : 'right';
            if (budgetControls && budgetControls.dataset) budgetControls.dataset.gigmaSide = side;
            if (mainline && budgetControls) {
                const alreadyInMainline = budgetControls.parentNode === mainline;
                const alreadyPlaced = !!(
                    alreadyInMainline && (
                        (label && budgetControls.nextSibling === label) ||
                        (!label && mainline.contains(budgetControls))
                    )
                );
                if (!alreadyPlaced) {
                    if (label) mainline.insertBefore(budgetControls, label);
                    else if (!alreadyInMainline) mainline.appendChild(budgetControls);
                }
            }
        } catch (_ePos) {}

        let el = grid.querySelector ? grid.querySelector('.gigma-row-stats') : null;
        if (!el) {
            el = document.createElement('div');
            el.className = 'gigma-row-stats';
            grid.appendChild(el);
        }
        return el;
    } catch {
        return null;
    }
}

function gigmaGetModalLorebookStatsLayoutWidthEm(el) {
    try {
        if (!el || !el.isConnected) return 0;
        const rect = (typeof el.getBoundingClientRect === 'function') ? el.getBoundingClientRect() : null;
        const widthPx = Math.max(0, (rect && Number.isFinite(rect.width)) ? rect.width : (el.clientWidth || 0));
        if (!(widthPx > 0)) return 0;
        const cs = window.getComputedStyle ? window.getComputedStyle(el) : null;
        const fontPx = cs ? (parseFloat(cs.fontSize || '0') || 0) : 0;
        if (!(fontPx > 0)) return 0;
        return widthPx / fontPx;
    } catch {
        return 0;
    }
}

function gigmaGetModalLorebookStatsColumnGapEm(el) {
    try {
        if (!el || !window.getComputedStyle) return 0;
        const cs = window.getComputedStyle(el);
        const fontPx = parseFloat(cs.fontSize || '0') || 0;
        if (!(fontPx > 0)) return 0;
        const gapPx = parseFloat(cs.columnGap || cs.gap || '0') || 0;
        return gapPx / fontPx;
    } catch {
        return 0;
    }
}

function gigmaGetModalLorebookStatsTheoreticalRootWidthEm(fallbackEl) {
    try {
        const list = document.getElementById('gigma-ordering-list') || document.getElementById('gigma-ordering-container') || document.getElementById('gigma-modal-root');
        if (list) {
            const rect = (typeof list.getBoundingClientRect === 'function') ? list.getBoundingClientRect() : null;
            const widthPx = Math.max(0, (rect && Number.isFinite(rect.width)) ? rect.width : (list.clientWidth || 0));
            if (widthPx > 0) {
                const refEl = fallbackEl || list;
                const cs = window.getComputedStyle ? window.getComputedStyle(refEl) : null;
                const fontPx = cs ? (parseFloat(cs.fontSize || '0') || 0) : 0;
                if (fontPx > 0) return widthPx / fontPx;
            }
        }
    } catch (_e) { }
    return gigmaGetModalLorebookStatsLayoutWidthEm(fallbackEl);
}

function gigmaRecomputeModalLorebookStatsTargetCountCache(fallbackEl) {
    try {
        const preferredColEm = 8; // 5em content + 3em buffer target
        const gapEm = gigmaGetModalLorebookStatsColumnGapEm(fallbackEl);
        const rootWidthEm = gigmaGetModalLorebookStatsTheoreticalRootWidthEm(fallbackEl);
        const nTarget = Math.max(1, Math.floor((rootWidthEm + gapEm) / (preferredColEm + gapEm)));
        window.__gigmaModalLorebookStatsTargetCountCache = {
            nTarget,
            rootWidthEm,
            gapEm,
        };
        return nTarget;
    } catch (_e) { }
    return 1;
}

function gigmaGetModalLorebookStatsTargetCount(fallbackEl) {
    try {
        const cached = window.__gigmaModalLorebookStatsTargetCountCache;
        if (cached && Number.isFinite(cached.nTarget) && cached.nTarget > 0) return cached.nTarget;
    } catch (_e) { }
    return gigmaRecomputeModalLorebookStatsTargetCountCache(fallbackEl);
}

function gigmaQueueModalLorebookStatsAffectedLorebooks(nodes) {
    try {
        if (!nodes) return;
        const queue = window.__gigmaModalLorebookStatsAffectedLorebooks || (window.__gigmaModalLorebookStatsAffectedLorebooks = new Set());
        const pushNode = (node) => {
            try {
                if (!node || !(node instanceof HTMLElement)) return;
                if (node.classList && node.classList.contains('gigma-row') && node.dataset && node.dataset.world) {
                    queue.add(node);
                }
                const rows = node.querySelectorAll ? node.querySelectorAll('.gigma-row[data-world]') : [];
                for (const row of rows) queue.add(row);
            } catch (_e) { }
        };
        if (nodes instanceof HTMLElement) {
            pushNode(nodes);
            return;
        }
        if (Array.isArray(nodes) || (typeof nodes[Symbol.iterator] === 'function')) {
            for (const node of nodes) pushNode(node);
        }
    } catch (_e) { }
}

function gigmaFlushQueuedModalLorebookStatsAffectedLorebooks() {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        if (!EXTENSION_STATE?.modalLorebookStatsEnabled) return;
        const queue = window.__gigmaModalLorebookStatsAffectedLorebooks;
        if (!(queue && typeof queue.forEach === 'function' && queue.size > 0)) return;
        queue.forEach((row) => {
            try {
                if (!row || !row.isConnected) return;
                const host = row.querySelector ? row.querySelector(':scope > .gigma-row-header-grid > .gigma-row-stats') : null;
                if (host) gigmaApplyModalLorebookStatsColumnCount(host);
            } catch (_e) { }
        });
        try { queue.clear(); } catch (_e) { window.__gigmaModalLorebookStatsAffectedLorebooks = new Set(); }
    } catch (_e) { }
}

function gigmaGetOrderingModalStatsRoot() {
    try {
        return document.getElementById('gigma-ordering-container') || document.getElementById('gigma-modal-root') || null;
    } catch (_e) { }
    return null;
}

function gigmaGetModalLorebookStatsRows(forceRefresh = false) {
    try {
        if (!forceRefresh && Array.isArray(window.__gigmaModalLorebookStatsRowsCache)) {
            return window.__gigmaModalLorebookStatsRowsCache;
        }
        const root = gigmaGetOrderingModalStatsRoot();
        const rows = root && root.querySelectorAll ? Array.from(root.querySelectorAll('.gigma-row[data-world]')) : [];
        window.__gigmaModalLorebookStatsRowsCache = rows;
        return rows;
    } catch (_e) { }
    return [];
}


function gigmaGetModalLorebookStatsRefreshRows(forceRefresh = false) {
    const rows = gigmaGetModalLorebookStatsRows(forceRefresh);
    if (!gigmaIsMobileLargeLorebookPerfMode()) return rows;

    try {
        const visible = window.__gigmaVisibleModalLorebookStatsRows;
        if (visible && typeof visible.forEach === 'function' && visible.size > 0) {
            const out = [];
            visible.forEach((row) => {
                if (row && row.isConnected && row.dataset && row.dataset.world) out.push(row);
            });
            if (out.length) return out;
        }
    } catch (_e) { }

    return rows.filter((row) => row && row.isConnected && row.dataset && row.dataset.world).slice(0, 40);
}

function gigmaObserveModalLorebookStatsRow(row) {
    try {
        if (!row || !row.isConnected || !row.dataset || !row.dataset.world) return;
        gigmaBindModalLorebookStatsObserversOnce();
        const io = window.__gigmaModalLorebookStatsIo;
        if (!io) return;
        let observed = window.__gigmaObservedModalLorebookStatsRows;
        if (!(observed && typeof observed.has === 'function' && typeof observed.add === 'function')) {
            observed = new WeakSet();
            window.__gigmaObservedModalLorebookStatsRows = observed;
        }
        if (observed.has(row)) return;
        observed.add(row);
        io.observe(row);
    } catch (_e) { }
}

function gigmaObserveModalLorebookStatsRows(forceRefresh = false) {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        const rows = gigmaGetModalLorebookStatsRows(!!forceRefresh);
        if (!rows.length) return;
        let index = 0;
        const batchSize = gigmaIsMobileLargeLorebookPerfMode() ? 60 : 200;
        const step = () => {
            try {
                if (!gigmaIsOrderingModalActive()) return;
                const end = Math.min(index + batchSize, rows.length);
                for (; index < end; index += 1) {
                    gigmaObserveModalLorebookStatsRow(rows[index]);
                }
                if (index < rows.length) {
                    window.__gigmaModalLorebookStatsObserveTimer = setTimeout(step, gigmaIsMobileLargeLorebookPerfMode() ? 16 : 0);
                } else {
                    window.__gigmaModalLorebookStatsObserveTimer = 0;
                }
            } catch (_e) {
                window.__gigmaModalLorebookStatsObserveTimer = 0;
            }
        };
        if (window.__gigmaModalLorebookStatsObserveTimer) return;
        step();
    } catch (_e) { }
}

function gigmaBindModalLorebookStatsObserversOnce() {
    try {
        if (window.__gigmaModalLorebookStatsIo) return;
        let visibleRows = window.__gigmaVisibleModalLorebookStatsRows;
        if (!(visibleRows && typeof visibleRows.add === 'function' && typeof visibleRows.delete === 'function')) {
            visibleRows = new Set();
            window.__gigmaVisibleModalLorebookStatsRows = visibleRows;
        }
        window.__gigmaModalLorebookStatsIo = new IntersectionObserver((entries) => {
            try {
                let changed = false;
                for (const entry of entries) {
                    const row = entry && entry.target;
                    if (!row || !row.isConnected) continue;
                    if (entry.isIntersecting) {
                        visibleRows.add(row);
                    } else {
                        visibleRows.delete(row);
                    }
                    changed = true;
                }
                if (changed) gigmaScheduleModalLorebookStatsRefresh();
            } catch (_e) { }
        }, {
            root: null,
            rootMargin: '160px 0px 160px 0px',
            threshold: 0,
        });
    } catch (_e) { }
}

function gigmaQueueModalLorebookStatsBuild(worldName) {
    try {
        const key = String(worldName || '').trim();
        if (!key) return;
        let queue = window.__gigmaModalLorebookStatsBuildQueue;
        if (!Array.isArray(queue)) {
            queue = [];
            window.__gigmaModalLorebookStatsBuildQueue = queue;
        }
        let pending = window.__gigmaModalLorebookStatsBuildPending;
        if (!(pending && typeof pending.has === 'function' && typeof pending.add === 'function' && typeof pending.delete === 'function')) {
            pending = new Set();
            window.__gigmaModalLorebookStatsBuildPending = pending;
        }
        if (pending.has(key)) return;
        pending.add(key);
        queue.push(key);
        gigmaScheduleModalLorebookStatsBuildQueue();
    } catch (_e) { }
}

async function gigmaDrainModalLorebookStatsBuildQueue() {
    try {
        if (window.__gigmaModalLorebookStatsBuildActive) return;
        window.__gigmaModalLorebookStatsBuildActive = true;
        const queue = Array.isArray(window.__gigmaModalLorebookStatsBuildQueue) ? window.__gigmaModalLorebookStatsBuildQueue : [];
        const pending = window.__gigmaModalLorebookStatsBuildPending;
        while (queue.length && gigmaIsOrderingModalActive() && !!EXTENSION_STATE.modalLorebookStatsEnabled) {
            const key = String(queue.shift() || '').trim();
            if (!key) continue;
            try {
                await gigmaGetLorebookStats(key);
            } catch (_eItem) { }
            try { if (pending && typeof pending.delete === 'function') pending.delete(key); } catch (_eDelete) { }
            gigmaScheduleModalLorebookStatsRefresh();
            try { gigmaRefreshLayoutPresetTreePreviewLorebookRowsByWorldName(key); } catch (_ePreviewRefresh) { }
            break;
        }
    } catch (_e) { }
    finally {
        window.__gigmaModalLorebookStatsBuildActive = false;
        const queue = Array.isArray(window.__gigmaModalLorebookStatsBuildQueue) ? window.__gigmaModalLorebookStatsBuildQueue : [];
        if (queue.length && gigmaIsOrderingModalActive() && !!EXTENSION_STATE.modalLorebookStatsEnabled) {
            gigmaScheduleModalLorebookStatsBuildQueue();
        }
    }
}

function gigmaScheduleModalLorebookStatsBuildQueue() {
    try {
        if (window.__gigmaModalLorebookStatsBuildActive) return;
        if (window.__gigmaModalLorebookStatsBuildTimer || window.__gigmaModalLorebookStatsBuildIdle) return;
        const run = () => {
            window.__gigmaModalLorebookStatsBuildTimer = 0;
            window.__gigmaModalLorebookStatsBuildIdle = 0;
            gigmaDrainModalLorebookStatsBuildQueue();
        };
        if (window.requestIdleCallback) {
            window.__gigmaModalLorebookStatsBuildIdle = window.requestIdleCallback(run, { timeout: 250 });
            return;
        }
        window.__gigmaModalLorebookStatsBuildTimer = setTimeout(run, 16);
    } catch (_e) { }
}

function gigmaRefreshVisibleModalLorebookStats() {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        const root = gigmaGetOrderingModalStatsRoot();
        if (!root) return;

        if (!EXTENSION_STATE.modalLorebookStatsEnabled || gigmaGetLorebookStatsDisplayCollapsed('modal')) {
            const hosts = root.querySelectorAll ? root.querySelectorAll('.gigma-row-header-grid > .gigma-row-stats') : [];
            hosts.forEach((host) => {
                try {
                    host.classList.add('gigma-hidden');
                    host.textContent = '';
                } catch (_eHost) { }
            });
            return;
        }

        const rows = gigmaGetModalLorebookStatsRefreshRows(false);
        for (const row of rows) {
            try {
                if (!row || !row.isConnected || !row.dataset || !row.dataset.world) continue;
                gigmaUpdateModalLorebookRowStats(row);
            } catch (_eRow) { }
        }
    } catch (_e) { }
}

function gigmaScheduleModalLorebookStatsRefresh(forceRefresh = false) {
    try {
        if (forceRefresh) {
            try { window.__gigmaModalLorebookStatsRowsCache = null; } catch (_eCache) { }
        }
        if (window.__gigmaModalLorebookStatsRefreshRaf) return;
        window.__gigmaModalLorebookStatsRefreshRaf = requestAnimationFrame(() => {
            window.__gigmaModalLorebookStatsRefreshRaf = 0;
            gigmaRefreshVisibleModalLorebookStats();
        });
    } catch (_e) { }
}

function gigmaApplyModalLorebookStatsColumnCount(el) {
    try {
        if (!el || !el.isConnected) return;
        const chips = el.querySelectorAll ? el.querySelectorAll('.gigma-row-stat-chip') : [];
        const chipCount = chips ? chips.length : 0;
        if (!(chipCount > 0)) {
            try { el.style.removeProperty('--gigma-row-stats-cols'); } catch (_e) { }
            return;
        }
        const nTarget = Math.max(1, Number(gigmaGetModalLorebookStatsTargetCount(el)) || 1);
        el.style.setProperty('--gigma-row-stats-cols', String(nTarget));
    } catch (_e) { }
}

function gigmaUpdateModalLorebookStatsColumnCountsAllRows() {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        const root = gigmaGetOrderingModalStatsRoot() || document;
        let hosts = [];
        if (gigmaIsMobileLargeLorebookPerfMode()) {
            const rows = gigmaGetModalLorebookStatsRefreshRows(false);
            hosts = rows.map((row) => row && row.querySelector ? row.querySelector(':scope > .gigma-row-header-grid > .gigma-row-stats') : null).filter(Boolean);
        } else {
            hosts = root.querySelectorAll ? root.querySelectorAll('.gigma-row[data-world] > .gigma-row-header-grid > .gigma-row-stats') : [];
        }
        const firstHost = (hosts && hosts.length) ? hosts[0] : root;
        gigmaRecomputeModalLorebookStatsTargetCountCache(firstHost);
        hosts.forEach((el) => gigmaApplyModalLorebookStatsColumnCount(el));
    } catch (_e) { }
}

(function gigmaBindModalLorebookStatsColumnResizeOnce(){
    try {
        if (window.__gigmaModalLorebookStatsColsResizeBound) return;
        window.__gigmaModalLorebookStatsColsResizeBound = true;
        window.addEventListener('resize', () => {
            try { window.__gigmaModalLorebookStatsTargetCountCache = null; } catch (_e) { }
            try { gigmaUpdateModalLorebookStatsColumnCountsAllRows(); } catch (_e) { }
            try {
                const container = document.getElementById('gigma-global-wi-stats-display-modal');
                if (container) gigmaApplyGlobalWiStatsColumnCount(container);
            } catch (_e) { }
        }, { passive: true });
    } catch (_e) { }
})();

function gigmaRenderLorebookStatsSectionInto(el, stats, sectionKey) {
    if (!el) return 0;

    const showEntries = !!EXTENSION_STATE.modalLorebookStatsShowEntries;
    const showTokens = !!EXTENSION_STATE.modalLorebookStatsShowTokens;
    const labelByKey = new Map(GIGMA_MODAL_STATS_CATEGORIES.map(c => [c.key, c.label]));
    const items = gigmaGetStatsDisplayItems(stats, {
        sectionKey,
        categorySet: gigmaGetModalLorebookStatsCategorySet(),
        showEntries,
        showTokens,
        removeIrrelevantCategories: !!EXTENSION_STATE.modalLorebookStatsRemoveIrrelevantCategories,
        removeZeroTokenCategories: !!EXTENSION_STATE.modalLorebookStatsRemoveZeroTokenCategories,
        labelByKey,
    });
    const frag = document.createDocumentFragment();
    const chipsFrag = document.createDocumentFragment();

    let count = 0;
    for (const item of items) {
        if (!item) continue;
        chipsFrag.appendChild(gigmaCreateStatChip(item.label || item.key || '', item.value || '', (showEntries && showTokens ? 'Entries/Tokens' : (showEntries ? 'Entries' : (showTokens ? 'Tokens' : ''))), '', '', null, '', ''));
        count += 1;
    }

    if (count > 0) {
        frag.appendChild(gigmaCreateGlobalWiStatsSectionLabelChip(gigmaGetGlobalWiStatsSectionTitle(sectionKey), ''));
        frag.appendChild(chipsFrag);
        count += 1;
    }

    el.replaceChildren(frag);
    if (count > 0) el.classList.remove('gigma-hidden');
    else el.classList.add('gigma-hidden');
    return count;
}

function gigmaRenderLorebookStatsInto(el, rawStats, worldName) {
    if (!el) return;
    const enabled = !!EXTENSION_STATE.modalLorebookStatsEnabled;
    const collapsed = !!((el.closest && el.closest('#gigma-layout-preset-tree-preview-root'))
        ? gigmaGetLorebookStatsDisplayCollapsed('preview')
        : gigmaGetLorebookStatsDisplayCollapsed('modal'));

    if (!enabled || collapsed) {
        el.classList.add('gigma-hidden');
        el.textContent = '';
        return;
    }

    const sections = [];
    const world = String(worldName || '').trim();
    const snapshotPair = EXTENSION_STATE.modalLorebookStatsLastWiSnapshotPair;

    if (gigmaIsModalLorebookStatsRawSectionEnabled()) {
        sections.push({ key: 'raw', stats: rawStats });
    }

    if (gigmaIsModalLorebookStatsActivatedSectionEnabled()) {
        sections.push({ key: 'activated', stats: snapshotPair ? gigmaGetLastModalLorebookStatsSnapshotByWorld('activated', world) : gigmaCreateEmptyLorebookStatsObject() });
    }

    if (gigmaIsModalLorebookStatsIncludedSectionEnabled()) {
        sections.push({ key: 'included', stats: snapshotPair ? gigmaGetLastModalLorebookStatsSnapshotByWorld('included', world) : gigmaCreateEmptyLorebookStatsObject() });
    }

    if (!sections.length) {
        el.classList.add('gigma-hidden');
        el.textContent = '';
        return;
    }

    const frag = document.createDocumentFragment();
    let totalChipCount = 0;

    for (const section of sections) {
        const sec = document.createElement('div');
        sec.className = 'gigma-row-stats-section';
        sec.setAttribute('data-gigma-stats-section', section.key);
        const n = gigmaRenderLorebookStatsSectionInto(sec, section.stats, section.key);
        if (n > 0) {
            frag.appendChild(sec);
            totalChipCount += n;
        }
    }

    el.replaceChildren(frag);
    if (totalChipCount > 0) {
        try { gigmaApplyModalLorebookStatsColumnCount(el); } catch (_eStatsCols) { }
        el.classList.remove('gigma-hidden');
    } else {
        el.classList.add('gigma-hidden');
    }
}

function gigmaUpdateModalLorebookRowStats(row) {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        if (!row || !row.dataset) return;
        const worldName = String(row.dataset.world || '').trim();
        if (!worldName) return;

        let host = row.querySelector ? row.querySelector(':scope > .gigma-row-header-grid > .gigma-row-stats') : null;

        if (row.classList && row.classList.contains('gigma-parent-unchained-placeholder')) {
            const asSel = gigmaGetParentUnchainedAsSelect();
            const asMode = (asSel && typeof asSel.value === 'string') ? asSel.value.trim() : '';
            if (asMode === 'text between lorebooks') {
                if (host) gigmaRenderLorebookStatsInto(host, null, worldName);
                return;
            }
        }

        if (!EXTENSION_STATE.modalLorebookStatsEnabled || gigmaGetLorebookStatsDisplayCollapsed('modal')) {
            if (host) gigmaRenderLorebookStatsInto(host, null);
            return;
        }

        host = host || gigmaEnsureModalRowStatsHost(row);
        if (!host) return;

        let stats = gigmaGetLorebookStatsIndexStatsByWorldName(worldName);
        if (!stats) {
            const cached = GIGMA_MODAL_LOREBOOK_STATS_CACHE.get(worldName);
            if (cached && cached.stats) stats = cached.stats;
        }

        if (!stats && gigmaIsModalLorebookStatsRawSectionEnabled()) {
            gigmaQueueModalLorebookStatsBuild(worldName);
        }

        gigmaRenderLorebookStatsInto(host, stats || null, worldName);
    } catch (_e) { }
}

function gigmaUpdateModalLorebookStatsAllRows() {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        const rows = gigmaIsMobileLargeLorebookPerfMode()
            ? gigmaGetModalLorebookStatsRefreshRows(true)
            : gigmaGetModalLorebookStatsRows(true);
        for (const row of rows) {
            try {
                if (!row || !row.isConnected || !row.dataset || !row.dataset.world) continue;
                gigmaEnsureModalRowStatsHost(row);
            } catch (_eHost) { }
        }
        for (const row of rows) {
            try {
                if (!row || !row.isConnected || !row.dataset || !row.dataset.world) continue;
                gigmaUpdateModalLorebookRowStats(row);
            } catch (_eRow) { }
        }
        try { gigmaUpdateModalLorebookStatsColumnCountsAllRows(); } catch (_eCols) { }
    } catch (_e) { }
}

function gigmaMaybeAttachModalLorebookStats(labelEl, worldName) {
    try {
        if (!labelEl || !worldName) return;
        if (!EXTENSION_STATE.modalLorebookStatsEnabled) return;
        const root = labelEl.closest && labelEl.closest('#gigma-modal-root');
        if (!root) return;
        const row = labelEl.closest && labelEl.closest('.gigma-row');
        if (!row) return;
        if (gigmaIsMobileLargeLorebookPerfMode()) {
            gigmaObserveModalLorebookStatsRow(row);
            const visible = window.__gigmaVisibleModalLorebookStatsRows;
            if (!(visible && typeof visible.has === 'function' && visible.has(row))) return;
        }
        gigmaEnsureModalRowStatsHost(row);
        gigmaUpdateModalLorebookRowStats(row);
    } catch (_e) { }
}

function gigmaUpdateOrderingModalStatsControlsUi() {
    try {
        const pairs = [
            ['gigma-modal-stats-toggle', !!EXTENSION_STATE.modalLorebookStatsEnabled],
            ['gigma-modal-stats-toggle-right', !!EXTENSION_STATE.modalLorebookStatsEnabled],
            ['gigma-modal-stats-entries', !!EXTENSION_STATE.modalLorebookStatsShowEntries],
            ['gigma-modal-stats-entries-right', !!EXTENSION_STATE.modalLorebookStatsShowEntries],
            ['gigma-modal-stats-tokens', !!EXTENSION_STATE.modalLorebookStatsShowTokens],
            ['gigma-modal-stats-tokens-right', !!EXTENSION_STATE.modalLorebookStatsShowTokens],
            ['gigma-modal-stats-section-raw', !!EXTENSION_STATE.modalLorebookStatsSectionRaw],
            ['gigma-modal-stats-section-raw-right', !!EXTENSION_STATE.modalLorebookStatsSectionRaw],
            ['gigma-modal-stats-section-activated', !!EXTENSION_STATE.modalLorebookStatsSectionActivated],
            ['gigma-modal-stats-section-activated-right', !!EXTENSION_STATE.modalLorebookStatsSectionActivated],
            ['gigma-modal-stats-section-included', !!EXTENSION_STATE.modalLorebookStatsSectionIncluded],
            ['gigma-modal-stats-section-included-right', !!EXTENSION_STATE.modalLorebookStatsSectionIncluded],
        ];
        for (const [id, on] of pairs) {
            const b = document.getElementById(id);
            if (b) b.setAttribute('aria-pressed', on ? 'true' : 'false');
        }

        const loreExpanded = !gigmaGetLorebookStatsDisplayCollapsed('modal');
        const loreBtnPairs = [
            [document.getElementById('gigma-modal-stats-cats'), document.getElementById('gigma-modal-stats-collapse')],
            [document.getElementById('gigma-modal-stats-cats-right'), document.getElementById('gigma-modal-stats-collapse-right')]
        ];
        const loreEnabled = !!EXTENSION_STATE.modalLorebookStatsEnabled;
        const loreShowCollapseButton = gigmaGetStatsCollapseButtonVisible('modal', 'lorebook');
        for (const [mainBtn, collapseBtn] of loreBtnPairs) {
            gigmaSyncStatsButtonPairUi(mainBtn, collapseBtn, loreEnabled, loreExpanded, 'Lorebook Stats', loreShowCollapseButton);
        }

        const set = gigmaGetModalLorebookStatsCategorySet();
        const panels = [
            document.getElementById('gigma-modal-stats-panel'),
            document.getElementById('gigma-modal-stats-panel-right')
        ].filter(Boolean);
        for (const panel of panels) {
            const sw = panel.querySelector('input[type="checkbox"][data-gigma-lore-switch="1"]');
            if (sw) sw.checked = !!EXTENSION_STATE.modalLorebookStatsEnabled;
            const collapseSw = panel.querySelector('input[type="checkbox"][data-gigma-lore-collapse-switch="1"]');
            if (collapseSw) collapseSw.checked = gigmaGetStatsCollapseButtonVisible('modal', 'lorebook');
            const removeIrrelevantSw = panel.querySelector('input[type="checkbox"][data-gigma-lore-remove-irrelevant-switch="1"]');
            if (removeIrrelevantSw) removeIrrelevantSw.checked = !!EXTENSION_STATE.modalLorebookStatsRemoveIrrelevantCategories;
            const removeZeroTokensSw = panel.querySelector('input[type="checkbox"][data-gigma-lore-remove-zero-tokens-switch="1"]');
            if (removeZeroTokensSw) removeZeroTokensSw.checked = !!EXTENSION_STATE.modalLorebookStatsRemoveZeroTokenCategories;
            panel.querySelectorAll('input[type="checkbox"][data-gigma-cat]').forEach((cb) => {
                const k = cb.getAttribute('data-gigma-cat');
                cb.checked = !!(k && set.has(k));
            });
        }
        gigmaUpdateManualUsageRefreshButtonsUi();
    } catch (_e) { }
}


function gigmaEnsureModalGlobalWiStatsPlacement(rootOverride, refreshBtnOverride, btnOverride, panelOverride, collapseBtnOverride){
    try{
        const root = rootOverride || document.getElementById('gigma-modal-root');
        if (!root) return;

        const refreshBtn = refreshBtnOverride || document.getElementById('gigma-modal-ordering-refresh');
        const btn = btnOverride || document.getElementById('gigma-modal-global-wi-stats');
        const panel = panelOverride || document.getElementById('gigma-modal-global-wi-stats-panel');
        const collapseBtn = collapseBtnOverride || document.getElementById('gigma-modal-global-wi-stats-collapse');
        const previewBtn = root.querySelector('#gigma-ordering-preview');

        if (!btn || !panel || !previewBtn || !previewBtn.parentNode) return;

        let host = root.querySelector('#gigma-ordering-gwi-host');
        if (!host){
            host = document.createElement('div');
            host.id = 'gigma-ordering-gwi-host';
            host.className = 'gigma-ordering-gwi-host';
            try{
                host.style.position = 'relative';
                host.style.display = 'inline-flex';
                host.style.alignItems = 'center';
                host.style.justifyContent = 'center';
                host.style.gap = '0.25em';
            }catch(_e){}
        }

        const row = previewBtn.parentNode;
        if (host.parentNode !== row) row.insertBefore(host, previewBtn);
        else if (host.nextSibling !== previewBtn) row.insertBefore(host, previewBtn);

        if (refreshBtn && refreshBtn.parentNode !== host) host.appendChild(refreshBtn);
        if (btn.parentNode !== host) host.appendChild(btn);
        if (collapseBtn && collapseBtn.parentNode !== host) host.appendChild(collapseBtn);
        if (panel.parentNode !== host) host.appendChild(panel);
    }catch(_e){}
}

function gigmaInitOrderingModalStatsUi(modalEventListeners = []) {
    try {
        if (!gigmaIsOrderingModalActive()) return;
        const root = document.getElementById('gigma-modal-root');
        if (!root) return;

        const modalScroll = root.querySelector('#gigma-modal-scroll');

        const mkBtn = (id, text, title) => {
            const b = document.createElement('button');
            b.type = 'button';
            b.id = id;
            b.className = 'menu_button';
            b.textContent = text;
            if (title) {
                b.title = title;
                b.setAttribute('aria-label', title);
            }
            return b;
        };

        
const ensure = (toolbarSelector, suffix) => {
    try {
        const toolbar = root.querySelector(toolbarSelector);
        if (!toolbar) return;
        const btnGuardId = 'gigma-modal-stats-cats' + suffix;
        if (document.getElementById(btnGuardId)) {
            if (!suffix) { try{ gigmaEnsureModalGlobalWiStatsPlacement(root); }catch(_e){} }
            return;
        }

        const group = toolbar.querySelector('.gigma-toolbar-group') || toolbar;
        const host = document.createElement('div');
        host.className = 'gigma-modal-stats-controls';
        const btnRefresh = mkBtn('gigma-modal-stats-refresh' + suffix, 'Gen', 'Refresh Activated/Included values with a dry WI scan');
        btnRefresh.setAttribute('data-gigma-idle-text', 'Gen');

        // Global WI statistics button (single instance). We place it next to the modal Preview button.
        const wantGlobalWi = (suffix === '');
        let btnGlobalWi = null;
        let btnGlobalWiCollapse = null;
        let btnOrderingRefresh = null;
        if (wantGlobalWi) {
            btnOrderingRefresh = mkBtn('gigma-modal-ordering-refresh' + suffix, 'Gen', 'Refresh Activated/Included values with a dry WI scan');
            btnOrderingRefresh.setAttribute('data-gigma-idle-text', 'Gen');
            btnOrderingRefresh.addEventListener('click', (ev) => {
                try { ev.preventDefault(); ev.stopPropagation(); } catch (_eStop) { }
                scheduleBackground(() => gigmaRefreshLastGenerationUsageSnapshot({ source: 'modal-ordering-row' }));
            });
            btnGlobalWi = mkBtn('gigma-modal-global-wi-stats' + suffix, '', 'Global WI statistics');
            try { btnGlobalWi.classList.add('gigma-icon-btn', 'gigma-global-wi-stats-btn'); } catch (_e) {}
            btnGlobalWi.innerHTML = GIGMA_GLOBAL_WI_STATS_ICON_HTML;
            btnGlobalWi.setAttribute('aria-expanded', 'false');
            btnGlobalWiCollapse = document.createElement('button');
            btnGlobalWiCollapse.id = 'gigma-modal-global-wi-stats-collapse';
            gigmaUpdateStatsCollapseButtonUi(btnGlobalWiCollapse, !gigmaGetGlobalWiStatsDisplayCollapsed('modal'), 'Global WI Statistics');
        }

        const btnEnt = mkBtn('gigma-modal-stats-entries' + suffix, 'Entries', 'Toggle entry counts');
        const btnTok = mkBtn('gigma-modal-stats-tokens' + suffix, 'Tokens', 'Toggle token counts');
        const btnCats = mkBtn('gigma-modal-stats-cats' + suffix, '', 'Lorebook Stats');
        try { btnCats.classList.add('gigma-icon-btn', 'gigma-global-wi-stats-btn', 'gigma-lorebook-stats-btn'); } catch (_e) {}
        btnCats.innerHTML = GIGMA_LOREBOOK_STATS_ICON_HTML;
        btnCats.setAttribute('aria-expanded', 'false');
        const btnCatsCollapse = document.createElement('button');
        btnCatsCollapse.id = 'gigma-modal-stats-collapse' + suffix;
        gigmaUpdateStatsCollapseButtonUi(btnCatsCollapse, !gigmaGetLorebookStatsDisplayCollapsed('modal'), 'Lorebook Stats');

        // Cats panel (existing)
        const panelCats = document.createElement('div');
        panelCats.id = 'gigma-modal-stats-panel' + suffix;
        panelCats.className = 'gigma-modal-stats-panel gigma-lorebook-stats-panel gigma-hidden';
        panelCats.setAttribute('aria-hidden', 'true');
        gigmaEnsureMobileFullscreenDropdownShell(panelCats, 'Close Lorebook statistics');

        const headCats = document.createElement('div');
        headCats.className = 'gigma-gwi-panel-headrow';

        const titleCats = document.createElement('div');
        titleCats.className = 'gigma-global-wi-stats-panel-title';
        titleCats.textContent = 'Lorebook Statistics';

        const switchLabelCats = document.createElement('label');
        switchLabelCats.className = 'gigma-gwi-pretty-switch';
        switchLabelCats.title = 'Toggle Lorebook Stats display';
        const swCats = document.createElement('input');
        swCats.type = 'checkbox';
        swCats.setAttribute('data-gigma-lore-switch', '1');
        swCats.setAttribute('aria-label', 'Toggle Lorebook Stats display');
        const trackCats = document.createElement('span');
        trackCats.className = 'gigma-gwi-pretty-switch-track';
        const thumbCats = document.createElement('span');
        thumbCats.className = 'gigma-gwi-pretty-switch-thumb';
        trackCats.appendChild(thumbCats);
        switchLabelCats.appendChild(swCats);
        switchLabelCats.appendChild(trackCats);

        headCats.appendChild(titleCats);
        headCats.appendChild(switchLabelCats);
        panelCats.appendChild(headCats);

        const collapseSwitchRowCats = gigmaCreateStatsPanelSwitchRow('Show Expand/Collapse button', 'data-gigma-lore-collapse-switch', '1', 'Show Expand/Collapse button', 'Show Expand/Collapse button');
        panelCats.appendChild(collapseSwitchRowCats.row);

        const removeIrrelevantSwitchRowCats = gigmaCreateStatsPanelSwitchRow('Remove irrelevant categories', 'data-gigma-lore-remove-irrelevant-switch', '1', 'Remove irrelevant categories', 'Remove irrelevant categories');
        panelCats.appendChild(removeIrrelevantSwitchRowCats.row);

        const removeZeroTokensSwitchRowCats = gigmaCreateStatsPanelSwitchRow('Remove 0 tokens categories', 'data-gigma-lore-remove-zero-tokens-switch', '1', 'Remove 0 tokens categories', 'Remove 0 tokens categories');
        panelCats.appendChild(removeZeroTokensSwitchRowCats.row);

        const countRowCats = document.createElement('div');
        countRowCats.className = 'gigma-modal-stats-panel-actions';
        countRowCats.appendChild(btnEnt);
        countRowCats.appendChild(btnTok);
        panelCats.appendChild(countRowCats);

        const set = gigmaGetModalLorebookStatsCategorySet();
        const list = document.createElement('div');
        list.className = 'gigma-modal-stats-panel-list';

        const sectionToggles = document.createElement('div');
        sectionToggles.className = 'gigma-modal-stats-panel-actions';
        const btnRaw = mkBtn('gigma-modal-stats-section-raw' + suffix, 'Raw', 'Toggle Raw stats section');
        const btnActivated = mkBtn('gigma-modal-stats-section-activated' + suffix, 'Activated', 'Toggle Activated stats section');
        const btnIncluded = mkBtn('gigma-modal-stats-section-included' + suffix, 'Included', 'Toggle Included stats section');
        sectionToggles.appendChild(btnRaw);
        sectionToggles.appendChild(btnActivated);
        sectionToggles.appendChild(btnIncluded);

        const actions = document.createElement('div');
        actions.className = 'gigma-modal-stats-panel-actions';
        const btnAll = mkBtn('gigma-modal-stats-all' + suffix, 'All', 'Show all categories');
        const btnNone = mkBtn('gigma-modal-stats-none' + suffix, 'None', 'Hide all categories');
        actions.appendChild(btnAll);
        actions.appendChild(btnNone);

        for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
            const row = document.createElement('label');
            row.className = 'gigma-modal-stats-panel-item';
            const cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.setAttribute('data-gigma-cat', c.key);
            cb.checked = set.has(c.key);
            const span = document.createElement('span');
            span.innerHTML = c.menuHtml;
            row.appendChild(cb);
            row.appendChild(span);
            list.appendChild(row);
        }

        panelCats.appendChild(sectionToggles);
        panelCats.appendChild(actions);
        panelCats.appendChild(list);

        // Global WI stats panel (single instance)
        let panelGlobal = null;
        if (wantGlobalWi) {
            panelGlobal = document.createElement('div');
            panelGlobal.id = 'gigma-modal-global-wi-stats-panel' + suffix;
            panelGlobal.className = 'gigma-modal-stats-panel gigma-hidden';
            panelGlobal.setAttribute('aria-hidden', 'true');
            gigmaBuildGlobalWiStatsPanel(panelGlobal, 'modal');
        }

        host.appendChild(btnRefresh);
        host.appendChild(btnCats);
        host.appendChild(btnCatsCollapse);
        host.appendChild(panelCats);

        // Place Global WI stats button/panel next to the modal Preview button (left of it).
        if (wantGlobalWi && btnGlobalWi && panelGlobal) {
            try { gigmaEnsureModalGlobalWiStatsPlacement(root, btnOrderingRefresh, btnGlobalWi, panelGlobal, btnGlobalWiCollapse); } catch (_e) { }
        }

        group.appendChild(host);

        const updatePanelMaxHeight = (panelEl, btnEl) => {
            try {
                if (!modalScroll || !panelEl || panelEl.classList.contains('gigma-hidden')) return;
                const scRect = modalScroll.getBoundingClientRect();
                const dir = (panelEl.dataset && panelEl.dataset.gigmaOpenDir) ? panelEl.dataset.gigmaOpenDir : 'down';
                let maxH = 0;

                if (dir === 'up' && btnEl) {
                    const bRect = btnEl.getBoundingClientRect();
                    maxH = Math.max(0, bRect.top - scRect.top - 8);
                } else {
                    const pRect = panelEl.getBoundingClientRect();
                    maxH = Math.max(0, scRect.bottom - pRect.top - 8);
                }
                panelEl.style.maxHeight = maxH + 'px';
            } catch (_e) { }
        };

        const closeCats = () => {
            try {
                panelCats.classList.add('gigma-hidden');
                panelCats.setAttribute('aria-hidden', 'true');
                btnCats.setAttribute('aria-expanded', 'false');
            } catch (_e) { }
        };
        const openCats = () => {
            try {
                closeGlobal();
                panelCats.classList.remove('gigma-hidden');
                panelCats.setAttribute('aria-hidden', 'false');
                btnCats.setAttribute('aria-expanded', 'true');
                updatePanelMaxHeight(panelCats);
            } catch (_e) { }
        };

        const closeGlobal = () => {
            try {
                EXTENSION_STATE.globalWiStatsModalPanelOpen = false;
                EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen = '';
                gigmaUpdateGlobalWiStatsControlsUi('modal');
            } catch (_e) { }
        };
        const openGlobal = () => {
            try {
                closeCats();
                EXTENSION_STATE.globalWiStatsModalPanelOpen = true;
                EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen = suffix;
                gigmaUpdateGlobalWiStatsControlsUi('modal');
                if (panelGlobal && btnGlobalWi) {
                    try{ gigmaApplyGlobalWiStatsDropdownPlacement(panelGlobal, btnGlobalWi, 'modal'); }catch(_ePlace){}
                    updatePanelMaxHeight(panelGlobal, btnGlobalWi);
                }
            } catch (_e) { }
        };

        let modalScrollLayoutQueued = false;
        const onModalScroll = () => {
            if (modalScrollLayoutQueued) return;
            modalScrollLayoutQueued = true;
            const runLayout = () => {
                modalScrollLayoutQueued = false;
                updatePanelMaxHeight(panelCats);
                if (panelGlobal && btnGlobalWi && !panelGlobal.classList.contains('gigma-hidden')) {
                    try{ gigmaApplyGlobalWiStatsDropdownPlacement(panelGlobal, btnGlobalWi, 'modal'); }catch(_ePlace2){}
                    updatePanelMaxHeight(panelGlobal, btnGlobalWi);
                }
            };
            if (typeof requestAnimationFrame === 'function') requestAnimationFrame(runLayout);
            else setTimeout(runLayout, 16);
        };
        if (modalScroll) {
            modalScroll.addEventListener('scroll', onModalScroll, { passive: true });
            modalEventListeners.push({ element: modalScroll, event: 'scroll', handler: onModalScroll });
        }
        const onWinResize = () => {
            updatePanelMaxHeight(panelCats);
            if (panelGlobal && btnGlobalWi && !panelGlobal.classList.contains('gigma-hidden')) {
                try{ gigmaApplyGlobalWiStatsDropdownPlacement(panelGlobal, btnGlobalWi, 'modal'); }catch(_ePlace3){}
                updatePanelMaxHeight(panelGlobal, btnGlobalWi);
            }
        };
        window.addEventListener('resize', onWinResize);
        modalEventListeners.push({ element: window, event: 'resize', handler: onWinResize });

        const onDocDown = (ev) => {
            try {
                const t = ev && ev.target;
                if (!t) return;

                // Cats
                if (!panelCats.classList.contains('gigma-hidden')) {
                    if (!(panelCats.contains(t) || btnCats.contains(t))) closeCats();
                }
                // Global
                if (EXTENSION_STATE.globalWiStatsModalPanelOpen && EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen === suffix) {
                    if (!panelGlobal || !btnGlobalWi) { closeGlobal(); return; }
                    if (!(panelGlobal.contains(t) || btnGlobalWi.contains(t) || (btnGlobalWiCollapse && btnGlobalWiCollapse.contains(t)))) closeGlobal();
                }
            } catch (_e) { }
        };
        document.addEventListener('mousedown', onDocDown, true);
        modalEventListeners.push({ element: document, event: 'mousedown', handler: onDocDown, options: true });

        btnRefresh.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            scheduleBackground(() => gigmaRefreshLastGenerationUsageSnapshot({ source: 'ordering-modal' }));
        });

        // Toggle the Global WI stats dropdown
        if (btnGlobalWi) btnGlobalWi.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            const isOpen = !!(EXTENSION_STATE.globalWiStatsModalPanelOpen && EXTENSION_STATE.globalWiStatsModalPanelSuffixOpen === suffix);
            if (isOpen) closeGlobal();
            else openGlobal();
        });
        if (btnGlobalWiCollapse) btnGlobalWiCollapse.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            gigmaSetGlobalWiStatsDisplayCollapsed('modal', !gigmaGetGlobalWiStatsDisplayCollapsed('modal'));
            gigmaUpdateGlobalWiStatsControlsUi('modal');
            gigmaQueueGlobalWiStatsUpdate('modal');
        });

        btnEnt.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            const wasE = !!EXTENSION_STATE.modalLorebookStatsShowEntries;
            const wasT = !!EXTENSION_STATE.modalLorebookStatsShowTokens;
            EXTENSION_STATE.modalLorebookStatsShowEntries = !wasE;
            if (!EXTENSION_STATE.modalLorebookStatsShowEntries && !wasT) EXTENSION_STATE.modalLorebookStatsShowTokens = true;
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });
        btnTok.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            const wasE = !!EXTENSION_STATE.modalLorebookStatsShowEntries;
            const wasT = !!EXTENSION_STATE.modalLorebookStatsShowTokens;
            EXTENSION_STATE.modalLorebookStatsShowTokens = !wasT;
            if (!wasE && !EXTENSION_STATE.modalLorebookStatsShowTokens) EXTENSION_STATE.modalLorebookStatsShowEntries = true;
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });
        btnCats.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            if (panelCats.classList.contains('gigma-hidden')) openCats();
            else closeCats();
        });
        btnCatsCollapse.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            gigmaSetLorebookStatsDisplayCollapsed('modal', !gigmaGetLorebookStatsDisplayCollapsed('modal'));
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });

        btnRaw.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            EXTENSION_STATE.modalLorebookStatsSectionRaw = !EXTENSION_STATE.modalLorebookStatsSectionRaw;
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });
        btnActivated.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            EXTENSION_STATE.modalLorebookStatsSectionActivated = !EXTENSION_STATE.modalLorebookStatsSectionActivated;
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });
        btnIncluded.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            EXTENSION_STATE.modalLorebookStatsSectionIncluded = !EXTENSION_STATE.modalLorebookStatsSectionIncluded;
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });

        btnAll.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            gigmaSetModalLorebookStatsCategoryList(GIGMA_MODAL_STATS_CATEGORIES.map(c => c.key));
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });
        btnNone.addEventListener('click', (ev) => {
            try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
            gigmaSetModalLorebookStatsCategoryList([]);
            gigmaPersistModalLorebookStatsSettings();
            gigmaUpdateOrderingModalStatsControlsUi();
            gigmaUpdateModalLorebookStatsAllRows();
        });

        panelCats.addEventListener('change', (ev) => {
            try {
                const t = ev && ev.target;
                if (!t || t.tagName !== 'INPUT') return;
                if (t.getAttribute('data-gigma-lore-switch') === '1') {
                    EXTENSION_STATE.modalLorebookStatsEnabled = !!t.checked;
                    gigmaPersistModalLorebookStatsSettings();
                    gigmaUpdateOrderingModalStatsControlsUi();
                    gigmaUpdateModalLorebookStatsAllRows();
                    return;
                }
                if (t.getAttribute('data-gigma-lore-collapse-switch') === '1') {
                    gigmaSetStatsCollapseButtonVisible('modal', 'lorebook', !!t.checked);
                    gigmaUpdateOrderingModalStatsControlsUi();
                    return;
                }
                if (t.getAttribute('data-gigma-lore-remove-irrelevant-switch') === '1') {
                    EXTENSION_STATE.modalLorebookStatsRemoveIrrelevantCategories = !!t.checked;
                    gigmaPersistModalLorebookStatsSettings();
                    gigmaUpdateOrderingModalStatsControlsUi();
                    gigmaUpdateModalLorebookStatsAllRows();
                    return;
                }
                if (t.getAttribute('data-gigma-lore-remove-zero-tokens-switch') === '1') {
                    EXTENSION_STATE.modalLorebookStatsRemoveZeroTokenCategories = !!t.checked;
                    gigmaPersistModalLorebookStatsSettings();
                    gigmaUpdateOrderingModalStatsControlsUi();
                    gigmaUpdateModalLorebookStatsAllRows();
                    return;
                }
                const k = t.getAttribute('data-gigma-cat');
                if (!k) return;
                const cur = gigmaGetModalLorebookStatsCategoryList().slice();
                const i = cur.indexOf(k);
                if (t.checked) {
                    if (i < 0) cur.push(k);
                } else {
                    if (i >= 0) cur.splice(i, 1);
                }
                gigmaSetModalLorebookStatsCategoryList(cur);
                gigmaPersistModalLorebookStatsSettings();
                gigmaUpdateOrderingModalStatsControlsUi();
                gigmaUpdateModalLorebookStatsAllRows();
                gigmaQueueGlobalWiStatsUpdate('modal');
            } catch (_e) { }
        });

        // Keep the global WI panel and display synced immediately on build.
        gigmaUpdateGlobalWiStatsControlsUi('modal');
        gigmaQueueGlobalWiStatsUpdate('modal');
    } catch (_e) { }
};

        try { gigmaInstallLorebookContentStylesOnce(); } catch (_e) { }
        try { gigmaEnsureOrderingModalLorebookContentToggleButton(root); } catch (_e) { }
        try { gigmaEnsureOrderingModalSettingsButton(root); } catch (_e) { }
        try { gigmaApplyHideUndoRedoDesktopPref(); } catch (_e) { }

        try { gigmaUpdateLorebookContentToggleButtonsUi(); } catch (_e) { }
        try { gigmaUpdateLorebookContentExpandersInModal(root); } catch (_e) { }

        ensure('#gigma-toolbar', '');
        ensure('#gigma-toolbar-right', '-right');

        gigmaUpdateOrderingModalStatsControlsUi();
        gigmaUpdateManualUsageRefreshButtonsUi();
    } catch (_e) { }
}

