function gigmaEnsureWorldInfoTokenTotalSlot() {
    try {
        const list = document.getElementById('world_popup_entries_list');
        if (!list) return null;

        const parent = list.parentElement;
        if (!parent) return null;

        let totalEl = document.getElementById(SELECTORS.WORLD_INFO_TOKEN_TOTAL);
        if (!totalEl) {
            totalEl = document.createElement('div');
            totalEl.id = SELECTORS.WORLD_INFO_TOKEN_TOTAL;
            parent.insertBefore(totalEl, list);
        } else if (totalEl.parentElement !== parent || totalEl.nextSibling !== list) {
            parent.insertBefore(totalEl, list);
        }

        return totalEl;
    } catch (e) {
        console.warn('[GIGMA] Failed to ensure WI token total slot:', e);
        return null;
    }
}

function gigmaUpdateWorldInfoUsageToggleButtons() {
    const applyState = (id, pressed) => {
        const btn = document.getElementById(id);
        if (!btn) return;
        btn.setAttribute('aria-pressed', pressed ? 'true' : 'false');
    };

    applyState(SELECTORS.WORLD_INFO_LAST_ACTIVATED_BUTTON, !!EXTENSION_STATE.worldInfoLastActivatedEnabled);
    applyState(SELECTORS.WORLD_INFO_LAST_INCLUDED_BUTTON, !!EXTENSION_STATE.worldInfoLastIncludedEnabled);
    gigmaUpdateManualUsageRefreshButtonsUi();
}


function gigmaCreateWorldInfoEntryUsageFlagBox(letter, isMarked) {
    const box = document.createElement('span');
    const label = String(letter || '').slice(0, 1).toUpperCase();
    box.className = 'gigma-wi-entry-flag-box' + (isMarked ? '' : ' gigma-wi-entry-flag-box-empty');
    if (label === 'A') box.classList.add('gigma-wi-entry-flag-box-activated');
    else if (label === 'I') box.classList.add('gigma-wi-entry-flag-box-included');
    box.textContent = label;
    box.setAttribute('aria-hidden', isMarked ? 'false' : 'true');
    return box;
}

function gigmaUpdateWorldInfoTokenAlignButton() {
    const btn = document.getElementById(SELECTORS.WORLD_INFO_TOKEN_ALIGN_BUTTON);
    if (!btn) return;
    const mode = EXTENSION_STATE.worldInfoTokenAlign ?? 0;
    btn.classList.remove('fa-align-left', 'fa-align-center', 'fa-align-right');
    if (mode === 1) btn.classList.add('fa-align-center');
    else if (mode === 2) btn.classList.add('fa-align-right');
    else btn.classList.add('fa-align-left');
    btn.setAttribute('aria-disabled', 'false');
}

function gigmaUpdateWorldInfoHeaderStatsToggleButton() {
    const btn = document.getElementById(SELECTORS.WORLD_INFO_HEADER_STATS_TOGGLE_BUTTON);
    if (!btn) return;
    btn.setAttribute('aria-pressed', EXTENSION_STATE.worldInfoHeaderStatsEnabled ? 'true' : 'false');
}

async function gigmaSetWorldInfoHeaderStatsEnabled(enabled) {
    EXTENSION_STATE.worldInfoHeaderStatsEnabled = !!enabled;
    try {
        gigmaPersistBinaryExtensionSetting('worldInfoHeaderStatsEnabled', EXTENSION_STATE.worldInfoHeaderStatsEnabled, 1);
        saveSettingsDebounced();
    } catch (_) { }

    gigmaUpdateWorldInfoHeaderStatsToggleButton();
    try{ gigmaUpdateWorldInfoLorebookStatsDropdownUi(); }catch(_e){}
    gigmaEnsureWorldInfoTokenTotalSlot();
    gigmaEnsureWorldInfoTokenObserver();
    await gigmaUpdateWorldInfoTokenDisplay();
}


function gigmaCloseWorldInfoLorebookStatsDropdown(){
    try{
        EXTENSION_STATE.worldInfoLorebookStatsPanelOpen = false;
        gigmaUpdateWorldInfoLorebookStatsDropdownUi();
    }catch(_e){}
}

function gigmaUpdateWorldInfoLorebookStatsDropdownUi(){
    try{
        const btn = document.getElementById(SELECTORS.WORLD_INFO_LOREBOOK_STATS_BUTTON);
        const panel = document.getElementById(SELECTORS.WORLD_INFO_LOREBOOK_STATS_PANEL);
        const open = !!EXTENSION_STATE.worldInfoLorebookStatsPanelOpen;

        if (btn) btn.setAttribute('aria-expanded', open ? 'true' : 'false');
        const collapseBtn = document.getElementById(SELECTORS.WORLD_INFO_LOREBOOK_COLLAPSE_BUTTON);
        gigmaSyncStatsButtonPairUi(btn, collapseBtn, !!EXTENSION_STATE.worldInfoLorebookStatsEnabled, !gigmaIsWorldInfoStatsSectionCollapsed('lorebook'), 'Lorebook Stats', gigmaGetStatsCollapseButtonVisible('wi', 'lorebook'));

        gigmaSyncNativeWiMobileFullscreenStatsLayer();

        if (!panel) return;

        panel.classList.toggle('gigma-hidden', !open);
        panel.setAttribute('aria-hidden', open ? 'false' : 'true');

        const statsEnabledSw = panel.querySelector('input[data-gigma-wi-lore="enabled"]');
        if (statsEnabledSw) statsEnabledSw.checked = !!EXTENSION_STATE.worldInfoLorebookStatsEnabled;

        const collapseSw = panel.querySelector('input[data-gigma-wi-lore="collapse"]');
        if (collapseSw) collapseSw.checked = gigmaGetStatsCollapseButtonVisible('wi', 'lorebook');

        const headerSw = panel.querySelector('input[data-gigma-wi-lore="header"]');
        if (headerSw) headerSw.checked = !!EXTENSION_STATE.worldInfoHeaderStatsEnabled;

        const tokenSw = panel.querySelector('input[data-gigma-wi-lore="tokens"]');
        if (tokenSw) tokenSw.checked = !!EXTENSION_STATE.worldInfoTokensEnabled;

        const actSw = panel.querySelector('input[data-gigma-wi-lore="activated"]');
        if (actSw) actSw.checked = !!EXTENSION_STATE.worldInfoLastActivatedEnabled;

        const incSw = panel.querySelector('input[data-gigma-wi-lore="included"]');
        if (incSw) incSw.checked = !!EXTENSION_STATE.worldInfoLastIncludedEnabled;

        const removeIrrelevantSw = panel.querySelector('input[data-gigma-wi-lore="remove-irrelevant"]');
        if (removeIrrelevantSw) removeIrrelevantSw.checked = !!EXTENSION_STATE.worldInfoLorebookStatsRemoveIrrelevantCategories;

        const removeZeroTokensSw = panel.querySelector('input[data-gigma-wi-lore="remove-zero-tokens"]');
        if (removeZeroTokensSw) removeZeroTokensSw.checked = !!EXTENSION_STATE.worldInfoLorebookStatsRemoveZeroTokenCategories;

        panel.querySelectorAll('button[data-gigma-wi-lore-section]').forEach((b) => {
            const k = String(b.getAttribute('data-gigma-wi-lore-section') || '');
            const on = (k === 'raw') ? !!EXTENSION_STATE.worldInfoLorebookStatsSectionRaw
                : (k === 'activated') ? !!EXTENSION_STATE.worldInfoLorebookStatsSectionActivated
                : (k === 'included') ? !!EXTENSION_STATE.worldInfoLorebookStatsSectionIncluded
                : false;
            b.setAttribute('aria-pressed', on ? 'true' : 'false');
        });

        const set = gigmaGetWorldInfoLorebookStatsCategorySet();
        panel.querySelectorAll('input[data-gigma-wi-lore-cat]').forEach((cb) => {
            const k = String(cb.getAttribute('data-gigma-wi-lore-cat') || '');
            cb.checked = !!(k && set.has(k));
        });

        if (open && btn) {
            gigmaApplyWorldInfoFloatingDropdownPlacement(panel, btn);
        } else {
            gigmaResetWorldInfoFloatingDropdownPlacement(panel);
        }

        const alignBtn = panel.querySelector('button[data-gigma-wi-lore="align"]');
        if (alignBtn) {
            const mode = Number.isInteger(EXTENSION_STATE.worldInfoTokenAlign) ? EXTENSION_STATE.worldInfoTokenAlign : 0;
            const m = (mode === 1) ? 1 : (mode === 2 ? 2 : 0);
            alignBtn.classList.remove('fa-align-left', 'fa-align-center', 'fa-align-right');
            if (m === 1) alignBtn.classList.add('fa-align-center');
            else if (m === 2) alignBtn.classList.add('fa-align-right');
            else alignBtn.classList.add('fa-align-left');
            const label = (m === 1) ? 'center' : (m === 2 ? 'right' : 'left');
            alignBtn.setAttribute('aria-label', 'Marker & Token Alignment: ' + label);
            alignBtn.title = 'Marker & Token Alignment: ' + label;
        }
    }catch(_e){}
}

function gigmaBuildWorldInfoLorebookStatsDropdown(panel){
    try{
        if (!panel) return;
        if (panel.dataset.gigmaBuilt === '1') return;

        panel.dataset.gigmaBuilt = '1';
        panel.classList.add('gigma-wi-lorebook-stats-panel', 'gigma-modal-stats-panel', 'gigma-hidden');
        panel.setAttribute('aria-hidden', 'true');
        gigmaEnsureMobileFullscreenDropdownShell(panel, 'Close Lorebook statistics');

        const mkRow = (labelText, controlEl) => {
            const row = document.createElement('div');
            row.className = 'gigma-wi-lorebook-stats-row';
            const label = document.createElement('div');
            label.className = 'gigma-wi-lorebook-stats-label';
            label.textContent = labelText;
            const ctrl = document.createElement('div');
            ctrl.className = 'gigma-wi-lorebook-stats-control';
            if (controlEl) ctrl.appendChild(controlEl);
            row.appendChild(label);
            row.appendChild(ctrl);
            panel.appendChild(row);
        };

        const mkSwitch = (key, aria, onChange) => {
            const wrap = document.createElement('label');
            wrap.className = 'gigma-wi-switch';
            const input = document.createElement('input');
            input.type = 'checkbox';
            input.setAttribute('data-gigma-wi-lore', key);
            input.setAttribute('aria-label', aria);
            const track = document.createElement('span');
            track.className = 'gigma-wi-switch-track';
            const thumb = document.createElement('span');
            thumb.className = 'gigma-wi-switch-thumb';
            track.appendChild(thumb);
            wrap.appendChild(input);
            wrap.appendChild(track);
            input.addEventListener('change', (ev) => {
                try{ ev.stopPropagation(); }catch(_e){}
                try{ onChange(!!input.checked); }catch(_e){}
            });
            return wrap;
        };

        const makeActionButton = (textValue, titleValue, attrName, attrValue) => {
            const b = document.createElement('button');
            b.type = 'button';
            b.className = 'menu_button';
            b.textContent = textValue;
            b.title = titleValue;
            b.setAttribute(attrName, attrValue);
            return b;
        };

        const head = document.createElement('div');
        head.className = 'gigma-wi-lorebook-stats-headrow';
        const headTitle = document.createElement('div');
        headTitle.className = 'gigma-wi-lorebook-stats-headtitle';
        headTitle.textContent = 'Lorebook Statistics';
        const headCtrl = document.createElement('div');
        headCtrl.className = 'gigma-wi-lorebook-stats-control';
        headCtrl.appendChild(mkSwitch('enabled', 'Lorebook Statistics', (v) => {
            EXTENSION_STATE.worldInfoLorebookStatsEnabled = !!v;
            try{
                gigmaPersistBinaryExtensionSetting('worldInfoLorebookStatsEnabled', EXTENSION_STATE.worldInfoLorebookStatsEnabled, 1);
                saveSettingsDebounced();
            }catch(_e){}
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            gigmaQueueWorldInfoTokenUpdate();
        }));
        head.appendChild(headTitle);
        head.appendChild(headCtrl);
        panel.appendChild(head);

        mkRow('Show Expand/Collapse button', mkSwitch('collapse', 'Show Expand/Collapse button', (v) => {
            gigmaSetStatsCollapseButtonVisible('wi', 'lorebook', v);
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
        }));

        mkRow('Header statistics', mkSwitch('header', 'Header statistics', (v) => { gigmaSetWorldInfoHeaderStatsEnabled(v); }));

        mkRow('Remove irrelevant categories', mkSwitch('remove-irrelevant', 'Remove irrelevant categories', (v) => {
            EXTENSION_STATE.worldInfoLorebookStatsRemoveIrrelevantCategories = !!v;
            gigmaPersistWorldInfoLorebookStatsSettings();
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            gigmaQueueWorldInfoTokenUpdate();
        }));

        mkRow('Remove 0 tokens categories', mkSwitch('remove-zero-tokens', 'Remove 0 tokens categories', (v) => {
            EXTENSION_STATE.worldInfoLorebookStatsRemoveZeroTokenCategories = !!v;
            gigmaPersistWorldInfoLorebookStatsSettings();
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            gigmaQueueWorldInfoTokenUpdate();
        }));

        const alignBtn = document.createElement('button');
        alignBtn.type = 'button';
        alignBtn.className = 'menu_button fa-solid gigma-wi-lorebook-stats-align-btn';
        alignBtn.setAttribute('data-gigma-wi-lore', 'align');
        alignBtn.addEventListener('click', (ev) => {
            try{ ev.preventDefault(); ev.stopPropagation(); }catch(_e){}
            const mode = Number.isInteger(EXTENSION_STATE.worldInfoTokenAlign) ? EXTENSION_STATE.worldInfoTokenAlign : 0;
            EXTENSION_STATE.worldInfoTokenAlign = (mode === 0) ? 1 : ((mode === 1) ? 2 : 0);
            try{
                if (EXTENSION_STATE.worldInfoTokenAlign === 0) delete gigmaExtensionSettings.worldInfoTokenAlign;
                else gigmaExtensionSettings.worldInfoTokenAlign = EXTENSION_STATE.worldInfoTokenAlign;
                saveSettingsDebounced();
            }catch(_e){}
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            gigmaQueueWorldInfoTokenUpdate();
        });
        mkRow('Marker & Token Alignment', alignBtn);

        mkRow('Token counts', mkSwitch('tokens', 'Token counts', (v) => { gigmaSetWorldInfoTokensEnabled(v); }));

        mkRow('Activated Markers', mkSwitch('activated', 'Activated Markers', (v) => {
            EXTENSION_STATE.worldInfoLastActivatedEnabled = !!v;
            try{
                gigmaPersistBinaryExtensionSetting('worldInfoLastActivatedEnabled', EXTENSION_STATE.worldInfoLastActivatedEnabled, 0);
                saveSettingsDebounced();
            }catch(_e){}
            gigmaUpdateWorldInfoUsageToggleButtons();
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            gigmaQueueWorldInfoTokenUpdate();
        }));

        mkRow('Included Markers', mkSwitch('included', 'Included Markers', (v) => {
            EXTENSION_STATE.worldInfoLastIncludedEnabled = !!v;
            try{
                gigmaPersistBinaryExtensionSetting('worldInfoLastIncludedEnabled', EXTENSION_STATE.worldInfoLastIncludedEnabled, 0);
                saveSettingsDebounced();
            }catch(_e){}
            gigmaUpdateWorldInfoUsageToggleButtons();
            gigmaUpdateWorldInfoLorebookStatsDropdownUi();
            gigmaQueueWorldInfoTokenUpdate();
        }));

        const sectionToggles = document.createElement('div');
        sectionToggles.className = 'gigma-modal-stats-panel-actions';
        sectionToggles.appendChild(makeActionButton('Raw', 'Toggle Raw block', 'data-gigma-wi-lore-section', 'raw'));
        sectionToggles.appendChild(makeActionButton('Activated', 'Toggle Activated block', 'data-gigma-wi-lore-section', 'activated'));
        sectionToggles.appendChild(makeActionButton('Included', 'Toggle Included block', 'data-gigma-wi-lore-section', 'included'));
        panel.appendChild(sectionToggles);

        const actions = document.createElement('div');
        actions.className = 'gigma-modal-stats-panel-actions';
        actions.appendChild(makeActionButton('All', 'Show all categories', 'data-gigma-wi-lore-action', 'all'));
        actions.appendChild(makeActionButton('None', 'Hide all categories', 'data-gigma-wi-lore-action', 'none'));
        panel.appendChild(actions);

        const list = document.createElement('div');
        list.className = 'gigma-modal-stats-panel-list';
        for (const c of GIGMA_MODAL_STATS_CATEGORIES) {
            const row = document.createElement('label');
            row.className = 'gigma-modal-stats-panel-item';
            const cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.setAttribute('data-gigma-wi-lore-cat', c.key);
            const txt = document.createElement('span');
            txt.innerHTML = GIGMA_NATIVE_WI_FULL_STATS_LABEL_BY_KEY.get(c.key) || c.key;
            row.appendChild(cb);
            row.appendChild(txt);
            list.appendChild(row);
        }
        panel.appendChild(list);

        panel.addEventListener('click', (ev) => {
            try{
                const t = ev && ev.target;
                const btn = (t && t.closest) ? t.closest('button') : null;
                if (!btn) return;
                const section = btn.getAttribute('data-gigma-wi-lore-section');
                const action = btn.getAttribute('data-gigma-wi-lore-action');
                if (section) {
                    try{ ev.preventDefault(); ev.stopPropagation(); }catch(_e){}
                    if (section === 'raw') EXTENSION_STATE.worldInfoLorebookStatsSectionRaw = !EXTENSION_STATE.worldInfoLorebookStatsSectionRaw;
                    if (section === 'activated') EXTENSION_STATE.worldInfoLorebookStatsSectionActivated = !EXTENSION_STATE.worldInfoLorebookStatsSectionActivated;
                    if (section === 'included') EXTENSION_STATE.worldInfoLorebookStatsSectionIncluded = !EXTENSION_STATE.worldInfoLorebookStatsSectionIncluded;
                    gigmaPersistWorldInfoLorebookStatsSettings();
                    gigmaUpdateWorldInfoLorebookStatsDropdownUi();
                    gigmaQueueWorldInfoTokenUpdate();
                    return;
                }
                if (action) {
                    try{ ev.preventDefault(); ev.stopPropagation(); }catch(_e){}
                    if (action === 'all') gigmaSetWorldInfoLorebookStatsCategoryList(GIGMA_MODAL_STATS_CATEGORIES.map(c => c.key));
                    else if (action === 'none') gigmaSetWorldInfoLorebookStatsCategoryList([]);
                    gigmaPersistWorldInfoLorebookStatsSettings();
                    gigmaUpdateWorldInfoLorebookStatsDropdownUi();
                    gigmaQueueWorldInfoTokenUpdate();
                }
            }catch(_e){}
        }, true);

        panel.addEventListener('change', (ev) => {
            try{
                const t = ev && ev.target;
                if (!t || t.tagName !== 'INPUT') return;
                const k = t.getAttribute('data-gigma-wi-lore-cat');
                if (!k) return;
                const cur = gigmaGetWorldInfoLorebookStatsCategoryList().slice();
                const i = cur.indexOf(k);
                if (t.checked) {
                    if (i < 0) cur.push(k);
                } else if (i >= 0) {
                    cur.splice(i, 1);
                }
                gigmaSetWorldInfoLorebookStatsCategoryList(cur);
                gigmaPersistWorldInfoLorebookStatsSettings();
                gigmaUpdateWorldInfoLorebookStatsDropdownUi();
                gigmaQueueWorldInfoTokenUpdate();
            }catch(_e){}
        }, true);

        gigmaUpdateWorldInfoLorebookStatsDropdownUi();
    }catch(_e){}
}

