function gigmaSkinLorebookContentToggleButton(btn, titleText) {
    try {
        if (!btn) return;
        btn.classList.add('gigma-lore-content-toggle-icon', 'gigma-icon-btn');
        if (titleText) {
            btn.title = titleText;
            btn.setAttribute('aria-label', titleText);
        }
        if (btn.dataset && btn.dataset.gigmaLoreContentSkinned === '1') {
            // Still re-square on rebuilds (font size / zoom can change).
            try { gigmaSquareButtonToHeight(btn); } catch (_e) { }
            return;
        }
        btn.dataset.gigmaLoreContentSkinned = '1';

        // Replace text label with a book icon
        try {
            btn.textContent = '';
            const i = document.createElement('i');
            i.className = 'fa-solid fa-book';
            i.setAttribute('aria-hidden', 'true');
            btn.appendChild(i);
        } catch (_e2) { }

        try { gigmaSquareButtonToHeight(btn); } catch (_e3) { }
    } catch (_e) { }
}

function gigmaSquareButtonToHeight(btn) {
    try {
        if (!btn || !btn.getBoundingClientRect) return;
        const apply = () => {
            try {
                const r = btn.getBoundingClientRect();
                const hPx = r && r.height ? r.height : 0;
                if (!hPx) return;
                const cs = window.getComputedStyle ? getComputedStyle(btn) : null;
                const fsPx = cs ? (parseFloat(cs.fontSize) || 16) : 16;
                const wEm = fsPx ? (hPx / fsPx) : (hPx / 16);
                const w = (Math.round(wEm * 10000) / 10000) + 'em';
                btn.style.width = w;
                btn.style.minWidth = w;
                btn.style.maxWidth = w;
            } catch (_e2) { }
        };
        // two RAFs to ensure layout is settled
        try { requestAnimationFrame(() => { apply(); requestAnimationFrame(apply); }); } catch (_e3) { apply(); }
    } catch (_e) { }
}


