function gigmaApplyModalSettingsPopupPlacement(popupEl, btnEl, rootEl, rowEl){
    try{
        if (!popupEl || !btnEl) return;
        const root = rootEl || document.getElementById('gigma-modal-root') || document;
        const row = rowEl || btnEl.parentElement;
        if (!row || !row.getBoundingClientRect) return;

        const bRect = btnEl.getBoundingClientRect ? btnEl.getBoundingClientRect() : null;
        const rRect = row.getBoundingClientRect ? row.getBoundingClientRect() : null;
        if (!bRect || !rRect) return;

        const modalScroll = root && root.querySelector ? root.querySelector('#gigma-modal-scroll') : null;
        const clipEl = modalScroll || (btnEl.closest ? btnEl.closest('dialog') : null) || document.documentElement;
        const clipRect = clipEl && clipEl.getBoundingClientRect ? clipEl.getBoundingClientRect() : { top: 0, bottom: (window && window.innerHeight) ? window.innerHeight : 0 };

        const em = (typeof gigmaGetEmPx === 'function') ? gigmaGetEmPx(btnEl) : 16;
        const gapPx = em * 0.25;
        const safetyPx = em * 0.6;

        const abovePx = bRect.top - clipRect.top;
        const belowPx = clipRect.bottom - bRect.bottom;
        const openUp = (belowPx < abovePx);

        try{ popupEl.dataset.gigmaOpenDir = openUp ? 'up' : 'down'; }catch(_e2){}

        popupEl.style.left = 'auto';
        const rightPx = rRect.right - bRect.right;
        popupEl.style.right = Math.round(rightPx) + 'px';

        if (openUp){
            popupEl.style.top = 'auto';
            const bottomPx = rRect.bottom - bRect.top + gapPx;
            popupEl.style.bottom = Math.round(bottomPx) + 'px';
        } else {
            popupEl.style.bottom = 'auto';
            const topPx = bRect.bottom - rRect.top + gapPx;
            popupEl.style.top = Math.round(topPx) + 'px';
        }

        let maxH = openUp ? (abovePx - gapPx - safetyPx) : (belowPx - gapPx - safetyPx);
        if (!Number.isFinite(maxH)) maxH = 0;
        maxH = Math.max(0, maxH);

        popupEl.style.maxHeight = Math.floor(maxH) + 'px';
        popupEl.style.overflowY = 'auto';
        popupEl.style.overflowX = 'hidden';
    }catch(_e){}
}

function gigmaUpdateModalSettingsPopupPlacementNow(){
    try{
        const root = document.getElementById('gigma-modal-root');
        if (!root) return;
        const popupEl = root.querySelector('#gigma-modal-settings-popup');
        if (!popupEl || popupEl.style.display === 'none') return;
        const btnEl = document.getElementById('gigma-modal-settings-toggle');
        if (!btnEl) return;
        const rowEl = btnEl.parentElement;
        if (typeof gigmaApplyModalSettingsPopupPlacement === 'function') gigmaApplyModalSettingsPopupPlacement(popupEl, btnEl, root, rowEl);
    }catch(_e){}
}

function gigmaSkinLorebookSettingsButton(btn, titleText) {
    try {
        if (!btn) return;
        btn.classList.add('gigma-lore-content-toggle-icon');
        if (titleText) {
            btn.title = titleText;
            btn.setAttribute('aria-label', titleText);
        }
        if (btn.dataset && btn.dataset.gigmaLoreSettingsSkinned === '1') {
            try { gigmaSquareButtonToHeight(btn); } catch (_e) { }
            return;
        }
        btn.dataset.gigmaLoreSettingsSkinned = '1';
        try {
            btn.textContent = '';
            const i = document.createElement('i');
            i.className = 'fa-solid fa-gear';
            i.setAttribute('aria-hidden', 'true');
            btn.appendChild(i);
        } catch (_e2) { }
        try { gigmaSquareButtonToHeight(btn); } catch (_e3) { }
    } catch (_e) { }
}

