async function gigmaApplyCountLeadingNewlinePrefChangeNow(){
    try{
        try{ if (typeof TOKEN_COUNT_CACHE !== 'undefined' && TOKEN_COUNT_CACHE && typeof TOKEN_COUNT_CACHE.clear === 'function') TOKEN_COUNT_CACHE.clear(); }catch(_){}
        try{ if (typeof GIGMA_MODAL_LOREBOOK_STATS_CACHE !== 'undefined' && GIGMA_MODAL_LOREBOOK_STATS_CACHE && typeof GIGMA_MODAL_LOREBOOK_STATS_CACHE.clear === 'function') GIGMA_MODAL_LOREBOOK_STATS_CACHE.clear(); }catch(_){}
        const worlds = new Set();
        try{
            const modalRoot = document.getElementById('gigma-ordering-container') || document.getElementById('gigma-modal-root') || null;
            const rows = modalRoot && modalRoot.querySelectorAll ? modalRoot.querySelectorAll('.gigma-row[data-world]') : [];
            for (const r of rows){
                const w = r && r.dataset ? String(r.dataset.world || '') : '';
                if (w) worlds.add(w);
            }
        }catch(_){}
        try{
            const w = (typeof getCurrentLorebookName === 'function') ? String(getCurrentLorebookName() || '') : '';
            if (w) worlds.add(w);
        }catch(_){}
        const tasks = [];
        try{
            for (const w of worlds){
                tasks.push((async()=>{
                    try{ await gigmaEnsureLorebookStatsIndexForWorld(w, { forceRebuild: true }); }catch(_){}
                    try{
                        const stats = gigmaGetLorebookStatsIndexStatsByWorldName(w);
                        if (stats && typeof GIGMA_MODAL_LOREBOOK_STATS_CACHE !== 'undefined' && GIGMA_MODAL_LOREBOOK_STATS_CACHE && typeof GIGMA_MODAL_LOREBOOK_STATS_CACHE.set === 'function'){
                            GIGMA_MODAL_LOREBOOK_STATS_CACHE.set(String(w), { stats });
                        }
                    }catch(_){}
                })());
            }
        }catch(_){}
        try{ if (tasks.length) await Promise.all(tasks); }catch(_){}
        try{ if (typeof gigmaUpdateWorldInfoTokenDisplay === 'function') await gigmaUpdateWorldInfoTokenDisplay(); }catch(_){}
        try{
            const root = document.getElementById('gigma-modal-root') || document;
            const panels = root.querySelectorAll ? root.querySelectorAll('.gigma-lore-content-panel') : [];
            for (const panel of panels){
                try{
                    const scroll = panel && panel.querySelector ? panel.querySelector('.gigma-lore-content-scroll') : null;
                    if (!scroll) continue;
                    const row = panel.closest ? panel.closest('.gigma-row[data-world]') : null;
                    const worldName = row && row.dataset ? String(row.dataset.world || '') : '';
                    if (!worldName) continue;
                    let entriesObj = null;
                    try{
                        const data = (worldInfoCache && typeof worldInfoCache.has === 'function' && worldInfoCache.has(worldName)) ? worldInfoCache.get(worldName) : null;
                        entriesObj = data && data.entries ? data.entries : null;
                    }catch(_){}
                    if (!entriesObj){
                        try{
                            const data = await loadWorldInfo(worldName);
                            entriesObj = data && data.entries ? data.entries : null;
                        }catch(_){}
                    }
                    if (!entriesObj) continue;
                    const nlInfo = gigmaComputeLorebookLeadingNewlineInfo(entriesObj);
                    const entryEls = scroll.querySelectorAll ? scroll.querySelectorAll('.gigma-lore-entry[data-uid]') : [];
                    for (const el of entryEls){
                        try{
                            const uid = String(el.getAttribute('data-uid') || '');
                            if (!uid) continue;
                            const raw = entriesObj[uid];
                            if (!raw) continue;
                            const entryObj = (raw && typeof raw === 'object' && raw.uid != null) ? raw : { ...raw, uid };
                            const content = (typeof entryObj.content === 'string') ? entryObj.content : '';
                            const enabledNonEmpty = entryObj.disable !== true && !!content;
                            const leadingNewline = (nlInfo.count > 1) && enabledNonEmpty && uid && (uid !== nlInfo.minUid);
                            const tokens = getEntryTokenCountCached(entryObj, leadingNewline);
                            const badge = el.querySelector ? el.querySelector('.gigma-wi-entry-token') : null;
                            if (badge) badge.textContent = String(tokens || 0);
                        }catch(_){}
                    }
                }catch(_){}
            }
        }catch(_){}
        try{
            if (typeof gigmaIsOrderingModalActive === 'function' && gigmaIsOrderingModalActive()){
                try{ gigmaUpdateModalLorebookStatsAllRows(); }catch(_){}
                try{
                    const container = document.getElementById('gigma-global-wi-stats-display-modal');
                    if (container) gigmaRenderGlobalWiStatsDisplayInto(container, 'modal');
                }catch(_){}
            }
        }catch(_){}
        try{
            const prevRoot = (typeof gigmaGetLatestLayoutPresetTreePreviewRoot === 'function') ? gigmaGetLatestLayoutPresetTreePreviewRoot() : null;
            const container = prevRoot ? prevRoot.querySelector('#gigma-global-wi-stats-display-preview') : null;
            if (container) gigmaRenderGlobalWiStatsDisplayInto(container, 'preview', prevRoot || undefined);
        }catch(_){}
        try{ if (typeof gigmaUpdatePromptManagerTokenCountersInDom === 'function') gigmaUpdatePromptManagerTokenCountersInDom(); }catch(_){}
    }catch(_){}
}


