async function gigmaApplyDetailedLorebookEntriesPrefChangeNow(){
    try{
        const roots = [];
        try{
            const modalRoot = document.getElementById('gigma-modal-root');
            if (modalRoot) roots.push(modalRoot);
        }catch(_){}
        try{
            const prevRoot = (typeof gigmaGetLatestLayoutPresetTreePreviewRoot === 'function') ? gigmaGetLatestLayoutPresetTreePreviewRoot() : null;
            if (prevRoot) roots.push(prevRoot);
        }catch(_){}
        const tasks = [];
        for (const root of roots){
            const panels = root.querySelectorAll ? root.querySelectorAll('.gigma-lore-content-panel') : [];
            for (const panel of panels){
                try{
                    const worldName = panel && panel.dataset ? String(panel.dataset.worldName || '') : '';
                    if (!worldName) continue;
                    const scroll = panel.querySelector ? panel.querySelector('.gigma-lore-content-scroll') : null;
                    const top = scroll ? scroll.scrollTop : 0;
                    const openUids = [];
                    try{
                        const openEls = panel.querySelectorAll ? panel.querySelectorAll('.gigma-lore-entry[data-gigma-open="1"][data-uid]') : [];
                        for (const el of openEls){
                            const uid = el && el.getAttribute ? String(el.getAttribute('data-uid') || '') : '';
                            if (uid) openUids.push(uid);
                        }
                    }catch(_){}
                    tasks.push((async()=>{
                        try{ await gigmaRenderLorebookContentPanel(panel, worldName); }catch(_){}
                        try{
                            const sc2 = panel.querySelector ? panel.querySelector('.gigma-lore-content-scroll') : null;
                            if (sc2) sc2.scrollTop = top;
                            for (const uid of openUids){
                                const esc = (window.CSS && typeof CSS.escape === 'function') ? CSS.escape(String(uid)) : String(uid);
                                const el = panel.querySelector ? panel.querySelector('.gigma-lore-entry[data-uid="' + esc + '"]') : null;
                                if (!el) continue;
                                el.setAttribute('data-gigma-open','1');
                                try{ if (typeof gigmaEnsureLorebookEntryDetailsBuiltForElement === 'function') gigmaEnsureLorebookEntryDetailsBuiltForElement(el); }catch(_){}
                            }
                        }catch(_){}
                    })());
                }catch(_){}
            }
        }
        if (tasks.length) await Promise.all(tasks);
    }catch(_){}
}



function gigmaUpdateModalSettingsConvertButtonVisibility(root) {
    try {
        if (!root) return;
        const kindBtn = document.getElementById('gigma-layout-preset-kind-toggle');
        const kind = (kindBtn && kindBtn.dataset && kindBtn.dataset.gigmaPresetKind === 'parent') ? 'parent' : 'child';

        const popup = root.querySelector('#gigma-modal-settings-popup');
        if (popup) {
            const slotConvert = popup.querySelector('#gigma-modal-settings-slot-convert');
            if (slotConvert) {
                let park = popup.querySelector('#gigma-modal-settings-park');
                if (!park) {
                    park = document.createElement('div');
                    park.id = 'gigma-modal-settings-park';
                    park.style.display = 'none';
                    popup.appendChild(park);
                }

                const bParent = root.querySelector('#gigma-modal-convert-parent');
                const bChild = root.querySelector('#gigma-modal-convert-child');

                const active = (kind === 'child') ? bChild : bParent;
                const inactive = (kind === 'child') ? bParent : bChild;

                if (active && active.parentElement !== slotConvert) slotConvert.replaceChildren(active);
                else if (active && slotConvert.firstChild !== active) slotConvert.replaceChildren(active);

                if (inactive) {
                    inactive.style.display = 'none';
                    if (inactive.parentElement !== park) park.appendChild(inactive);
                }
                if (active) {
                    active.style.display = '';
                    try { gigmaSquareButtonToHeight(active); } catch (_e2) { }
                }

                const tdL = slotConvert.closest('tr') ? slotConvert.closest('tr').querySelector('td.gigma-settings-desc') : null;
                if (tdL) {
                    tdL.textContent = (kind === 'child')
                        ? 'Save child as parent preset'
                        : 'Save parent as child preset';
                }
            }
        }
    } catch (_e) { }
}

