function gigmaEnsureOrderingModalSettingsButton(rootOverride) {
    try {
        const root = rootOverride || document.getElementById('gigma-modal-root');
        if (!root) return;

        const previewBtn = root.querySelector('#gigma-ordering-preview');
        if (!previewBtn || !previewBtn.parentElement) return;

        const row = previewBtn.parentElement;
        const bookBtn = document.getElementById('gigma-modal-lore-content-toggle');
        if (!bookBtn) return;

        try { gigmaEnsureOrderingModalSettingsPopup(root); } catch (_e) { }

        let btn = document.getElementById('gigma-modal-settings-toggle');
        if (!btn) {
            btn = document.createElement('button');
            btn.type = 'button';
            btn.id = 'gigma-modal-settings-toggle';
            btn.className = 'menu_button';
            gigmaSkinLorebookSettingsButton(btn, 'Settings');
            btn.addEventListener('click', (ev) => {
                try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
                try { gigmaEnsureOrderingModalSettingsPopup(root); } catch (_e) { }
                const popup = root.querySelector('#gigma-modal-settings-popup');
                if (!popup) return;
                const isOpen = popup.style.display && popup.style.display !== 'none';
                if (isOpen) {
                    popup.style.display = 'none';
                    return;
                }
                if (popup.parentElement !== row) row.appendChild(popup);
                try{
                    const cs = getComputedStyle(row);
                    if (cs && cs.position === 'static') row.style.position = 'relative';
                    row.style.overflow = 'visible';
                }catch(_e){}
                popup.style.display = 'block';
                popup.style.visibility = 'hidden';
                requestAnimationFrame(() => {
                    try{
                        if (typeof gigmaApplyModalSettingsPopupPlacement === 'function') gigmaApplyModalSettingsPopupPlacement(popup, btn, root, row);
                    }catch(_e2){}
                    popup.style.visibility = 'visible';
                    try { gigmaSquareButtonToHeight(document.getElementById('gigma-clear-folders')); } catch (_e3) { }
                    try { gigmaSquareButtonToHeight(document.getElementById('gigma-clear-folders-right')); } catch (_e4) { }
                });
            });
        }

        try { gigmaSkinLorebookSettingsButton(btn, 'Settings'); } catch (_e) { }

        if (btn.parentElement !== row) {
            row.insertBefore(btn, bookBtn);
        } else if (btn.nextSibling !== bookBtn) {
            row.insertBefore(btn, bookBtn);
        }
    } catch (_e) { }
}

function gigmaEnsureOrderingModalLorebookContentToggleButton(rootOverride) {
    try {
        const root = rootOverride || document.getElementById('gigma-modal-root');
        if (!root) return;

        const previewBtn = root.querySelector('#gigma-ordering-preview');
        if (!previewBtn || !previewBtn.parentElement) return;

        const row = previewBtn.parentElement;
        let btn = document.getElementById('gigma-modal-lore-content-toggle');
        if (!btn) {
            btn = document.createElement('button');
            btn.type = 'button';
            btn.id = 'gigma-modal-lore-content-toggle';
            btn.className = 'menu_button';
            gigmaSkinLorebookContentToggleButton(btn, 'Toggle lorebook content buttons in this list');
            btn.setAttribute('aria-pressed', gigmaIsLorebookContentToggleEnabled() ? 'true' : 'false');
            btn.addEventListener('click', (ev) => {
                try { ev.preventDefault(); ev.stopPropagation(); } catch (_e) { }
                gigmaSetLorebookContentToggleEnabled(!gigmaIsLorebookContentToggleEnabled());
            });
        }

        try { gigmaSkinLorebookContentToggleButton(btn, 'Toggle lorebook content buttons in this list'); } catch (_e) { }

        // Keep it beside Reset/Preview without shifting the existing order too much.
        if (btn.parentElement !== row) {
            row.insertBefore(btn, previewBtn);
        } else if (btn.nextSibling !== previewBtn) {
            row.insertBefore(btn, previewBtn);
        }
    } catch (_e) { }
}

