// --- GIGMA: icon-only Preview buttons + folder action buttons (preserve text labels for logic/state checks) ---
(function gigmaIconizePreviewAndFolderButtonsOnce(){
  try{
    if (window.__gigmaIconizePreviewAndFolderButtonsInstalled) return;
    window.__gigmaIconizePreviewAndFolderButtonsInstalled = true;

    if (!document.getElementById('gigma-iconize-preview-folder-buttons-style')){
      const s = document.createElement('style');
      s.id = 'gigma-iconize-preview-folder-buttons-style';
      s.textContent = `
        .gigma-iconized-button{
          position:relative;
          display:inline-flex !important;
          align-items:center !important;
          justify-content:center !important;
          box-sizing:border-box;
          overflow:hidden;
        }
        .gigma-iconized-button .gigma-iconized-button-label{
          visibility:hidden;
          white-space:nowrap;
          line-height:inherit;
          display:block;
        }
        .gigma-iconized-button .gigma-iconized-button-glyph{
          position:absolute;
          inset:0;
          display:inline-flex;
          align-items:center;
          justify-content:center;
          }
        .gigma-iconized-button .gigma-iconized-button-glyph i{
          font-size:0.9em;
          line-height:1;
        }
        .gigma-folder-header .gigma-iconized-button .gigma-iconized-button-glyph i{
          font-size:0.82em;
        }
        /* Pre-lock button geometry before iconization so the modal does not visibly shift on first paint. */
        #gigma-lorebook-tree-button,
        #gigma-ordering-preview,
        #gigma-assignment-preview-button,
        #gigma-lorebook-drawer-assignment-preview{
          width:3em !important;
          min-width:3em !important;
          max-width:3em !important;
          padding-left:0 !important;
          padding-right:0 !important;
          box-sizing:border-box;
        }
        .gigma-folder-header .gigma-folder-toggle,
        .gigma-folder-header .gigma-folder-remove,
        .gigma-folder-header .gigma-show-right{
          width:2.25em !important;
          min-width:2.25em !important;
          max-width:2.25em !important;
          padding-left:0 !important;
          padding-right:0 !important;
          box-sizing:border-box;
        }
      `;
      document.head.appendChild(s);
    }

    const PREVIEW_IDS = new Set([
      'gigma-lorebook-tree-button',
      'gigma-ordering-preview',
      'gigma-assignment-preview-button',
      'gigma-lorebook-drawer-assignment-preview',
    ]);
    const TARGET_SELECTOR = [
      '#gigma-lorebook-tree-button',
      '#gigma-ordering-preview',
      '#gigma-assignment-preview-button',
      '#gigma-lorebook-drawer-assignment-preview',
      '.gigma-folder-header .gigma-folder-toggle',
      '.gigma-folder-header .gigma-folder-remove',
      '.gigma-folder-header .gigma-show-right',
    ].join(', ');

    const getButtonType = (btn) => {
      if (!btn) return '';
      if (PREVIEW_IDS.has(btn.id)) return 'preview';
      if (btn.classList && btn.classList.contains('gigma-folder-toggle')) return 'folder-toggle';
      if (btn.classList && btn.classList.contains('gigma-folder-remove')) return 'folder-remove';
      if (btn.classList && btn.classList.contains('gigma-show-right')) return 'folder-focus';
      return '';
    };

    const getButtonLabel = (btn, type) => {
      if (!btn) return '';
      const current = btn.querySelector(':scope > .gigma-iconized-button-label');
      const txt = String((current ? current.textContent : btn.textContent) || '').trim();
      if (txt) return txt;
      if (type === 'preview') return 'Preview';
      return '';
    };

    const getIconClass = (type, label) => {
      if (type === 'preview') return 'fa-eye';
      if (type === 'folder-remove') return 'fa-trash-can';
      if (type === 'folder-toggle') return label === 'Expand' ? 'fa-chevron-up' : 'fa-chevron-down';
      if (type === 'folder-focus') return /^defocus$/i.test(label) ? 'fa-arrow-right' : 'fa-arrow-left';
      return '';
    };

    const getCurrentStateTooltip = (btn, type, label) => {
      if (type === 'folder-toggle') {
        return (label === 'Expand') ? 'Current state: folder collapsed' : 'Current state: folder expanded';
      }
      if (type === 'folder-focus') {
        return /^defocus$/i.test(label)
          ? 'Current state: folder focused (shown on the right pane)'
          : 'Current state: folder defocused';
      }
      if (type === 'folder-remove') {
        return 'Current state: folder present';
      }
      if (type === 'preview') {
        return btn.getAttribute('title') || btn.getAttribute('aria-label') || 'Preview';
      }
      return '';
    };

    const clearDelayedFolderTooltip = (btn) => {
      try{
        if (!btn) return;
        if (btn._gigmaFolderTooltipTimer){
          clearTimeout(btn._gigmaFolderTooltipTimer);
          btn._gigmaFolderTooltipTimer = null;
        }
      }catch(_){ }
    };

    const ensureDelayedFolderTooltipHandlers = (btn) => {
      try{
        if (!btn || btn.dataset.gigmaFolderTooltipDelayWired === '1') return;
        btn.dataset.gigmaFolderTooltipDelayWired = '1';

        btn.addEventListener('pointerenter', () => {
          try{
            clearDelayedFolderTooltip(btn);
            const txt = btn.dataset.gigmaTooltipText || '';
            btn.removeAttribute('title');
            if (!txt) return;
            btn._gigmaFolderTooltipTimer = setTimeout(() => {
              btn._gigmaFolderTooltipTimer = null;
              if (btn.matches(':hover')) btn.setAttribute('title', txt);
            }, 2000);
          }catch(_){ }
        }, { passive:true });

        btn.addEventListener('pointerleave', () => {
          try{
            clearDelayedFolderTooltip(btn);
            btn.removeAttribute('title');
          }catch(_){ }
        }, { passive:true });

        btn.addEventListener('pointerdown', () => {
          try{
            clearDelayedFolderTooltip(btn);
            btn.removeAttribute('title');
          }catch(_){ }
        }, { passive:true });

        btn.addEventListener('blur', () => {
          try{
            clearDelayedFolderTooltip(btn);
            btn.removeAttribute('title');
          }catch(_){ }
        }, { passive:true });

        btn.addEventListener('focus', () => {
          try{
            clearDelayedFolderTooltip(btn);
            const txt = btn.dataset.gigmaTooltipText || '';
            if (txt) btn.setAttribute('title', txt);
          }catch(_){ }
        }, { passive:true });
      }catch(_){ }
    };

    const applyButtonTooltip = (btn, type, label) => {
      try{
        if (!btn) return;
        if (type === 'folder-toggle' || type === 'folder-focus' || type === 'folder-remove'){
          try{
            clearDelayedFolderTooltip(btn);
            btn.removeAttribute('title');
            if (btn.dataset) delete btn.dataset.gigmaTooltipText;
          }catch(_){ }
          return;
        }
        const txt = getCurrentStateTooltip(btn, type, label);
        if (!txt) return;
        btn.setAttribute('title', txt);
      }catch(_){ }
    };

    const applyIconButtonSize = (btn, ratio) => {
      try{
        if (!btn || !(ratio > 0)) return;
        if (btn.dataset && btn.dataset.gigmaIconBtnSizeLocked === '1') return;
        const fs = parseFloat(getComputedStyle(btn).fontSize) || 0;
        const h = btn.getBoundingClientRect().height || 0;
        if (!(fs > 0) || !(h > 0)) return;
        const widthEm = (h / fs) * ratio;
        btn.style.width = widthEm + 'em';
        btn.style.minWidth = widthEm + 'em';
        btn.style.maxWidth = widthEm + 'em';
        btn.style.paddingLeft = '0';
        btn.style.paddingRight = '0';
        if (btn.dataset) btn.dataset.gigmaIconBtnSizeLocked = '1';
      }catch(_){ }
    };

    const skinButton = (btn) => {
      try{
        const type = getButtonType(btn);
        if (!type) return;
        const label = getButtonLabel(btn, type);
        if (!label) return;
        const iconClass = getIconClass(type, label);
        if (!iconClass) return;
        const ratio = (type === 'preview') ? 2 : 1.5;

        applyIconButtonSize(btn, ratio);
        applyButtonTooltip(btn, type, label);

        if (btn.dataset && btn.dataset.gigmaIconizedType === type && btn.dataset.gigmaIconizedLabel === label && btn.querySelector(':scope > .gigma-iconized-button-glyph i.' + iconClass)) {
          return;
        }

        const labelSpan = document.createElement('span');
        labelSpan.className = 'gigma-iconized-button-label';
        labelSpan.textContent = label;

        const glyph = document.createElement('span');
        glyph.className = 'gigma-iconized-button-glyph';
        const i = document.createElement('i');
        i.className = 'fa-solid ' + iconClass;
        i.setAttribute('aria-hidden', 'true');
        glyph.appendChild(i);

        btn.replaceChildren(labelSpan, glyph);
        btn.classList.add('gigma-iconized-button');
        if (btn.dataset){
          btn.dataset.gigmaIconizedType = type;
          btn.dataset.gigmaIconizedLabel = label;
        }
        btn.setAttribute('aria-label', label);

        applyIconButtonSize(btn, ratio);
        applyButtonTooltip(btn, type, label);
      }catch(_){ }
    };

    const skinAll = (scope) => {
      try{
        const root = (scope && typeof scope.querySelectorAll === 'function') ? scope : document;
        if (root.matches && root.matches(TARGET_SELECTOR)) skinButton(root);
        const buttons = root.querySelectorAll(TARGET_SELECTOR);
        for (const btn of buttons) skinButton(btn);
      }catch(_){ }
    };

    window.gigmaSkinPreviewAndFolderButtons = skinAll;

    let queued = false;
    let queuedScope = null;
    const scheduleSkin = (scope) => {
      try{
        queuedScope = scope || queuedScope || document;
        if (queued) return;
        queued = true;
        const runner = () => {
          const scopeToUse = queuedScope || document;
          queued = false;
          queuedScope = null;
          try{ skinAll(scopeToUse); }catch(_){ }
        };
        if (typeof requestAnimationFrame === 'function') requestAnimationFrame(runner);
        else setTimeout(runner, 16);
      }catch(_){
        queued = false;
        queuedScope = null;
        try{ skinAll(document); }catch(__){ }
      }
    };

    const mutationSkinScope = (muts) => {
      try{
        for (const m of muts || []) {
          const nodes = [];
          const t = m && m.target;
          if (t) nodes.push(t.nodeType === 1 ? t : t.parentElement);
          if (m && m.addedNodes) {
            for (const n of m.addedNodes) nodes.push(n && n.nodeType === 1 ? n : null);
          }
          for (const node of nodes) {
            if (!node) continue;
            if (node.matches && node.matches(TARGET_SELECTOR)) return node;
            if (node.closest) {
              const near = node.closest('#gigma-modal-root, #gigma-layout-preset-tree-preview-root, #gigma-global-settings, .gigma-folder-header');
              if (near && near.querySelector && near.querySelector(TARGET_SELECTOR)) return near;
            }
            if (node.querySelector && node.querySelector(TARGET_SELECTOR)) return node;
          }
        }
      }catch(_){ }
      return null;
    };

    try{
      const obs = new MutationObserver((muts) => {
        const scope = mutationSkinScope(muts);
        if (scope) scheduleSkin(scope);
      });
      obs.observe(document.documentElement, { subtree:true, childList:true, characterData:true, attributes:true, attributeFilter:['class'] });
      window.__gigmaIconizePreviewAndFolderButtonsObserver = obs;
    }catch(_){ }

    try{ window.addEventListener('resize', () => scheduleSkin(document), { passive:true }); }catch(_){ }
    scheduleSkin(document);
  }catch(_){ }
})();

