/** Lock the inherit-area height to match the Child preset inheritance rows. */
function gigmaEnsureInheritAreaHeightLocked(){
    try{
        if (typeof document === 'undefined') return;
        const area = document.getElementById('gigma-inherit-area');
        const childWrap = document.getElementById('gigma-inherit-child');
        if (!area || !childWrap) return;
        // Measure child height even if currently hidden.
        let h = 0;
        try{
            h = childWrap.offsetHeight || 0;
        }catch(_){ h = 0; }
        if (!h){
            // Temporary measure when hidden.
            const prevDisplay = childWrap.style.display;
            const prevVis = childWrap.style.visibility;
            const prevPos = childWrap.style.position;
            const prevLeft = childWrap.style.left;
            const prevTop = childWrap.style.top;
            try{
                childWrap.style.display = 'flex';
                childWrap.style.visibility = 'hidden';
                childWrap.style.position = 'absolute';
                childWrap.style.left = '-625em';
                childWrap.style.top = '0';
                h = childWrap.offsetHeight || 0;
            }catch(_eMeas){ h = 0; }
            try{
                childWrap.style.display = prevDisplay;
                childWrap.style.visibility = prevVis;
                childWrap.style.position = prevPos;
                childWrap.style.left = prevLeft;
                childWrap.style.top = prevTop;
            }catch(_eRestore){}
        }
        if (h && isFinite(h)){
            area.style.minHeight = String(h) + 'px';
        }
    }catch(_){}
}
