/* ---------------- Parent presets: unchained lorebook placeholders ---------------- */
function gigmaFormatParentUnchainedGhostEntry(loreName, childPresetId){
    try{
        const lore = (loreName == null ? '' : String(loreName)).replace(/\u00AD/g,'').slice(0, 10);
        const child = (childPresetId == null ? '' : String(childPresetId)).replace(/\u00AD/g,'').slice(0, 10);
        return lore + ' - ' + child;
    }catch(_){
        return '';
    }
}
/** Parent presets: compute/update the "ghost" marker text for a placeholder row. */
function gigmaUpdateParentUnchainedGhostText(placeholderEl, childPresetId){
    try{
        if (!placeholderEl) return;
        const id = (childPresetId == null ? '' : String(childPresetId)).trim();
        const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        const snap = store ? store[id] : null;
        const nm = (snap && typeof snap.name === 'string') ? snap.name.trim() : '';
        const child = nm.replace(/\u00AD/g,'');
        const rawLore = (placeholderEl.dataset && placeholderEl.dataset.world) ? String(placeholderEl.dataset.world) : '';
        const lore = rawLore.replace(/\u00AD/g,'');
        const entry = gigmaFormatParentUnchainedGhostEntry(lore, child);
        try{ placeholderEl.dataset.gigmaParentUnchainedGhostEntry = entry; }catch(_){}
        const ghost = placeholderEl.querySelector('.gigma-parent-unchained-ghost-text');
        if (ghost) ghost.textContent = entry;
    }catch(_){}
}

function gigmaUpdateParentUnchainedTextBetweenLeft(){
    try{
        const root = document.getElementById('gigma-modal-root');
        if (!root) return;
        const ghost = root.querySelector('.gigma-parent-unchained-ghost-text');
        const nameEl = root.querySelector('.gigma-row:not(.gigma-parent-unchained-placeholder) .gigma-row-name');
        if (!ghost || !nameEl) return;
        const rowEl = nameEl.closest('.gigma-row');
        if (!rowEl) return;
        const off = nameEl.getBoundingClientRect().left - rowEl.getBoundingClientRect().left;
        const fs = parseFloat(getComputedStyle(ghost).fontSize) || 0;
        if (!fs) return;
        root.style.setProperty('--gigma-parent-unchained-text-left', (Math.round((off / fs) * 10000) / 10000) + 'em');
    }catch(_){}
}


/**
 * Parent presets: prevent overlapping "ghost" texts by merging consecutive ghost placeholders
 * into a single line like:
 *   first10(lore) - first10(child) | first10(lore2) - first10(child2) | ...
 */
function gigmaReflowParentUnchainedGhostMarkers(){
    try{
        if (typeof document === 'undefined') return;
        try{ gigmaUpdateParentUnchainedTextBetweenLeft(); }catch(_){ }
        // Collect list containers (ROOT + all folder lists).
        const lists = [];
        try{
            const root = document.getElementById('gigma-ordering-list');
            if (root) lists.push(root);
        }catch(_){}
        try{
            document.querySelectorAll('.gigma-folder-list').forEach((el) => {
                try{ if (el && lists.indexOf(el) === -1) lists.push(el); }catch(_){}
            });
        }catch(_){}
        const setGhostText = (el, txt) => {
            try{
                const ghost = el ? el.querySelector('.gigma-parent-unchained-ghost-text') : null;
                if (ghost) ghost.textContent = txt || '';
            }catch(_){}
        };
        const getEntry = (el) => {
            try{
                if (!el) return '';
                try{ if (el.classList && el.classList.contains('gigma-parent-unchained-notext')) return ''; }catch(_){ }
                const cached = el.dataset ? el.dataset.gigmaParentUnchainedGhostEntry : '';
                if (cached) return String(cached);
                const child = el.dataset ? (el.dataset.gigmaParentUnchainedChild || '') : '';
                const lore = el.dataset ? (el.dataset.world || '') : '';
                const entry = gigmaFormatParentUnchainedGhostEntry(lore, child);
                try{ el.dataset.gigmaParentUnchainedGhostEntry = entry; }catch(_){}
                return entry;
            }catch(_){
                return '';
            }
        };
        for (const listEl of lists){
            if (!listEl) continue;
            const kids = Array.from(listEl.children || []);
            if (!kids.length) continue;
            let i = 0;
            while (i < kids.length){
                const el = kids[i];
                const isGhost = !!(el && el.classList
                    && el.classList.contains('gigma-parent-unchained-placeholder')
                    && el.classList.contains('gigma-parent-unchained-ghost')
                    && !el.classList.contains('gigma-parent-unchained-hidden')
                    && !el.classList.contains('gigma-parent-unchained-notext'));
                if (!isGhost){ i++; continue; }
                // Collect consecutive ghost placeholders (skip hidden placeholders without breaking the run).
                const run = [];
                let j = i;
                while (j < kids.length){
                    const cur = kids[j];
                    if (!cur || !cur.classList) break;
                    const isPlaceholder = cur.classList.contains('gigma-parent-unchained-placeholder');
                    if (!isPlaceholder) break;
                    const isHidden = cur.classList.contains('gigma-parent-unchained-hidden');
                    const isNoText = cur.classList.contains('gigma-parent-unchained-notext');
                    const isCurGhost = cur.classList.contains('gigma-parent-unchained-ghost');
                    if (!isCurGhost) break;
                    if (!isHidden && !isNoText) run.push(cur);
                    j++;
                }
                if (run.length){
                    // Order matters: left-to-right must follow top-to-bottom order.
                    const parts = run.map(getEntry).filter(Boolean);
                    const combined = parts.join(' | ');
                    setGhostText(run[0], combined);
                    for (let k = 1; k < run.length; k++) setGhostText(run[k], '');
                }
                i = j;
            }
        }
    }catch(_){}
}
function gigmaGetOrCreateParentUnchainedPlaceholderRow(worldId, childPresetId){
    try{
        if (typeof document === 'undefined') return null;
        const id = (worldId == null ? '' : String(worldId)).trim();
        const child = (childPresetId == null ? '' : String(childPresetId)).trim();
        if (!id || !child) return null;
        if (!window.__gigmaParentUnchainedPlaceholderByKey) window.__gigmaParentUnchainedPlaceholderByKey = {};
        const key = child + '|' + id;
        let el = window.__gigmaParentUnchainedPlaceholderByKey[key];
                if (el && el.isConnected) {
            // Ensure unchained placeholder labels show the same usage icons + bound-owner tag as normal lorebooks.
            try{
                const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
                const p = store && store[child];
                const childShort = (p && typeof p.name === 'string') ? p.name.trim().slice(0, 15) : '';
                const label = el.querySelector('.gigma-row-label');
                const rawName = (el.dataset && el.dataset.world) ? String(el.dataset.world) : (label ? (label.textContent || '') : '');
                __gigmaRenderUnchainedRowLabel(label, rawName, childShort, true, true);
                if (typeof gigmaUpdateParentUnchainedGhostText === 'function') gigmaUpdateParentUnchainedGhostText(el, child);
            }catch(_){}
            return el;
        }
// Resolve display name
        let name = '';
        try{
            if (window.gigmaNameByWorldId && window.gigmaNameByWorldId[id]) {
                name = String(window.gigmaNameByWorldId[id]);
            }
        }catch(_){}
        if (!name) {
            try{
                const real = document.querySelector('.gigma-row[data-world-id="' + CSS.escape(id) + '"]');
                if (real && real.dataset && real.dataset.world) name = String(real.dataset.world);
            }catch(_){}
        }
        if (!name) name = '(Lorebook)';
        el = document.createElement('div');
        el.className = 'gigma-row MarginTop3 gigma-parent-unchained-placeholder';
        try{
            el.style.display = 'flex';
            el.style.justifyContent = 'flex-start';
            el.style.gap = '0.375em';
            el.style.alignItems = 'center';
        }catch(_){}
        el.dataset.world = name;
        el.dataset.worldId = id;
        el.dataset.gigmaParentUnchainedChild = child;
        const label = document.createElement('div');
        label.className = 'gigma-row-label';
        label.style.flex = '1 1 auto';
        label.style.minWidth = '0';
        // Render the unchained label with the same usage icons + bound-owner tag as normal lorebooks.
        const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        const p = store && store[child];
        const childShort = (p && typeof p.name === 'string') ? p.name.trim().slice(0, 15) : '';
        __gigmaRenderUnchainedRowLabel(label, name, childShort, true, true);
el.appendChild(label);
        try{ el.setAttribute('draggable', 'false'); }catch(_){}
        try{ el.dataset.gigmaNonInteractive = '1'; }catch(_){}
        window.__gigmaParentUnchainedPlaceholderByKey[key] = el;
        return el;
    }catch(_){
        return null;
    }
}
function gigmaFlattenPresetLorebookOrderIds(preset){
    const out = [];
    try{
        if (!preset || typeof preset !== 'object') return out;
        const childrenOrder = (preset.childrenOrder && typeof preset.childrenOrder === 'object') ? preset.childrenOrder : null;
        if (!childrenOrder) return out;
        const walk = (pid) => {
            const arr = childrenOrder[pid] || null;
            if (!Array.isArray(arr)) return;
            for (const token of arr){
                if (typeof token !== 'string') continue;
                if (token.indexOf('rowId:') === 0){
                    const id = token.slice(6);
                    if (id) out.push(String(id));
                } else if (token.indexOf('row:') === 0){
                    const name = token.slice(4);
                    let id = '';
                    try{
                        if (window.gigmaWorldIdByName && window.gigmaWorldIdByName[name]) id = String(window.gigmaWorldIdByName[name]);
                    }catch(_){}
                    if (id) out.push(id);
                } else if (token.indexOf('folder:') === 0){
                    const fid = token.slice(7);
                    if (fid) walk(String(fid));
                }
            }
        };
        walk('ROOT');
    }catch(_){}
    return out;
}
/* ---------------- Child presets: store ONLY unchained positions when inheriting order ---------------- */
function gigmaGetUnchainedIdSetFromPreset(preset){
    try{
        if (!preset || typeof preset !== 'object') return new Set();
        const arr = Array.isArray(preset.retroLocksOrder)
            ? preset.retroLocksOrder
            : (Array.isArray(preset.retroLocks) ? preset.retroLocks : []);
        return new Set((arr || []).map(v => String(v)));
    }catch(_){
        return new Set();
    }
}
function gigmaTokenForOrderingElement(el){
    try{
        if (!el || !el.classList) return null;
        if (el.classList.contains('gigma-folder')) {
            const fid = el.dataset ? el.dataset.folderId : null;
            return fid ? ('folder:' + String(fid)) : null;
        }
        if (el.classList.contains('gigma-row')) {
            // Never use placeholders as anchors.
            if (el.classList.contains('gigma-parent-unchained-placeholder')) return null;
            const worldId = el.dataset ? el.dataset.worldId : null;
            if (worldId) return 'rowId:' + String(worldId);
            const worldName = el.dataset ? el.dataset.world : null;
            return worldName ? ('row:' + String(worldName)) : null;
        }
        return null;
    }catch(_){
        return null;
    }
}
function gigmaFindContainerLists(){
    const out = [];
    try{
        if (typeof document === 'undefined') return out;
        const rootList = document.getElementById('gigma-ordering-list');
        if (rootList) out.push({ key: 'ROOT', listEl: rootList });
        const folderEls = Array.from(document.querySelectorAll('.gigma-folder[data-folder-id]') || []);
        const getContentList = (folderEl) => {
            if (!folderEl) return null;
            try {
                if (typeof gigmaGetFolderContentList === 'function') {
                    const list = gigmaGetFolderContentList(folderEl);
                    if (list) return list;
                } else if (typeof window !== 'undefined' && typeof window.gigmaGetFolderContentList === 'function') {
                    const list = window.gigmaGetFolderContentList(folderEl);
                    if (list) return list;
                }
            } catch (_ignore) {}
            try { return folderEl.querySelector('.gigma-folder-list'); } catch (_ignore2) { return null; }
        };
        for (const folderEl of folderEls) {
            try{
                const fid = folderEl && folderEl.dataset ? folderEl.dataset.folderId : null;
                if (!fid) continue;
                const listEl = getContentList(folderEl);
                if (!listEl) continue;
                out.push({ key: String(fid), listEl });
            }catch(_){ }
        }
    }catch(_){ }
    return out;
}
function gigmaCaptureUnchainedPositionsFromDom(unchainedIdSet){
    const positions = {};
    try{
        if (typeof document === 'undefined') return positions;
        const unchained = (unchainedIdSet instanceof Set) ? unchainedIdSet : new Set();
        const lists = gigmaFindContainerLists();
        for (const entry of lists){
            const key = entry.key || 'ROOT';
            const listEl = entry.listEl;
            if (!listEl) continue;
            const children = Array.from(listEl.children || []);
            if (!children.length) continue;

            let visibleIndex = 0;
            for (const el of children){
                if (!el || !el.classList) continue;
                if (el.classList.contains('gigma-parent-unchained-placeholder')) continue;

                const isRow = el.classList.contains('gigma-row');
                const isFolder = el.classList.contains('gigma-folder');
                if (!isRow && !isFolder) continue;

                if (isRow){
                    const wid = el.dataset ? (el.dataset.worldId || el.dataset.world) : null;
                    const id = wid ? String(wid) : '';
                    if (id && unchained.has(id)){
                        if (!positions[key]) positions[key] = [];
                        positions[key].push({ id, index: visibleIndex });
                    }
                }
                visibleIndex++;
            }
        }
    }catch(_){ }
    return positions;
}
function gigmaDeriveUnchainedPositionsFromChildrenOrder(preset, unchainedIdSet){
    const positions = {};
    try{
        if (!preset || typeof preset !== 'object') return positions;
        const childrenOrder = (preset.childrenOrder && typeof preset.childrenOrder === 'object') ? preset.childrenOrder : null;
        if (!childrenOrder) return positions;
        const unchained = (unchainedIdSet instanceof Set) ? unchainedIdSet : new Set();
        const resolveRowIdFromToken = (token) => {
            try{
                if (typeof token !== 'string') return null;
                if (token.indexOf('rowId:') === 0) return token.slice(6) || null;
                if (token.indexOf('row:') === 0) {
                    const name = token.slice(4);
                    if (!name) return null;
                    if (window.gigmaWorldIdByName && window.gigmaWorldIdByName[name]) return String(window.gigmaWorldIdByName[name]);
                }
            }catch(_){ }
            return null;
        };
        for (const parentKey of Object.keys(childrenOrder)){
            const list = childrenOrder[parentKey];
            if (!Array.isArray(list) || !list.length) continue;
            let lastAnchor = null;
            for (let i = 0; i < list.length; i++){
                const token = list[i];
                if (typeof token !== 'string') continue;
                // Skip child placeholder tokens inside a child preset (shouldn't exist, but be safe).
                if (token.indexOf('urowid:') === 0) continue;
                const rowId = resolveRowIdFromToken(token);
                if (rowId && unchained.has(String(rowId))) {
                    // Find next non-unchained anchor.
                    let before = null;
                    for (let j = i + 1; j < list.length; j++){
                        const t2 = list[j];
                        if (typeof t2 !== 'string') continue;
                        if (t2.indexOf('urowid:') === 0) continue;
                        const rid2 = resolveRowIdFromToken(t2);
                        if (rid2 && unchained.has(String(rid2))) continue;
                        if (t2.indexOf('folder:') === 0 || t2.indexOf('rowId:') === 0 || t2.indexOf('row:') === 0) {
                            before = t2;
                            break;
                        }
                    }
                    if (!positions[parentKey || 'ROOT']) positions[parentKey || 'ROOT'] = [];
                    positions[parentKey || 'ROOT'].push({ id: String(rowId), after: lastAnchor, before });
                    continue;
                }
                // Update anchor for chained row/folder tokens.
                if (token.indexOf('folder:') === 0) {
                    lastAnchor = token;
                } else if (rowId) {
                    if (!unchained.has(String(rowId))) {
                        lastAnchor = 'rowId:' + String(rowId);
                    }
                }
            }
        }
    }catch(_){ }
    return positions;
}
function gigmaFindDirectChildByToken(listEl, token){
    try{
        if (!listEl || !token || typeof token !== 'string') return null;
        const children = Array.from(listEl.children || []);
        if (!children.length) return null;
        if (token.indexOf('folder:') === 0){
            const fid = token.slice(7);
            return children.find(el => el && el.classList && el.classList.contains('gigma-folder') && el.dataset && String(el.dataset.folderId) === String(fid)) || null;
        }
        if (token.indexOf('rowId:') === 0){
            const wid = token.slice(6);
            return children.find(el => el && el.classList && el.classList.contains('gigma-row') && !el.classList.contains('gigma-parent-unchained-placeholder') && el.dataset && String(el.dataset.worldId || el.dataset.world) === String(wid)) || null;
        }
        if (token.indexOf('row:') === 0){
            const name = token.slice(4);
            return children.find(el => el && el.classList && el.classList.contains('gigma-row') && !el.classList.contains('gigma-parent-unchained-placeholder') && el.dataset && String(el.dataset.world) === String(name)) || null;
        }
    }catch(_){ }
    return null;
}
function gigmaGetListElForContainerKey(containerKey){
    try{
        if (typeof document === 'undefined') return null;
        const key = (containerKey == null ? 'ROOT' : String(containerKey)) || 'ROOT';
        if (key === 'ROOT') return document.getElementById('gigma-ordering-list');
        const folderEl = document.querySelector('.gigma-folder[data-folder-id="' + CSS.escape(key) + '"]');
        if (!folderEl) return null;
        try{
            if (typeof gigmaGetFolderContentList === 'function') {
                const list = gigmaGetFolderContentList(folderEl);
                if (list) return list;
            } else if (typeof window !== 'undefined' && typeof window.gigmaGetFolderContentList === 'function') {
                const list = window.gigmaGetFolderContentList(folderEl);
                if (list) return list;
            }
        }catch(_){ }
        try{ return folderEl.querySelector('.gigma-folder-list'); }catch(_){ return null; }
    }catch(_){
        return null;
    }
}
function gigmaApplyUnchainedPositionsToRealRows(positions, unchainedIdSet){
    try{
        if (!positions || typeof positions !== 'object') return;
        const unchained = (unchainedIdSet instanceof Set) ? unchainedIdSet : new Set();
        const getVisibleNodes = (listEl) => {
            const out = [];
            try{
                const children = Array.from(listEl.children || []);
                for (const el of children){
                    if (!el || !el.classList) continue;
                    if (el.classList.contains('gigma-parent-unchained-placeholder')) continue;
                    if (el.classList.contains('gigma-row') || el.classList.contains('gigma-folder')) out.push(el);
                }
            }catch(_){ }
            return out;
        };
        for (const key of Object.keys(positions)){
            const listEl = gigmaGetListElForContainerKey(key) || gigmaGetListElForContainerKey('ROOT');
            if (!listEl) continue;
            const arr = positions[key];
            if (!Array.isArray(arr) || !arr.length) continue;

            // Apply from bottom to top so indices refer to the final state.
            const sorted = arr.slice().sort((a, b) => (b.index || 0) - (a.index || 0));
            for (const rec of sorted){
                if (!rec || !rec.id) continue;
                const id = String(rec.id);
                if (unchained.size && !unchained.has(id)) continue;

                const rowEl = document.querySelector('.gigma-row[data-world-id="' + CSS.escape(id) + '"]:not(.gigma-parent-unchained-placeholder)');
                if (!rowEl) continue;

                const visible = getVisibleNodes(listEl);
                const ref = (typeof rec.index === 'number' && rec.index >= 0) ? (visible[rec.index] || null) : null;
                try{
                    if (ref && ref !== rowEl) listEl.insertBefore(rowEl, ref);
                    else if (!ref) listEl.appendChild(rowEl);
                }catch(_){ }

                // Keep internal folder assignment in sync for these moved rows.
                try{
                    const worldName = rowEl.dataset ? rowEl.dataset.world : null;
                    if (worldName && window.gigmaRowFolder){
                        window.gigmaRowFolder[String(worldName)] = (key === 'ROOT') ? 'ROOT' : String(key);
                    }
                }catch(_){ }
            }
        }
        try{ if (typeof window.gigmaRenumberRows === 'function') window.gigmaRenumberRows(); }catch(_){ }
        try{ if (typeof window.gigmaUpdateFolderRanges === 'function') window.gigmaUpdateFolderRanges(); }catch(_){ }
        try{
            if (typeof window !== 'undefined' && typeof window.gigmaRefreshEmptyFoldersUI === 'function') {
                window.gigmaRefreshEmptyFoldersUI();
            } else if (typeof gigmaRefreshEmptyFoldersUI === 'function') {
                gigmaRefreshEmptyFoldersUI();
            }
        }catch(_){ }
    }catch(_){ }
}

// --- GIGMA: modal preset conversion button (parent <-> child) ---
function gigmaPrepareConvertedPresetSnapshot(snapshot, targetKind){
    try{
        if (!snapshot || typeof snapshot !== 'object') return;
        var k = (targetKind === 'parent') ? 'parent' : 'child';

        if (k === 'child'){
            // Remove parent-only UI state, and force the new child preset to be standalone.
            delete snapshot.parentUnchainedLorebooksVisibility;
            delete snapshot.parentUnchainedLorebooksChildPresetIds;
            delete snapshot.parentUnchainedLorebooksAs;
            delete snapshot.parentUnchainedBudgetLorebooksVisibility;
            delete snapshot.parentUnchainedBudgetLorebooksChildPresetIds;
            snapshot.chatInheritOrderFromId = 'decoupled';
            snapshot.budgetInheritFromId = 'decoupled';
            delete snapshot.unchainedPositions;
            delete snapshot.folderCollapsedState;
            // Parent placeholders are represented as urowid:/burowid: tokens; strip them from child presets.
            try{
                var co = snapshot.childrenOrder;
                if (co && typeof co === 'object'){
                    Object.keys(co).forEach(function(pid){
                        var arr = co[pid];
                        if (!Array.isArray(arr)) return;
                        co[pid] = arr.filter(function(t){
                            return !(typeof t === 'string' && (t.indexOf('urowid:') === 0 || t.indexOf('burowid:') === 0));
                        });
                    });
                }
            }catch(_eTok){}
            return;
        }

        // Parent preset: strip child-only state.
        delete snapshot.chatInheritOrderFromId;
        delete snapshot.budgetInheritFromId;
        delete snapshot.unchainedPositions;
        delete snapshot.folderCollapsedState;
        delete snapshot.retroLocks;
        delete snapshot.retroLocksOrder;
        delete snapshot.retroLocksBudget;
    }catch(_){ }
}

async function gigmaConvertActivePresetToOtherKind(fromKind){
    try{
        var srcKind = (fromKind === 'parent') ? 'parent' : 'child';
        var dstKind = (srcKind === 'parent') ? 'child' : 'parent';
        if (!Array.isArray(world_names) || !world_names.length) {
            try{ toastr.error('No lorebooks available to save as a layout preset.'); }catch(_){ }
            return;
        }
        if (typeof gigmaCaptureCurrentLayout !== 'function') return;
        var snapshot = gigmaCaptureCurrentLayout(srcKind);
        if (!snapshot) {
            try{ toastr.error('Load lorebooks and adjust the layout before saving a layout preset.'); }catch(_){ }
            return;
        }

        var srcSelect = document.getElementById(srcKind === 'parent' ? 'gigma-parent-preset-select' : 'gigma-child-preset-select');
        var srcId = (srcSelect && typeof srcSelect.value === 'string') ? srcSelect.value.trim() : '';
        var srcStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore(srcKind) || {}) : {};
        var srcSnap = (srcId && srcStore && srcStore[srcId]) ? srcStore[srcId] : null;
        var defaultName = (srcSnap && typeof srcSnap.name === 'string') ? srcSnap.name.trim() : '';

        var nameRaw = null;
        try{
            var ctx = (typeof SillyTavern !== 'undefined' && SillyTavern && typeof SillyTavern.getContext === 'function') ? SillyTavern.getContext() : null;
            var popupApi = ctx && ctx.Popup ? ctx.Popup : null;
            if (!popupApi || !popupApi.show || typeof popupApi.show.input !== 'function') return;
            nameRaw = await popupApi.show.input(
                dstKind === 'parent' ? 'Save parent preset' : 'Save child preset',
                dstKind === 'parent' ? 'Parent preset name:' : 'Child preset name:',
                defaultName
            );
        }catch(_eInput){ return; }

        if (nameRaw === null || nameRaw === undefined) return;
        var desiredName = String(nameRaw).trim();
        if (!desiredName) {
            try{ toastr.error('Preset name cannot be empty.'); }catch(_){ }
            return;
        }

        if (typeof gigmaGetLayoutPresetStore !== 'function' || typeof gigmaSetLayoutPresetStore !== 'function') return;
        var presets = gigmaGetLayoutPresetStore(dstKind) || {};
        var existingId = (typeof gigmaFindLayoutPresetIdByName === 'function') ? gigmaFindLayoutPresetIdByName(presets, desiredName) : null;
        var existedBeforeSave = !!(existingId && Object.prototype.hasOwnProperty.call(presets, existingId));
        var targetId = existingId || ((typeof gigmaGeneratePresetId === 'function') ? gigmaGeneratePresetId(presets) : null);
        if (!targetId) return;

        if (existedBeforeSave) {
            try{
                var ctx2 = (typeof SillyTavern !== 'undefined' && SillyTavern && typeof SillyTavern.getContext === 'function') ? SillyTavern.getContext() : null;
                var popupApi2 = ctx2 && ctx2.Popup ? ctx2.Popup : null;
                if (!popupApi2 || !popupApi2.show || typeof popupApi2.show.confirm !== 'function') return;
                var safeName = String(desiredName).replace(/[&<>"']/g, function(ch){
                    return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch] || ch);
                });
                var overwrite = await popupApi2.show.confirm('Overwrite layout preset', 'Layout preset "<b>' + safeName + '</b>" already exists. Overwrite it?');
                if (!overwrite) return;
            }catch(_eConf){ return; }
        }

        gigmaPrepareConvertedPresetSnapshot(snapshot, dstKind);
        snapshot.id = targetId;
        snapshot.name = desiredName;
        presets[targetId] = snapshot;
        gigmaSetLayoutPresetStore(presets, dstKind);

        try{
            if (dstKind === 'parent' && typeof gigmaUpdateChildrenUnchainedPositionsFromParentSnapshot === 'function') {
                gigmaUpdateChildrenUnchainedPositionsFromParentSnapshot(snapshot, targetId);
            }
        }catch(_eProp){}

        try{ if (typeof gigmaRefreshLayoutPresetSelect === 'function') gigmaRefreshLayoutPresetSelect(dstKind); }catch(_eRef){}
        try{ if (typeof gigmaSaveAllLorebookBudgetSettingsFromHeaders === 'function') gigmaSaveAllLorebookBudgetSettingsFromHeaders(dstKind, targetId); }catch(_eBud){}
        try{ if (typeof gigmaSetLastLayoutPresetId === 'function') gigmaSetLastLayoutPresetId(targetId, dstKind); }catch(_eLast){}
        try{ if (typeof gigmaShowScopedLayoutOrAssignmentPresetStatus === 'function') gigmaShowScopedLayoutOrAssignmentPresetStatus('Saved as ' + (dstKind === 'parent' ? 'parent' : 'child') + ' preset "' + desiredName + '".', 'success'); }catch(_eStat){}
    }catch(_){ }
}

function gigmaInitModalPresetConvertButtons(){
    try{
        if (typeof document === 'undefined') return;
        var root = document.getElementById('gigma-modal-root');
        if (!root) return;
        if (root.dataset && root.dataset.gigmaModalConvertWired === '1') return;
        if (root.dataset) root.dataset.gigmaModalConvertWired = '1';
        root.addEventListener('click', function(ev){
            try{
                var t = (ev && ev.target && ev.target.closest)
                    ? ev.target.closest('#gigma-modal-convert-parent,#gigma-modal-convert-child')
                    : null;
                if (!t) return;
                ev.preventDefault();
                ev.stopPropagation();
                gigmaConvertActivePresetToOtherKind(t.id === 'gigma-modal-convert-parent' ? 'parent' : 'child');
            }catch(_){ }
        }, true);
    }catch(_){ }
}
function gigmaBuildChildUnchainedPositionsFromParentSnapshot(parentSnapshot){
    const byChild = {};
    try{
        if (!parentSnapshot || typeof parentSnapshot !== 'object') return byChild;
        const childrenOrder = (parentSnapshot.childrenOrder && typeof parentSnapshot.childrenOrder === 'object') ? parentSnapshot.childrenOrder : null;
        if (!childrenOrder) return byChild;
        const parseUrow = (token) => {
            try{
                if (typeof token !== 'string') return null;
                if (token.indexOf('urowid:') !== 0) return null;
                const rest = token.slice(7);
                const parts = rest.split(':');
                if (parts.length < 2) return null;
                const encChild = parts[0];
                const wid = parts.slice(1).join(':');
                const child = decodeURIComponent(encChild || '');
                if (!child || !wid) return null;
                return { child, id: String(wid) };
            }catch(_){ return null; }
        };
        for (const parentKey of Object.keys(childrenOrder)){
            const list = childrenOrder[parentKey];
            if (!Array.isArray(list) || !list.length) continue;
            // Track last non-urow anchor token.
            let lastAnchor = null;
            for (let i = 0; i < list.length; i++){
                const token = list[i];
                if (typeof token !== 'string') continue;
                const u = parseUrow(token);
                if (u){
                    // Find next non-urow token as a fallback.
                    let before = null;
                    for (let j = i + 1; j < list.length; j++){
                        const t2 = list[j];
                        if (typeof t2 !== 'string') continue;
                        if (t2.indexOf('urowid:') === 0) continue;
                        if (t2.indexOf('folder:') === 0 || t2.indexOf('rowId:') === 0 || t2.indexOf('row:') === 0) {
                            before = t2;
                            break;
                        }
                    }
                    if (!byChild[u.child]) byChild[u.child] = {};
                    const ck = parentKey || 'ROOT';
                    if (!byChild[u.child][ck]) byChild[u.child][ck] = [];
                    byChild[u.child][ck].push({ id: u.id, after: lastAnchor, before });
                    continue;
                }
                // Update anchor.
                if (token.indexOf('folder:') === 0 || token.indexOf('rowId:') === 0 || token.indexOf('row:') === 0){
                    lastAnchor = token;
                }
            }
        }
    }catch(_){ }
    return byChild;
}
function gigmaStripLayoutFieldsForInheritedChildSnapshot(snapshot){
    try{
        if (!snapshot || typeof snapshot !== 'object') return;
        delete snapshot.childrenOrder;
        delete snapshot.folders;
        delete snapshot.folderParent;
        delete snapshot.rowFolder;
        // In inherited order mode, the child preset should not persist any order data.
        delete snapshot.retroLocksOrder;
        delete snapshot.retroLocks;
    }catch(_){ }
}
function gigmaRemoveChildUrowTokensFromParent(parentId, childId){
    try{
        const pid = (typeof parentId === 'string') ? parentId.trim() : '';
        if (!pid || pid === 'decoupled') return;
        const cid = (typeof childId === 'string') ? childId.trim() : '';
        if (!cid) return;
        const parentStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('parent') || {}) : {};
        const parentPreset = (parentStore && Object.prototype.hasOwnProperty.call(parentStore, pid)) ? parentStore[pid] : null;
        if (!parentPreset || typeof parentPreset !== 'object') return;
        const childrenOrder = (parentPreset.childrenOrder && typeof parentPreset.childrenOrder === 'object') ? parentPreset.childrenOrder : null;
        if (!childrenOrder) return;
        const prefix = 'urowid:' + encodeURIComponent(cid) + ':';
        let changed = false;
        for (const k of Object.keys(childrenOrder)){
            const arr = childrenOrder[k];
            if (!Array.isArray(arr) || !arr.length) continue;
            const next = arr.filter(t => !(typeof t === 'string' && t.indexOf(prefix) === 0));
            if (next.length !== arr.length) { childrenOrder[k] = next; changed = true; }
        }
        if (!changed) return;
        parentPreset.childrenOrder = childrenOrder;
        parentStore[pid] = parentPreset;
        if (typeof gigmaSetLayoutPresetStore === 'function') gigmaSetLayoutPresetStore(parentStore, 'parent');
    }catch(_){ }
}

function gigmaPrepareChildSnapshotForInheritedOrderSave(snapshot){
    try{
        if (!snapshot || typeof snapshot !== 'object') return;
        const parentId = (typeof snapshot.chatInheritOrderFromId === 'string') ? snapshot.chatInheritOrderFromId.trim() : '';
        if (!parentId || parentId === 'decoupled') return;

        const parentStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('parent') || {}) : {};
        const parentPreset = (parentStore && Object.prototype.hasOwnProperty.call(parentStore, parentId)) ? parentStore[parentId] : null;
        if (!parentPreset || typeof parentPreset !== 'object') return;

        // Persist folder collapsed/expanded state even when order is inherited.
        try{
            const map = {};
            const folders = Array.isArray(snapshot.folders) ? snapshot.folders : [];
            for (const f of folders){
                if (!f || f.id == null) continue;
                map[String(f.id)] = !!f.collapsed;
            }
            snapshot.folderCollapsedState = map;
        }catch(_){ }


        // Resolve the child preset ID (used in urowid tokens).
        let childId = (typeof snapshot.id === 'string') ? snapshot.id.trim() : '';
        if (!childId) {
            try{
                const sel = (typeof document !== 'undefined') ? document.getElementById('gigma-child-preset-select') : null;
                const v = (sel && typeof sel.value === 'string') ? sel.value.trim() : '';
                if (v) childId = v;
            }catch(_){ }
        }
        if (!childId) return;

        const unchained = (typeof gigmaGetUnchainedIdSetFromPreset === 'function')
            ? gigmaGetUnchainedIdSetFromPreset(snapshot)
            : new Set();
        const unchainedSet = (unchained instanceof Set) ? unchained : new Set();
        if (!unchainedSet.size) {
            try{ gigmaRemoveChildUrowTokensFromParent(parentId, childId); }catch(_){ }
            delete snapshot.unchainedPositions;
            gigmaStripLayoutFieldsForInheritedChildSnapshot(snapshot);
            return;
        }

        // Capture numeric indices (no anchors) for the child's unchained lorebooks in the DOM.
        const positions = (typeof gigmaCaptureUnchainedPositionsFromDom === 'function')
            ? gigmaCaptureUnchainedPositionsFromDom(unchainedSet)
            : {};

        try{
            const encChild = encodeURIComponent(String(childId));
            const prefix = 'urowid:' + encChild + ':';
            if (!parentPreset.childrenOrder || typeof parentPreset.childrenOrder !== 'object') parentPreset.childrenOrder = {};

            const tokenRowId = (token) => {
                try{
                    if (typeof token !== 'string') return null;
                    if (token.indexOf('rowId:') === 0) return token.slice(6) || null;
                    if (token.indexOf('row:') === 0) {
                        const nm = token.slice(4);
                        if (nm && window.gigmaWorldIdByName && window.gigmaWorldIdByName[nm]) return String(window.gigmaWorldIdByName[nm]);
                    }
                }catch(_){ }
                return null;
            };

            const isInvisibleOtherChildToken = (token) => (typeof token === 'string' && token.indexOf('urowid:') === 0 && token.indexOf(prefix) !== 0);

            const removeThisChildTokensEverywhere = () => {
                Object.keys(parentPreset.childrenOrder).forEach((k) => {
                    const arr = parentPreset.childrenOrder[k];
                    if (!Array.isArray(arr)) return;
                    parentPreset.childrenOrder[k] = arr.filter(t => !(typeof t === 'string' && t.indexOf(prefix) === 0));
                });
            };

            // Remove existing urowid tokens for this child, and remove normal row tokens for these unchained IDs
            // so the parent stores them only as urowid index tokens.
            const purgeUnchainedRowTokensEverywhere = () => {
                Object.keys(parentPreset.childrenOrder).forEach((k) => {
                    const arr = parentPreset.childrenOrder[k];
                    if (!Array.isArray(arr)) return;
                    parentPreset.childrenOrder[k] = arr.filter((t) => {
                        if (typeof t !== 'string') return true;
                        if (t.indexOf(prefix) === 0) return false;
                        const id = tokenRowId(t);
                        if (id && unchainedSet.has(String(id))) return false;
                        return true;
                    });
                });
            };

            removeThisChildTokensEverywhere();
            purgeUnchainedRowTokensEverywhere();

            const insertAtVisibleIndex = (list, visibleIndex, token) => {
                let v = 0;
                for (let i = 0; i <= list.length; i++){
                    if (v >= visibleIndex) { list.splice(i, 0, token); return; }
                    if (i === list.length) { list.push(token); return; }
                    const t = list[i];
                    if (isInvisibleOtherChildToken(t)) continue;
                    v++;
                }
                list.push(token);
            };

            // Insert urowid tokens into the parent preset using captured numeric indices.
            Object.keys(positions || {}).forEach((containerKeyRaw) => {
                const listPos = positions[containerKeyRaw];
                if (!Array.isArray(listPos) || !listPos.length) return;
                const containerKey = containerKeyRaw || 'ROOT';
                if (!Array.isArray(parentPreset.childrenOrder[containerKey])) parentPreset.childrenOrder[containerKey] = [];
                const container = parentPreset.childrenOrder[containerKey];

                // Sort by index ascending to build the final visible order deterministically.
                const sorted = listPos.slice().sort((a, b) => (a.index || 0) - (b.index || 0));
                for (const rec of sorted){
                    if (!rec || !rec.id) continue;
                    const wid = String(rec.id);
                    if (!unchainedSet.has(wid)) continue;
                    const idx = (typeof rec.index === 'number' && rec.index >= 0) ? rec.index : container.length;
                    insertAtVisibleIndex(container, idx, prefix + wid);
                }
            });

            // Ensure every unchained lorebook has some position token in the parent.
            if (!Array.isArray(parentPreset.childrenOrder.ROOT)) parentPreset.childrenOrder.ROOT = [];
            for (const wid of Array.from(unchainedSet)){
                const id = String(wid);
                let found = false;
                for (const k of Object.keys(parentPreset.childrenOrder)){
                    const arr = parentPreset.childrenOrder[k];
                    if (!Array.isArray(arr)) continue;
                    if (arr.indexOf(prefix + id) !== -1) { found = true; break; }
                }
                if (!found) parentPreset.childrenOrder.ROOT.push(prefix + id);
            }

            parentStore[parentId] = parentPreset;
            if (typeof gigmaSetLayoutPresetStore === 'function') gigmaSetLayoutPresetStore(parentStore, 'parent');
        }catch(_){ }

        delete snapshot.unchainedPositions;
        gigmaStripLayoutFieldsForInheritedChildSnapshot(snapshot);
    }catch(_){ }
}
function gigmaUpdateChildrenUnchainedPositionsFromParentSnapshot(parentSnapshot, parentName){
    try{
        if (!parentSnapshot || typeof parentSnapshot !== 'object') return;
        const pName = (parentName == null ? '' : String(parentName)).trim();
        if (!pName) return;
        const childStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        let changed = false;
        for (const childName of Object.keys(childStore || {})){
            const childPreset = childStore[childName];
            if (!childPreset || typeof childPreset !== 'object') continue;
            const inherit = (typeof childPreset.chatInheritOrderFromId === 'string') ? childPreset.chatInheritOrderFromId.trim() : '';
            if (inherit !== pName) continue;

            // Order inheritance no longer persists anchor-based unchained positions in child presets.
            if (Object.prototype.hasOwnProperty.call(childPreset, 'unchainedPositions')) {
                delete childPreset.unchainedPositions;
                changed = true;
            }
            gigmaStripLayoutFieldsForInheritedChildSnapshot(childPreset);
        }
        if (changed && typeof gigmaSetLayoutPresetStore === 'function') {
            gigmaSetLayoutPresetStore(childStore, 'child');
        }
    }catch(_){ }
}
function gigmaSyncParentUnchainedLorebooksInParent(){
    try{
        if (typeof document === 'undefined') return;
        const refreshEmptyFolderPlaceholders = () => {
            try{
                if (typeof window !== 'undefined' && typeof window.gigmaRefreshEmptyFoldersUI === 'function') {
                    window.gigmaRefreshEmptyFoldersUI();
                } else if (typeof gigmaRefreshEmptyFoldersUI === 'function') {
                    gigmaRefreshEmptyFoldersUI();
                }
            }catch(_){ }
        };
        const cleanupAndRefresh = () => {
            try{
                document.querySelectorAll('.gigma-row.gigma-parent-unchained-placeholder').forEach(el => { try{ el.remove(); }catch(_){ } });
            }catch(_){ }
            refreshEmptyFolderPlaceholders();
        };

        const kindBtn = document.getElementById('gigma-layout-preset-kind-toggle');
        const isParent = !!(kindBtn && kindBtn.dataset && kindBtn.dataset.gigmaPresetKind === 'parent');
        if (!isParent) {
            cleanupAndRefresh();
            return;
        }

        try{
            if (document.documentElement && document.documentElement.classList && document.documentElement.classList.contains('gigma-budget-mode-active')){
                cleanupAndRefresh();
                return;
            }
        }catch(_){ }

        const parentSel = document.getElementById('gigma-parent-preset-select');
        const parentName = (parentSel && typeof parentSel.value === 'string') ? parentSel.value.trim() : '';
        if (!parentName){
            cleanupAndRefresh();
            return;
        }

        const parentStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('parent') || {}) : {};
        const parentPreset = (parentStore && Object.prototype.hasOwnProperty.call(parentStore, parentName)) ? parentStore[parentName] : null;
        const childrenOrder = (parentPreset && parentPreset.childrenOrder && typeof parentPreset.childrenOrder === 'object') ? parentPreset.childrenOrder : {};

        const visSel = gigmaGetParentUnchainedVisibilitySelect();
        const vis = (visSel && typeof visSel.value === 'string') ? visSel.value.trim() : 'hide';
        const multi = gigmaGetParentUnchainedChildPresetsSelect();
        const selected = gigmaGetMultiSelectValues(multi);
        const asSel = gigmaGetParentUnchainedAsSelect();
        const asMode = (asSel && typeof asSel.value === 'string') ? asSel.value.trim() : 'text between lorebooks';
        const editableUnchained = (typeof gigmaIsEditableUnchainedLorebooksEnabled === 'function')
            ? gigmaIsEditableUnchainedLorebooksEnabled('parent', 'order')
            : false;

        const childStore = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        const inheriting = Object.keys(childStore).filter((k) => {
            try{
                const snap = childStore[k];
                const v = (snap && typeof snap.chatInheritOrderFromId === 'string') ? snap.chatInheritOrderFromId.trim() : '';
                return v && v === parentName;
            }catch(_){ return false; }
        }).sort((a,b) => {
            const an = (childStore[a] && typeof childStore[a].name === 'string') ? childStore[a].name.trim() : '';
            const bn = (childStore[b] && typeof childStore[b].name === 'string') ? childStore[b].name.trim() : '';
            return an.localeCompare(bn);
        });

        const tokensByChild = {};
        try{
            Object.keys(childrenOrder || {}).forEach((parentKey) => {
                const list = childrenOrder[parentKey];
                if (!Array.isArray(list)) return;
                const ck = parentKey || 'ROOT';
                for (const token of list){
                    if (typeof token !== 'string') continue;
                    if (token.indexOf('urowid:') !== 0) continue;
                    const rest = token.slice(7);
                    const sep = rest.indexOf(':');
                    if (sep <= -1) continue;
                    const encChild = rest.slice(0, sep);
                    const wid = rest.slice(sep + 1);
                    const childId = decodeURIComponent(encChild || '');
                    if (!childId || !wid) continue;
                    if (!tokensByChild[childId]) tokensByChild[childId] = {};
                    if (!Array.isArray(tokensByChild[childId][ck])) tokensByChild[childId][ck] = [];
                    tokensByChild[childId][ck].push(String(wid));
                }
            });
        }catch(_){ }

        const existing = new Map();
        try{
            document.querySelectorAll('.gigma-row.gigma-parent-unchained-placeholder').forEach((el) => {
                try{
                    const id = (el.dataset && (el.dataset.worldId || el.dataset.world)) ? String(el.dataset.worldId || el.dataset.world) : '';
                    const child = (el.dataset && el.dataset.gigmaParentUnchainedChild) ? String(el.dataset.gigmaParentUnchainedChild) : '';
                    if (id && child) existing.set(child + '|' + id, el);
                }catch(_){ }
            });
        }catch(_){ }

        const desired = new Set();

        const ensureInListByIndex = (el, listEl, containerKey, childId, wid) => {
            try{
                if (!el || !listEl) return;
                if (el.parentNode === listEl) return;
                const enc = encodeURIComponent(String(childId));
                const tok = 'urowid:' + enc + ':' + String(wid);
                const order = Array.isArray(childrenOrder[containerKey]) ? childrenOrder[containerKey] : (containerKey === 'ROOT' && Array.isArray(childrenOrder.ROOT) ? childrenOrder.ROOT : []);
                let idx = -1;
                for (let i = 0; i < order.length; i++){
                    if (order[i] === tok) { idx = i; break; }
                }
                if (idx === -1) {
                    listEl.appendChild(el);
                    return;
                }
                const findNode = (t) => {
                    try{
                        if (typeof t !== 'string') return null;
                        if (t.indexOf('folder:') === 0) {
                            const fid = t.slice(7);
                            return fid ? listEl.querySelector('.gigma-folder[data-folder-id="' + CSS.escape(fid) + '"]') : null;
                        }
                        if (t.indexOf('rowId:') === 0) {
                            const id = t.slice(6);
                            return id ? listEl.querySelector('.gigma-row[data-world-id="' + CSS.escape(id) + '"]:not(.gigma-parent-unchained-placeholder)') : null;
                        }
                        if (t.indexOf('row:') === 0) {
                            const nm = t.slice(4);
                            return nm ? listEl.querySelector('.gigma-row[data-world="' + CSS.escape(nm) + '"]:not(.gigma-parent-unchained-placeholder)') : null;
                        }
                        if (t.indexOf('urowid:') === 0) {
                            const rr = t.slice(7);
                            const sp = rr.indexOf(':');
                            if (sp <= -1) return null;
                            const ec = decodeURIComponent(rr.slice(0, sp) || '');
                            const ww = rr.slice(sp + 1);
                            if (!ec || !ww) return null;
                            const key = ec + '|' + ww;
                            return existing.get(key) || null;
                        }
                    }catch(_){ }
                    return null;
                };
                for (let j = idx + 1; j < order.length; j++){
                    const n = findNode(order[j]);
                    if (n && n.parentNode === listEl) {
                        listEl.insertBefore(el, n);
                        return;
                    }
                }
                listEl.appendChild(el);
            }catch(_){ }
        };

        for (const childId of inheriting){
            const tmap = tokensByChild[childId] || {};
            const isSelected = selected.includes(childId);
            const isShownChild = (vis === 'show') && isSelected;
            const showAsTextBetween = isShownChild && (asMode === 'text between lorebooks');
            const showAsFullSized = isShownChild && (asMode === 'full-sized lorebooks');
            const rowReadonly = (!editableUnchained) || showAsTextBetween;
            const useGhost = !showAsFullSized;
            const useNoText = useGhost && !showAsTextBetween;

            for (const containerKey of Object.keys(tmap || {})){
                const listEl = gigmaGetListElForContainerKey(containerKey) || gigmaGetListElForContainerKey('ROOT');
                if (!listEl) continue;
                const ids = tmap[containerKey];
                if (!Array.isArray(ids)) continue;
                for (const wid of ids){
                    const id = String(wid);
                    const key = childId + '|' + id;
                    desired.add(key);
                    let ph = existing.get(key);
                    if (!ph || !ph.isConnected) {
                        ph = gigmaGetOrCreateParentUnchainedPlaceholderRow(id, childId);
                    }
                    if (!ph) continue;
                    existing.set(key, ph);
                    try{ ph.dataset.gigmaParentUnchainedChild = String(childId); }catch(_){ }
                    try{ ph.classList.toggle('gigma-parent-unchained-hidden', false); }catch(_){ }
                    try{ ph.classList.toggle('gigma-parent-unchained-ghost', useGhost); }catch(_){ }
                    try{ ph.classList.toggle('gigma-parent-unchained-notext', useNoText); }catch(_){ }
                    try{ ph.classList.toggle('gigma-unchained-readonly', !!rowReadonly); }catch(_){ }
                    try{ ph.setAttribute('draggable', rowReadonly ? 'false' : 'true'); }catch(_){ }
                    try{ if (ph.dataset) ph.dataset.gigmaNonInteractive = rowReadonly ? '1' : '0'; }catch(_){ }

                    try{
                        if (showAsTextBetween) {
                            if (typeof gigmaUpdateParentUnchainedGhostText === 'function') gigmaUpdateParentUnchainedGhostText(ph, childId);
                        } else {
                            const g = ph.querySelector('.gigma-parent-unchained-ghost-text');
                            if (g) g.textContent = '';
                            try{ ph.dataset.gigmaParentUnchainedGhostEntry = ''; }catch(_){ }
                        }
                    }catch(_){ }

                    if (!ph.isConnected) ensureInListByIndex(ph, listEl, containerKey || 'ROOT', childId, id);
                    try{ gigmaUpdateModalLorebookRowStats(ph); }catch(_){ }
                }
            }
        }

        existing.forEach((el, key) => {
            try{
                if (!desired.has(key)){
                    try{ el.remove(); }catch(_){ }
                }
            }catch(_){ }
        });

        try{ if (typeof gigmaReflowParentUnchainedGhostMarkers === 'function') gigmaReflowParentUnchainedGhostMarkers(); }catch(_){ }
        try{ if (typeof window.gigmaRenumberRows === 'function') window.gigmaRenumberRows(); }catch(_){ }
        try{ if (typeof window.gigmaUpdateFolderRanges === 'function') window.gigmaUpdateFolderRanges(); }catch(_){ }

        refreshEmptyFolderPlaceholders();
        try{ if (typeof gigmaApplyUnchainedReadonlyStateToRows === 'function') gigmaApplyUnchainedReadonlyStateToRows('parent', 'order'); }catch(_){ }
        try{ if (typeof gigmaUpdateLorebookContentExpandersInModal === 'function') gigmaUpdateLorebookContentExpandersInModal(); }catch(_){ }
        try{ if (typeof gigmaInitSortable === 'function') gigmaInitSortable(); }catch(_){ }
    }catch(_){ }
}
/* ---------------- End parent unchained lorebook placeholders ---------------- */

/* ---------------- Parent presets: Budget mode unchained lorebook rows ---------------- */
function gigmaGetParentBudgetUnchainedSection(){
    try{ return (typeof document !== 'undefined') ? document.getElementById('gigma-inherit-parent-budget') : null; }catch(_){ return null; }
}
function gigmaGetParentBudgetUnchainedVisibilitySelect(){
    try{ return (typeof document !== 'undefined') ? document.getElementById('gigma-parent-budget-unchained-visibility') : null; }catch(_){ return null; }
}
function gigmaGetParentBudgetUnchainedChildPresetsSelect(){
    try{ return (typeof document !== 'undefined') ? document.getElementById('gigma-parent-budget-unchained-childpresets') : null; }catch(_){ return null; }
}
function gigmaListChildPresetsInheritingBudgetFromParent(parentPresetId){
    const out = [];
    try{
        const parentId = (typeof parentPresetId === 'string') ? parentPresetId.trim() : '';
        if (!parentId) return out;
        const childPresets = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        for (const id of Object.keys(childPresets || {})){
            const snap = childPresets[id];
            const v = (snap && typeof snap.budgetInheritFromId === 'string') ? snap.budgetInheritFromId.trim() : '';
            if (v && v === parentId) out.push(id);
        }
    }catch(_){}
    try{
        const childPresets = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        out.sort((a,b)=>{
            const an = (childPresets[a] && typeof childPresets[a].name === 'string') ? childPresets[a].name.trim() : '';
            const bn = (childPresets[b] && typeof childPresets[b].name === 'string') ? childPresets[b].name.trim() : '';
            return an.localeCompare(bn);
        });
    }catch(_){}
    return out;
}

/**
 * Ensure the Budget-mode parent "unchained lorebooks" section exists only when
 * the current parent preset has child presets inheriting budget from it.
 * Returns true when the section exists after this call.
 */
function gigmaEnsureParentBudgetUnchainedSection(parentPresetId){
    try{
        if (typeof document === 'undefined') return false;
        const parentName = (typeof parentPresetId === 'string') ? parentPresetId.trim() : '';
        const inheriting = gigmaListChildPresetsInheritingBudgetFromParent(parentName);
        const existing = gigmaGetParentBudgetUnchainedSection();
        if (!inheriting.length){
            if (existing) { try{ existing.remove(); }catch(_){ } }
            return false;
        }
        if (existing && existing.isConnected) return true;

        const area = document.getElementById('gigma-inherit-area');
        if (!area) return false;

        const wrap = document.createElement('div');
        wrap.id = 'gigma-inherit-parent-budget';
        wrap.className = 'gigma-inherit-parent gigma-inherit-parent-budget';
        wrap.style.display = 'none';

        const row = document.createElement('div');
        row.className = 'gigma-parent-unchained-row';

        const visSel = document.createElement('select');
        visSel.id = 'gigma-parent-budget-unchained-visibility';
        visSel.className = 'text_pole textarea_compact gigma-parent-unchained-visibility';
        const optShow = document.createElement('option');
        optShow.value = 'show';
        optShow.textContent = 'Show';
        visSel.appendChild(optShow);
        const optHide = document.createElement('option');
        optHide.value = 'hide';
        optHide.textContent = 'Hide';
        visSel.appendChild(optHide);
        try{ visSel.value = 'hide'; }catch(_){}

        const label = document.createElement('span');
        label.className = 'gigma-parent-unchained-label';
        label.textContent = 'unchained lorebooks.';

        row.appendChild(visSel);
        row.appendChild(label);

        const multi = document.createElement('select');
        multi.id = 'gigma-parent-budget-unchained-childpresets';
        multi.className = 'text_pole textarea_compact gigma-parent-unchained-childpresets';
        multi.multiple = true;
        multi.style.width = '100%';

        
        multi.style.display = 'none';
wrap.appendChild(row);
        wrap.appendChild(multi);

        // Insert alongside the existing inherit rows (keep consistent vertical rhythm).
        try{
            const childWrap = document.getElementById('gigma-inherit-child');
            const parentOrderWrap = document.getElementById('gigma-inherit-parent');
            if (parentOrderWrap && parentOrderWrap.parentNode === area){
                area.insertBefore(wrap, parentOrderWrap.nextSibling);
            }else if (childWrap && childWrap.parentNode === area){
                area.insertBefore(wrap, childWrap.nextSibling);
            }else{
                area.appendChild(wrap);
            }
        }catch(_){
            area.appendChild(wrap);
        }
        return true;
    }catch(_){
        return false;
    }
}
function gigmaRefreshParentBudgetUnchainedChildPresetOptions(parentPresetId, desiredSelection){
    try{
        if (typeof document === 'undefined') return;
        const select = gigmaGetParentBudgetUnchainedChildPresetsSelect();
        if (!select) return;
        const parentId = (typeof parentPresetId === 'string') ? parentPresetId.trim() : '';
        const currentSel = Array.isArray(desiredSelection) ? desiredSelection : gigmaGetMultiSelectValues(select);
        let eligible = [];
        let childPresets = {};
        try{
            childPresets = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
            eligible = Object.keys(childPresets || {}).filter((id) => {
                const snap = childPresets[id];
                const v = (snap && typeof snap.budgetInheritFromId === 'string') ? snap.budgetInheritFromId.trim() : '';
                return parentId && v === parentId;
            }).sort((a,b) => {
                const an = (childPresets[a] && typeof childPresets[a].name === 'string') ? childPresets[a].name.trim() : '';
                const bn = (childPresets[b] && typeof childPresets[b].name === 'string') ? childPresets[b].name.trim() : '';
                return an.localeCompare(bn);
            });
        }catch(_eList){
            eligible = [];
            childPresets = {};
        }
        try{ select.innerHTML = ''; }catch(_){}
        eligible.forEach((id) => {
            const snap = childPresets[id];
            const nm = (snap && typeof snap.name === 'string') ? snap.name.trim() : '';
            const opt = document.createElement('option');
            opt.value = id;
            opt.textContent = nm;
            if (currentSel && currentSel.includes(id)) opt.selected = true;
            select.appendChild(opt);
        });
        const finalSel = (Array.isArray(currentSel) ? currentSel : []).filter(v => eligible.includes(v));
        try{
            if (typeof $ === 'function' && $.fn?.select2 && $(select).length){
                $(select).val(finalSel).trigger('change');
            }else{
                Array.from(select.options || []).forEach((o) => {
                    o.selected = finalSel.includes(o.value);
                });
            }
        }catch(_eApply){}
    }catch(_){}
}

function gigmaUpdateParentBudgetUnchainedUiVisibility(){
    try{
        if (typeof document === 'undefined') return;
        const wrap = gigmaGetParentBudgetUnchainedSection();
        const visSel = gigmaGetParentBudgetUnchainedVisibilitySelect();
        const multi = gigmaGetParentBudgetUnchainedChildPresetsSelect();
        const label = wrap ? wrap.querySelector('.gigma-parent-unchained-label') : null;
        if (!wrap || !visSel || !multi || !label) return;

        const isHide = (String(visSel.value || '').trim() === 'hide');
        try{ label.textContent = isHide ? 'unchained lorebooks.' : 'unchained lorebooks of'; }catch(_){}

        const show = !isHide;

        try{ multi.style.display = show ? '' : 'none'; }catch(_){}

        try{
            if (typeof $ === 'function' && $.fn?.select2 && $(multi).length && $(multi).data('select2')){
                const cont = $(multi).data('select2').$container;
                if (cont && cont.length) cont[0].style.display = show ? '' : 'none';
            }else{
                const cont = multi.parentElement ? multi.parentElement.querySelector('.select2') : null;
                if (cont) cont.style.display = show ? '' : 'none';
            }
        }catch(_){}
    }catch(_){}
}

function gigmaInitParentBudgetUnchainedControls(parentPresetId){
    try{
        if (typeof document === 'undefined') return;
        const parentName = (typeof parentPresetId === 'string') ? parentPresetId.trim() : '';
        if (!gigmaEnsureParentBudgetUnchainedSection(parentName)) return;

        const visSel = gigmaGetParentBudgetUnchainedVisibilitySelect();
        const multi = gigmaGetParentBudgetUnchainedChildPresetsSelect();
        if (!visSel || !multi) return;
        if (multi.dataset && multi.dataset.gigmaBudgetUnchainedWired === '1') return;
        if (multi.dataset) multi.dataset.gigmaBudgetUnchainedWired = '1';

        // Select2 multi-select
        try{
            if (typeof $ === 'function' && $.fn?.select2 && $(multi).length){
                if (!$(multi).data('select2')){
                    $(multi).select2({
                        width: '100%',
                        placeholder: 'Select child presets…',
                        allowClear: true,
                        closeOnSelect: false,
                        dropdownParent: $(multi).closest('.popup-content, .popup-body, [role="dialog"]').first()
                    });
                }
            }
        }catch(_eSel2){
            console.warn('GIGMA: failed to init parent budget unchained child presets Select2:', _eSel2);
        }

        try{ gigmaWireSelect2ChoiceToChildPresetSwitch(multi); }catch(_){ }

        const refresh = () => {
            try{ gigmaRefreshParentBudgetUnchainedChildPresetOptions(parentName); }catch(_){}
        };
        try{
            multi.addEventListener('mousedown', refresh);
            multi.addEventListener('focus', refresh);
        }catch(_){}

        const onChange = () => {
            try{ if (typeof gigmaUpdateParentBudgetUnchainedUiVisibility === 'function') gigmaUpdateParentBudgetUnchainedUiVisibility(); }catch(_){ }
            try{ gigmaSyncParentBudgetUnchainedLorebooksInParent(); }catch(_){ }
            try{ gigmaEnsureInheritAreaHeightLocked(); }catch(_){ }
        };
        try{ visSel.addEventListener('change', onChange); }catch(_){}
        try{ multi.addEventListener('change', onChange); }catch(_){}
        try{
            if (typeof $ === 'function' && $.fn?.select2 && $(multi).length){
                $(multi).on('change.select2', onChange);
                $(multi).on('select2:select', onChange);
                $(multi).on('select2:unselect', onChange);
                $(multi).on('select2:clear', onChange);
            }
        }catch(_){}

        // Apply initial visibility state.
        try{ if (typeof gigmaUpdateParentBudgetUnchainedUiVisibility === 'function') gigmaUpdateParentBudgetUnchainedUiVisibility(); }catch(_){ }

    }catch(_){}
}
function gigmaApplyParentBudgetUnchainedSettingsFromPreset(preset, parentPresetId){
    try{
        if (!preset || typeof document === 'undefined') return;
        const parentName = (typeof parentPresetId === 'string') ? parentPresetId.trim() : '';
        if (!gigmaEnsureParentBudgetUnchainedSection(parentName)) return;
        gigmaInitParentBudgetUnchainedControls(parentName);

        const visSel = gigmaGetParentBudgetUnchainedVisibilitySelect();
        const select = gigmaGetParentBudgetUnchainedChildPresetsSelect();

        const rawVis = (preset && typeof preset.parentUnchainedBudgetLorebooksVisibility === 'string')
            ? preset.parentUnchainedBudgetLorebooksVisibility.trim()
            : '';
        const vis = (rawVis === 'show' || rawVis === 'hide') ? rawVis : 'hide';
        if (visSel) {
            try{
                const supported = Array.from(visSel.options || []).some(o => o && o.value === vis);
                visSel.value = supported ? vis : 'hide';
            }catch(_){ try{ visSel.value = 'hide'; }catch(__){} }
        }
        const desired = Array.isArray(preset.parentUnchainedBudgetLorebooksChildPresetIds)
            ? preset.parentUnchainedBudgetLorebooksChildPresetIds.map(v => (v == null ? '' : String(v)).trim()).filter(v => v)
            : [];
        gigmaRefreshParentBudgetUnchainedChildPresetOptions(parentName, desired);
        if (select) {
            try{
                if (typeof $ === 'function' && $.fn?.select2 && $(select).length){
                    $(select).trigger('change');
                }
            }catch(_){}
        }
        try{ if (typeof gigmaUpdateParentBudgetUnchainedUiVisibility === 'function') gigmaUpdateParentBudgetUnchainedUiVisibility(); }catch(_){ }
        try{ gigmaSyncParentBudgetUnchainedLorebooksInParent(); }catch(_){ }

    }catch(_){}
}
function gigmaGetOrCreateParentBudgetUnchainedRow(worldId, worldName, childPresetId){
    try{
        if (typeof document === 'undefined') return null;
        const id = (worldId == null ? '' : String(worldId)).trim();
        const child = (childPresetId == null ? '' : String(childPresetId)).trim();
        if (!id || !child) return null;
        if (!window.__gigmaParentBudgetUnchainedRowByKey) window.__gigmaParentBudgetUnchainedRowByKey = {};
        const key = child + '|' + id;
        let el = window.__gigmaParentBudgetUnchainedRowByKey[key];
        if (el && el.isConnected) {
            try{
                const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
                const p = store && store[child];
                const childShort = (p && typeof p.name === 'string') ? p.name.trim().slice(0, 15) : '';
                const label = el.querySelector('.gigma-row-label');
                const rawName = (el.dataset && el.dataset.world) ? String(el.dataset.world) : String(worldName || '');
                __gigmaRenderUnchainedRowLabel(label, rawName, childShort, true, false);
            }catch(_){}
            return el;
        }

        // Clone an existing base row so styling matches.
        let base = null;
        try{
            base = document.querySelector('.gigma-row[data-world-id="' + CSS.escape(id) + '"]:not(.gigma-parent-budget-unchained-row):not(.gigma-parent-unchained-placeholder)');
        }catch(_){ base = null; }
        if (!base) return null;
        el = base.cloneNode(true);
        el.classList.add('gigma-parent-budget-unchained-row');
        try{ el.classList.remove('gigma-parent-unchained-placeholder'); }catch(_){}

        // Remove any existing origin tags from cloned rows.
        try{
            el.querySelectorAll('.gigma-parent-unchained-origin-tag').forEach(t => { try{ t.remove(); }catch(_){ } });
        }catch(_){}

        // Ensure budget controls are (re)built from dataset.
        try{
            if (typeof gigmaDetachBudgetHeaderControlsFromRow === 'function') gigmaDetachBudgetHeaderControlsFromRow(el);
        }catch(_){}

        // Left controls: start empty; budget controls are attached later from the child preset (read-only).
        try{
            const leftControls = el.querySelector('.gigma-row-left-controls');
            if (leftControls) leftControls.innerHTML = '';
        }catch(_){}

        // Label: show unchained icon + usage icons + bound-owner tag.
        try{
            const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
            const p = store && store[child];
            const childShort = (p && typeof p.name === 'string') ? p.name.trim().slice(0, 15) : '';
            const label = el.querySelector('.gigma-row-label');
            __gigmaRenderUnchainedRowLabel(label, String(worldName || ''), childShort, true, false);
        }catch(_){}

        try{ el.dataset.worldId = id; }catch(_){}
        try{ el.dataset.world = String(worldName || ''); }catch(_){}
        try{ el.dataset.gigmaParentUnchainedChild = child; }catch(_){}

        window.__gigmaParentBudgetUnchainedRowByKey[key] = el;
        return el;
    }catch(_){
        return null;
    }
}
function gigmaSyncParentBudgetUnchainedLorebooksInParent(){
    try{
        if (typeof document === 'undefined') return;
        const cleanup = () => {
            try{
                document.querySelectorAll('.gigma-row.gigma-parent-budget-unchained-row').forEach(el => { try{ el.remove(); }catch(_){ } });
            }catch(_){ }
        };

        const kindBtn = document.getElementById('gigma-layout-preset-kind-toggle');
        const isParent = !!(kindBtn && kindBtn.dataset && kindBtn.dataset.gigmaPresetKind === 'parent');
        if (!isParent) { cleanup(); return; }
        if (!gigmaIsBudgetModeActive()) { cleanup(); return; }

        const parentSel = document.getElementById('gigma-parent-preset-select');
        const parentName = (parentSel && typeof parentSel.value === 'string') ? parentSel.value.trim() : '';
        if (!parentName) { cleanup(); return; }

        if (!gigmaEnsureParentBudgetUnchainedSection(parentName)) { cleanup(); return; }

        const visSel = gigmaGetParentBudgetUnchainedVisibilitySelect();
        const vis = (visSel && typeof visSel.value === 'string') ? visSel.value.trim() : 'hide';
        const multi = gigmaGetParentBudgetUnchainedChildPresetsSelect();
        const selected = gigmaGetMultiSelectValues(multi);
        const editableUnchained = (typeof gigmaIsEditableUnchainedLorebooksEnabled === 'function')
            ? gigmaIsEditableUnchainedLorebooksEnabled('parent', 'budget')
            : false;

        const store = (typeof gigmaGetLayoutPresetStore === 'function') ? (gigmaGetLayoutPresetStore('child') || {}) : {};
        const inheriting = gigmaListChildPresetsInheritingBudgetFromParent(parentName);

        const existing = new Map();
        try{
            document.querySelectorAll('.gigma-row.gigma-parent-budget-unchained-row').forEach((el) => {
                try{
                    const id = (el.dataset && (el.dataset.worldId || el.dataset.world)) ? String(el.dataset.worldId || el.dataset.world) : '';
                    const child = (el.dataset && el.dataset.gigmaParentUnchainedChild) ? String(el.dataset.gigmaParentUnchainedChild) : '';
                    if (id && child) existing.set(child + '|' + id, el);
                }catch(_){ }
            });
        }catch(_){ }

        const desired = new Set();

        if (vis === 'show') {
            for (const childName of inheriting){
                if (!selected.includes(childName)) continue;
                const childPreset = store[childName];
                if (!childPreset || typeof childPreset !== 'object') continue;
                const lockSet = (typeof gigmaGetRetroBudgetLockSetFromPreset === 'function')
                    ? gigmaGetRetroBudgetLockSetFromPreset(childPreset)
                    : new Set();
                if (!lockSet || !lockSet.size) continue;

                for (const wid of Array.from(lockSet)){
                    const id = String(wid);
                    let worldName = '';
                    try{
                        if (window.gigmaNameByWorldId && window.gigmaNameByWorldId[id]) worldName = String(window.gigmaNameByWorldId[id]);
                    }catch(_){ }
                    if (!worldName){
                        try{
                            const real = document.querySelector('.gigma-row[data-world-id="' + CSS.escape(id) + '"]:not(.gigma-parent-budget-unchained-row):not(.gigma-parent-unchained-placeholder)');
                            if (real && real.dataset && real.dataset.world) worldName = String(real.dataset.world);
                        }catch(_){ }
                    }
                    if (!worldName) continue;

                    const key = childName + '|' + id;
                    desired.add(key);

                    let row = existing.get(key);
                    let rowWasNew = false;
                    if (!row || !row.isConnected) {
                        row = gigmaGetOrCreateParentBudgetUnchainedRow(id, worldName, childName);
                        rowWasNew = true;
                    }
                    if (!row) continue;
                    existing.set(key, row);

                    const rowReadonly = !editableUnchained;
                    try{ row.classList.toggle('gigma-unchained-readonly', !!rowReadonly); }catch(_){ }
                    try{ row.setAttribute('draggable', rowReadonly ? 'false' : 'true'); }catch(_){ }

                    try{
                        const map = (childPreset.lorebookSettings && typeof childPreset.lorebookSettings === 'object')
                            ? childPreset.lorebookSettings
                            : {};
                        const data = (map && map[id] && typeof map[id] === 'object') ? map[id] : {};
                        const merged = Object.assign({}, DEFAULT_LOREBOOK_SETTINGS || {}, data || {});
                        const mode = (typeof gigmaNormalizeBudgetHeaderMode === 'function')
                            ? gigmaNormalizeBudgetHeaderMode(merged.budgetMode || 'default')
                            : (merged.budgetMode || 'default');
                        const val = (typeof merged.budget === 'number' && !Number.isNaN(merged.budget)) ? merged.budget : 0;
                        const rt = !!merged.randomTrim;
                        if (row.dataset){
                            row.dataset.gigmaBudgetMode = mode || 'default';
                            row.dataset.gigmaBudgetValue = String((val && Number.isFinite(val)) ? val : 0);
                            row.dataset.gigmaRandomTrim = rt ? '1' : '0';
                        }
                        if (typeof gigmaAttachBudgetHeaderControlsToRow === 'function') gigmaAttachBudgetHeaderControlsToRow(row);

                        const sel = row.querySelector('.gigma-budget-header-select');
                        const inp = row.querySelector('.gigma-budget-header-value');
                        if (sel) { sel.disabled = !!rowReadonly; sel.tabIndex = rowReadonly ? -1 : 0; }
                        if (inp) { inp.disabled = false; inp.readOnly = !!rowReadonly; inp.tabIndex = rowReadonly ? -1 : 0; }
                    }catch(_){ }

                    try{
                        const tag = row.querySelector('.gigma-parent-unchained-origin-tag');
                        if (tag) tag.textContent = (childPreset && typeof childPreset.name === 'string') ? childPreset.name.trim().slice(0, 15) : '';
                    }catch(_){ }

                    if (rowWasNew) {
                        let parentRow = null;
                        try{
                            parentRow = document.querySelector('.gigma-row[data-world-id="' + CSS.escape(id) + '"]:not(.gigma-parent-budget-unchained-row):not(.gigma-parent-unchained-placeholder)');
                        }catch(_){ parentRow = null; }
                        if (parentRow && parentRow.parentNode) {
                            let insertAfter = parentRow;
                            try{
                                let n = parentRow.nextSibling;
                                while (n && n.classList && n.classList.contains('gigma-parent-budget-unchained-row') &&
                                       n.dataset && String(n.dataset.worldId || '') === id) {
                                    insertAfter = n;
                                    n = n.nextSibling;
                                }
                            }catch(_){ }
                            try{
                                if (insertAfter.nextSibling) insertAfter.parentNode.insertBefore(row, insertAfter.nextSibling);
                                else insertAfter.parentNode.appendChild(row);
                            }catch(_){
                                try{ parentRow.parentNode.insertBefore(row, parentRow.nextSibling); }catch(__){ }
                            }
                        }
                    }
                    try{ gigmaUpdateModalLorebookRowStats(row); }catch(_){ }
                }
            }
        }

        existing.forEach((el, key) => {
            try{
                if (!desired.has(key)){
                    try{ el.remove(); }catch(_){ }
                }
            }catch(_){ }
        });

        try{ if (typeof gigmaApplyUnchainedReadonlyStateToRows === 'function') gigmaApplyUnchainedReadonlyStateToRows('parent', 'budget'); }catch(_){ }
        try{ if (typeof gigmaUpdateLorebookContentExpandersInModal === 'function') gigmaUpdateLorebookContentExpandersInModal(); }catch(_){ }
    }catch(_){ }
}
/* ---------------- End parent budget unchained lorebook rows ---------------- */

/** Show/hide the inherit-area contents based on preset kind + Order/Budget mode. */
function gigmaUpdateInheritAreaVisibility(){
    try{
        if (typeof document === 'undefined') return;
        const kindBtn = document.getElementById('gigma-layout-preset-kind-toggle');
        const kind = (kindBtn && kindBtn.dataset && kindBtn.dataset.gigmaPresetKind === 'parent') ? 'parent' : 'child';
        const isParentPresetKind = (kind === 'parent');
        const inBudget = gigmaIsBudgetModeActive();
        const childWrap = document.getElementById('gigma-inherit-child');
        const parentWrap = document.getElementById('gigma-inherit-parent');
        if (childWrap) childWrap.style.display = isParentPresetKind ? 'none' : 'flex';
        if (parentWrap) parentWrap.style.display = (isParentPresetKind && !inBudget) ? 'flex' : 'none';
        // Budget-mode Parent presets: show a separate "unchained lorebooks" section (created only when needed).
        try{
            if (isParentPresetKind && inBudget){
                const pName = (function(){
                    try{
                        const s = document.getElementById('gigma-parent-preset-select');
                        return s && typeof s.value === 'string' ? s.value.trim() : '';
                    }catch(_){ return ''; }
                })();
                try{ gigmaEnsureParentBudgetUnchainedSection(pName); }catch(_){}
                const bw = (typeof gigmaGetParentBudgetUnchainedSection === 'function') ? gigmaGetParentBudgetUnchainedSection() : null;
                if (bw) bw.style.display = 'flex';
            }else{
                const bw = (typeof gigmaGetParentBudgetUnchainedSection === 'function') ? gigmaGetParentBudgetUnchainedSection() : null;
                if (bw) bw.style.display = 'none';
            }
        }catch(_){ }
        // Make sure Parent controls exist + options are correct when Parent preset is active.
        if (isParentPresetKind) {
            try{ gigmaInitParentUnchainedControls(); }catch(_){}
            try{
                if (inBudget){
                    const pName = (function(){
                        try{
                            const s = document.getElementById('gigma-parent-preset-select');
                            return s && typeof s.value === 'string' ? s.value.trim() : '';
                        }catch(_){ return ''; }
                    })();
                    gigmaInitParentBudgetUnchainedControls(pName);
                    try{ gigmaSyncParentBudgetUnchainedLorebooksInParent(); }catch(_){}
                }
            }catch(_){}

            try{
                if (inBudget){
                    const pName = (function(){
                        try{
                            const s = document.getElementById('gigma-parent-preset-select');
                            return s && typeof s.value === 'string' ? s.value.trim() : '';
                        }catch(_){ return ''; }
                    })();
                    gigmaInitParentBudgetUnchainedControls(pName);
                }
            }catch(_){ }
            try{
                const parentName = (function(){
                    try{
                        const s = document.getElementById('gigma-parent-preset-select');
                        return s && typeof s.value === 'string' ? s.value.trim() : '';
                    }catch(_){ return ''; }
                })();
                if (parentName) gigmaRefreshParentUnchainedChildPresetOptions(parentName);
            }catch(_){}
        }
        // Lock height to keep panes stable while toggling.
        try{ gigmaEnsureInheritAreaHeightLocked(); }catch(_){}
    }catch(_){}
}
function gigmaInsertSoftHyphens(str) {
    try {
        var s = String(str).replace(/ /g, '\u00A0');
        // Make lorebook names behave like continuous text so line wrapping
        // happens only at manual soft-hyphen points (visible hyphen on wrap).
        return Array.from(s).join('\u00AD');
    } catch (_) {
        return str;
    }
}

function gigmaLayoutPresetTreeBudgetPreviewPlaceholderHtml(mode, rawVal, worldId, worldName){
    var m = mode || 'default';
    if (!gigmaIsPercentageBudgetMode(m)) return '';
    return '<span class="gigma-layout-preset-tree-budget-pill gigma-budget-preview-pill" data-gigma-budget-mode="' + gigmaEscapeHtml(String(m)) + '" data-gigma-budget-value="' + gigmaEscapeHtml(String(rawVal || 0)) + '" data-world-id="' + gigmaEscapeHtml(String(worldId || '')) + '" data-world-name="' + gigmaEscapeHtml(String(worldName || '')) + '" style="display:none;" aria-label="Budget preview"></span>';
}

function gigmaLayoutPresetTreeBudgetPillHtml(mode, rawVal, label, randomTrim, worldId, worldName){
    // Used by the preset preview tree (including injected parent budget rows).
    var m = mode || 'default';
    var v = (typeof rawVal === 'number' && Number.isFinite(rawVal)) ? rawVal : gigmaParseBudgetValueForMode(m, rawVal);
    var l = (typeof label === 'string') ? label : '';

    if (m !== 'default' && m !== 'off' &&
        m !== 'percentage_budget' && m !== 'percentage_context' && m !== 'percentage_lorebook' && m !== 'percentage_entries' && m !== 'fixed' && m !== 'entries') {
        m = 'default';
        v = 0;
        l = '';
    }

    if (!l) {
        if (m === 'default') l = 'Default';
        else if (m === 'off') l = 'Off';
        else if (m === 'percentage_budget') l = '% of WI';
        else if (m === 'percentage_context') l = '% of MC';
        else if (m === 'percentage_lorebook') l = '% of LT';
        else if (m === 'percentage_entries') l = '% of LE';
        else if (m === 'fixed') l = 'Tokens';
        else if (m === 'entries') l = 'Entries';
    }

    var text = '';
    var title = '';
    var cls = '';
    if (m === 'default') {
        text = 'D.';
        title = l || 'Default';
        cls = 'gigma-budget-default';
    } else if (m === 'off') {
        text = l || 'Off';
        title = text;
        cls = 'gigma-budget-off';
    } else if (m === 'percentage_budget') {
        text = gigmaPctToString(v || 0) + (l || '% of WI');
        title = text;
        cls = 'gigma-budget-pct';
    } else if (m === 'percentage_context') {
        text = gigmaPctToString(v || 0) + (l || '% of MC');
        title = text;
        cls = 'gigma-budget-pct';
    } else if (m === 'percentage_lorebook') {
        text = gigmaPctToString(v || 0) + (l || '% of LT');
        title = text;
        cls = 'gigma-budget-pct';
    } else if (m === 'percentage_entries') {
        text = gigmaPctToString(v || 0) + (l || '% of LE');
        title = text;
        cls = 'gigma-budget-pct';
    } else if (m === 'fixed') {
        text = String(v || 0) + (l ? (' ' + l) : ' Tokens');
        title = text;
        cls = 'gigma-budget-fixed';
    } else if (m === 'entries') {
        text = String(v || 0) + (l ? (' ' + l) : ' Entries');
        title = text;
        cls = 'gigma-budget-fixed';
    }

    if (!text) return '<span class="gigma-layout-preset-tree-budget"></span>';
    var r = (randomTrim && m !== 'default' && m !== 'off')
        ? '<span class="gigma-layout-preset-tree-budget-pill gigma-budget-random-pill" title="Random">R</span>'
        : '';
    return '<span class="gigma-layout-preset-tree-budget">' + r + gigmaLayoutPresetTreeBudgetPreviewPlaceholderHtml(m, rawVal, worldId, worldName) + '<span class="gigma-layout-preset-tree-budget-pill' + (cls ? (' ' + cls) : '') + '" title="' + gigmaEscapeHtml(String(title || '')) + '">' + gigmaEscapeHtml(String(text || '')) + '</span></span>';
}

function gigmaLayoutPresetTreeBudgetBadgeHtml(worldId){
    var mode = 'default';
    var rawVal = 0;
    var label = '';
    var randomTrim = false;
    var foundRow = false;

    try{
        var origin = '';
        try{ origin = window.__gigmaLastLayoutPresetTreeOrigin || ''; }catch(_eOrigin){ origin = ''; }

        // Prefer the current ordering-modal row state when the preview comes from the modal.
        if (origin !== 'drawer' && typeof document !== 'undefined' && worldId != null) {
            var row = null;
            try{
                var esc = (window.CSS && typeof CSS.escape === 'function')
                    ? CSS.escape(String(worldId))
                    : String(worldId).replace(/"/g, '\\"');
                row = document.querySelector('.gigma-row[data-world-id="' + esc + '"], .gigma-row[data-world="' + esc + '"]');
            }catch(_eQ){ row = null; }

            if (row) {
                foundRow = true;

                var modeSelect = row.querySelector ? row.querySelector('.gigma-budget-header-select') : null;
                var valueInput = row.querySelector ? row.querySelector('.gigma-budget-header-value') : null;

                if (modeSelect) {
                    mode = modeSelect.value || 'default';
                    try{
                        var opt = (modeSelect.options && modeSelect.selectedIndex >= 0)
                            ? modeSelect.options[modeSelect.selectedIndex]
                            : null;
                        if (opt && opt.textContent) label = opt.textContent.trim();
                    }catch(_eOpt){}
                } else if (row.dataset && typeof row.dataset.gigmaBudgetMode === 'string') {
                    mode = row.dataset.gigmaBudgetMode || 'default';
                }

                if (mode !== 'default' && mode !== 'off') {
                    if (valueInput) {
                        var rv = gigmaParseBudgetValueForMode(mode, valueInput.value);
                        rawVal = Number.isFinite(rv) ? rv : 0;
                    } else if (row.dataset && typeof row.dataset.gigmaBudgetValue === 'string') {
                        var dv = gigmaParseBudgetValueForMode(mode, row.dataset.gigmaBudgetValue);
                        rawVal = Number.isFinite(dv) ? dv : 0;
                    }
                } else {
                    rawVal = 0;
                }
            }

            try{
                var rb = row.querySelector ? row.querySelector('.gigma-budget-random-box') : null;
                if (rb) {
                    randomTrim = (typeof gigmaGetDeterministicRandomBoxState === 'function')
                        ? !!gigmaGetDeterministicRandomBoxState(rb)
                        : !!((rb.textContent || '').trim().toUpperCase() === 'R');
                } else if (row.dataset && typeof row.dataset.gigmaRandomTrim === 'string') {
                    randomTrim = row.dataset.gigmaRandomTrim === '1';
                }
            }catch(_eRand){}
        }

        // Otherwise, fall back to the saved preset settings.
        if (!foundRow && typeof gigmaLoadLorebookSettingsFromCurrentPreset === 'function') {
            var settings = gigmaLoadLorebookSettingsFromCurrentPreset(worldId) || DEFAULT_LOREBOOK_SETTINGS || {};
            if (settings && typeof settings === 'object') {
                mode = settings.budgetMode || 'default';
                randomTrim = !!settings.randomTrim;
                if (settings.budget != null) rawVal = gigmaParseBudgetValueForMode(mode, settings.budget);
                if (!Number.isFinite(rawVal)) rawVal = 0;
            }
        }
    }catch(_e){}

    return gigmaLayoutPresetTreeBudgetPillHtml(mode, rawVal, label, randomTrim, worldId, gigmaResolveLorebookNameById(worldId, ''));
}

function gigmaRefreshLayoutPresetTreeBudgetPreviewFields(rootEl) {
    try {
        if (!rootEl || !rootEl.querySelectorAll) return;
        var els = rootEl.querySelectorAll('.gigma-budget-preview-pill[data-gigma-budget-mode]');
        els.forEach(function(el){
            try {
                var mode = el.getAttribute('data-gigma-budget-mode') || 'default';
                var rawVal = el.getAttribute('data-gigma-budget-value') || '0';
                var worldId = el.getAttribute('data-world-id') || '';
                var worldName = el.getAttribute('data-world-name') || '';
                var resolvedName = gigmaResolveLorebookNameById(worldId, worldName);
                gigmaRefreshBudgetPreviewDisplay(el, mode, rawVal, resolvedName, { includeUnitInText: true });
            } catch (_eLayoutPresetTreeBudgetPreviewOne) {}
        });
    } catch (_eLayoutPresetTreeBudgetPreview) {}
}

