// === GIGMA: Smooth-scroll helper (50% faster than previous) ===
function gigmaSmoothScrollTo(scrollEl, targetTop){
    try{
        if (!scrollEl) return;
        const start = scrollEl.scrollTop || 0;
        const delta = targetTop - start;
        if (!delta) return;
        const abs = Math.abs(delta);
        // speed: 0.1125em/ms (50% faster than 0.075em/ms baseline)
        const duration = Math.max(120, Math.min(900, abs / 1.8));
        const t0 = performance.now();
        const token = (scrollEl.__gigmaSmoothScrollToken = (scrollEl.__gigmaSmoothScrollToken || 0) + 1);
        const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);
        const step = (now) => {
            if (scrollEl.__gigmaSmoothScrollToken !== token) return;
            const t = Math.min(1, (now - t0) / duration);
            scrollEl.scrollTop = start + delta * easeOutCubic(t);
            try{ if (scrollEl.__gigmaViewLocked) scrollEl.__gigmaViewLockTop = scrollEl.scrollTop || 0; }catch(_){ }
            if (t < 1) requestAnimationFrame(step);
        };
        requestAnimationFrame(step);
    }catch(_){}
}

// === GIGMA: Center ordering panes within the modal viewport ===
function gigmaCenterOrderingPanesInModal(triggerEl){
    try{
        const ordering = document.getElementById('gigma-ordering-container');
        if (!ordering) return;
        // Prefer the dialog that contains the trigger element; fallback to the first open dialog.
        const dlg = (triggerEl && triggerEl.closest) ? triggerEl.closest('dialog') : null;
        const dialog = dlg || document.querySelector('dialog[open]') || null;
        // Identify the scrollable element that actually moves when the modal scrolls.
        let scrollEl = null;
        const isScrollable = (el) => {
            if (!el) return false;
            try{
                const cs = window.getComputedStyle(el);
                const oy = cs && cs.overflowY ? cs.overflowY : '';
                const canScroll = (oy === 'auto' || oy === 'scroll');
                return canScroll && el.scrollHeight > el.clientHeight + 2;
            }catch(_){
                return (el.scrollHeight > el.clientHeight + 2);
            }
        };
        if (dialog){
            // Common ST containers inside <dialog>
            const candidates = [
                dialog.querySelector('.popup-body'),
                dialog.querySelector('.popup-content'),
                dialog.querySelector('.popup-content-wrapper'),
                dialog
            ].filter(Boolean);
            scrollEl = candidates.find(isScrollable) || null;
            if (!scrollEl){
                // Walk down to find any scrollable descendant
                const all = Array.from(dialog.querySelectorAll('*') || []);
                scrollEl = all.find(isScrollable) || null;
            }
        }
        if (!scrollEl){
            // Absolute fallback
            scrollEl = document.scrollingElement || document.documentElement || document.body;
        }
        const elRect = ordering.getBoundingClientRect();
        const scRect = scrollEl.getBoundingClientRect();
        const elTopInScroll = (elRect.top - scRect.top) + (scrollEl.scrollTop || 0);
        const targetTop = elTopInScroll + (elRect.height / 2) - (scrollEl.clientHeight / 2);
        gigmaSmoothScrollTo(scrollEl, Math.max(0, targetTop));
}catch(_eCenter){}
}

