        const maxTop = Math.max(0, (scrollEl.scrollHeight || 0) - (scrollEl.clientHeight || 0));
        const targetTop = elBottomInScroll - ((scrollEl.clientHeight || 0) - 5);
        gigmaSmoothScrollTo(scrollEl, Math.max(0, Math.min(maxTop, targetTop)));
